def renderizar_guia_aba(chave_aba: str):
    """[F-NEW2 - 4ª geração] Renderiza a seção padronizada e obrigatória
    '❓ Como usar esta aba (passo a passo para iniciantes)' de forma consistente
    em todas as 10 abas. Conteúdo escrito para quem nunca viu geocodificação.
    """
    import streamlit as _st
    g = _GUIA_ABAS.get(chave_aba)
    if not g:
        return
    with _st.expander("❓ Como usar esta aba (passo a passo para iniciantes)", expanded=False):
        _st.markdown(f"""
        **📌 O que esta aba faz**
        {g['o_que_faz']}

        **🕐 Quando utilizar**
        {g['quando_usar']}

        **📥 Quais dados inserir**
        {g['dados']}

        **✍️ Como preencher corretamente**
        {g['preenchimento']}

        **⚙️ O que acontece após executar**
        {g['apos_executar']}

        **📊 Como interpretar os resultados**
        {g['interpretar']}

        **💡 Exemplos práticos**
        {g['exemplos']}

        **⚠️ Erros mais comuns**
        {g['erros_comuns']}

        **✅ Dicas e boas práticas**
        {g['dicas']}
        """)

def _formatar_duracao(segundos: float) -> str:
    """Formata segundos em texto legível: 'X minuto(s) e Y segundo(s)'."""
    segundos = max(0, int(round(segundos)))
    if segundos < 60:
        return f"{segundos} segundo{'s' if segundos != 1 else ''}"
    minutos = segundos // 60
    resto = segundos % 60
    if minutos < 60:
        txt = f"{minutos} minuto{'s' if minutos != 1 else ''}"
        if resto > 0:
            txt += f" e {resto} segundo{'s' if resto != 1 else ''}"
        return txt
    horas = minutos // 60
    min_resto = minutos % 60
    txt = f"{horas} hora{'s' if horas != 1 else ''}"
    if min_resto > 0:
        txt += f" e {min_resto} minuto{'s' if min_resto != 1 else ''}"
    return txt

def estimar_tempo_processamento(n_rotas_unicas: int, tipo="lote"):
    """[SPEED-2 / Etapa 5 - 9ª geração] Estimativa DINÂMICA de tempo de processamento.
    
    Baseia-se no histórico REAL de execuções (cache_historico_lotes). Calcula a média
    ponderada de 'Tempo Médio/Rota (s)' das execuções passadas, dando mais peso às
    recentes (que refletem o estado atual da rede/cache). Quanto mais a aplicação é
    usada, mais precisa fica a estimativa. Retorna (texto_estimativa, baseline_usado,
    n_amostras). Se não há histórico suficiente, usa um baseline conservador documentado.
    """
    try:
        registros = []
        prefixo = "alocacao_" if tipo == "alocacao" else "lote_"
        for chave in cache_historico_lotes:
            if not str(chave).startswith(prefixo):
                continue
            try:
                d = cache_historico_lotes.get(chave)
                if d and d.get("Tempo Médio/Rota (s)", 0) > 0 and d.get("Linhas Validadas", 0) > 0:
                    registros.append((float(chave.split("_", 1)[1]), d))  # (timestamp, dado)
            except Exception:
                continue
                
        if registros:
            # Ordena por timestamp (mais recente por último) e pondera exponencialmente
            registros.sort(key=lambda x: x[0])
            amostras = registros[-20:]  # últimas 20 execuções
            soma_pond = 0.0
            soma_pesos = 0.0
            for i, (_ts, d) in enumerate(amostras):
                peso = 1.5 ** i  # execuções recentes pesam mais
                soma_pond += d["Tempo Médio/Rota (s)"] * peso
                soma_pesos += peso
            tempo_por_rota = soma_pond / soma_pesos if soma_pesos > 0 else 0.5
            n_amostras = len(amostras)
            baseline = "histórico real"
        else:
            # Baseline conservador (cache vazio): ~0.4s/rota com pré-aquecimento e cache.
            # Valor documentado; será substituído por dados reais após o 1º lote.
            tempo_por_rota = 0.4
            n_amostras = 0
            baseline = "estimativa inicial (sem histórico ainda)"
            
        tempo_estimado = n_rotas_unicas * tempo_por_rota
        return _formatar_duracao(tempo_estimado), baseline, n_amostras, tempo_por_rota
    except Exception:
        return None, "indisponível", 0, 0.0


def _amostras_tempo_por_rota(tipo="lote", historico=None):
    """[ETA-FAIXA - 118ª geração] Coleta as amostras de 'Tempo Médio/Rota (s)' do histórico REAL de
    execuções (cache_historico_lotes), da mais antiga para a mais recente. `historico` é injetável
    (dict-like) para teste. PURA em relação ao histórico. Retorna list[float] (pode ser vazia)."""
    _fonte = historico if historico is not None else (
        cache_historico_lotes if "cache_historico_lotes" in globals() else {})
    prefixo = "alocacao_" if tipo == "alocacao" else "lote_"
    _regs = []
    try:
        for chave in _fonte:
            if not str(chave).startswith(prefixo):
                continue
            try:
                d = _fonte.get(chave)
                if d and float(d.get("Tempo Médio/Rota (s)", 0)) > 0 and int(d.get("Linhas Validadas", 0)) > 0:
                    _regs.append((float(str(chave).split("_", 1)[1]), float(d["Tempo Médio/Rota (s)"])))
            except Exception:
                continue
    except Exception:
        return []
    _regs.sort(key=lambda x: x[0])
    return [s for _ts, s in _regs]


def _faixa_tempo(n_rotas_unicas, s_esperado, s_otimista, s_pessimista):
    """[ETA-FAIXA - 118ª geração] Converte três ritmos (s/rota) em três durações totais (s) para n
    rotas únicas, garantindo a ordem mínimo ≤ esperado ≤ pessimista. PURO. Retorna (min_s, esp_s, pess_s)."""
    try:
        n = max(0, int(n_rotas_unicas))
    except (TypeError, ValueError):
        n = 0

    def _mul(_s):
        try:
            return max(0.0, float(_s)) * n
        except (TypeError, ValueError):
            return 0.0
    _esp = _mul(s_esperado)
    _min = min(_mul(s_otimista), _esp)
    _pess = max(_mul(s_pessimista), _esp)
    return round(_min, 1), round(_esp, 1), round(_pess, 1)


def estimar_faixa_tempo_processamento(n_rotas_unicas, tipo="lote", historico=None):
    """[ETA-FAIXA - 118ª geração] Estimativa de tempo DECOMPOSTA em faixa mínimo/esperado/pessimista.
    - ESPERADO: reusa estimar_tempo_processamento (o estimador ponderado existente) — não duplica lógica.
    - FAIXA: derivada da DISPERSÃO real das execuções passadas (s/rota). Com ≥3 amostras, usa
      média ± 1 desvio-padrão saturado no mínimo observado (faixa empírica, honesta). Com <3 amostras,
      aplica fatores heurísticos DOCUMENTADOS (otimista ×0.7, pessimista ×1.6) sobre o esperado,
      refletindo a variabilidade de rede/cache. `historico` injetável para teste.
    Retorna dict com *_s (segundos), *_txt (formatado), n_amostras, baseline, origem_faixa e s/rota."""
    if historico is None:
        _txt, baseline, n_amostras, s_esp = estimar_tempo_processamento(n_rotas_unicas, tipo)
    else:
        _am0 = _amostras_tempo_por_rota(tipo, historico)
        s_esp = (sum(_am0) / len(_am0)) if _am0 else 0.4
        n_amostras = len(_am0)
        baseline = "histórico real" if _am0 else "estimativa inicial (sem histórico ainda)"
    amostras = _amostras_tempo_por_rota(tipo, historico)
    if len(amostras) >= 3:
        _media = sum(amostras) / len(amostras)
        _dp = (sum((x - _media) ** 2 for x in amostras) / len(amostras)) ** 0.5
        s_otim = max(min(amostras), _media - _dp)
        s_pess = _media + _dp
        origem_faixa = f"dispersão real de {len(amostras)} execuções (±1σ)"
    else:
        s_otim = float(s_esp) * 0.7
        s_pess = float(s_esp) * 1.6
        origem_faixa = "heurística (histórico insuficiente p/ dispersão)"
    _min_s, _esp_s, _pess_s = _faixa_tempo(n_rotas_unicas, s_esp, s_otim, s_pess)
    return {
        "min_s": _min_s, "esperado_s": _esp_s, "pessimista_s": _pess_s,
        "min_txt": _formatar_duracao(_min_s), "esperado_txt": _formatar_duracao(_esp_s),
        "pessimista_txt": _formatar_duracao(_pess_s),
        "n_amostras": n_amostras, "baseline": baseline, "origem_faixa": origem_faixa,
        "s_por_rota_esperado": round(float(s_esp), 3),
    }


# ==============================================================================
# [PREVOO - 119ª geração] RAIO-X DE SAÚDE DA PLANILHA (pré-voo do Lote)
# ------------------------------------------------------------------------------
# Detecta, ANTES do processamento, os problemas de dado que mais degradam o
# resultado (lixo na entrada é a causa nº 1 de rota ruim). Funções PURAS e
# testáveis; render isolado. Reusa _RE_UF_SIGLA e a bbox de validar_coordenada_brasil.
# ==============================================================================
_RE_PREVOO_COORD = re.compile(r'^[\(\[]?\s*(-?\d{1,3}(?:[.,]\d+)?)\s*[;,]\s*(-?\d{1,3}(?:[.,]\d+)?)\s*[\)\]]?$')
_MOJIBAKE_MARCADORES = ('Ã', 'Â', 'â\x82', 'â\x80', 'ï¿½', '�', 'Ãƒ')


def _prevoo_strip_acentos(txt):
    """[PREVOO - 119ª] Minúsculo, sem acento/pontuação, espaços colapsados — chave p/ comparar grafias. PURO."""
    import unicodedata
    s = str(txt or "").strip().lower()
    s = unicodedata.normalize("NFKD", s).encode("ascii", "ignore").decode("ascii")
    s = re.sub(r"[^a-z0-9 ]", " ", s)
    return re.sub(r"\s+", " ", s).strip()


def _prevoo_parse_coord(texto):
    """[PREVOO - 119ª] Interpreta 'lat, lon' (separador vírgula/ponto-e-vírgula) → (a, b) float ou None. PURO."""
    m = _RE_PREVOO_COORD.match(str(texto or "").strip())
    if not m:
        return None
    try:
        return (float(m.group(1).replace(",", ".")), float(m.group(2).replace(",", ".")))
    except ValueError:
        return None


def _prevoo_status_coord(a, b):
    """[PREVOO - 119ª] 'ok' | 'trocada' | 'fora' para (a,b) lido como (lat,lon), usando a bbox do Brasil. PURO."""
    def _in_br(lat, lon):
        return (-35.0 <= lat <= 6.0) and (-75.0 <= lon <= -28.0)
    if _in_br(a, b):
        return "ok"
    if _in_br(b, a):
        return "trocada"
    return "fora"


def _prevoo_corrigir_mojibake(s):
    """[PREVOO - 119ª] Corrige mojibake clássico (UTF-8 lido como Latin-1) SÓ quando há marcadores e o
    round-trip é seguro; senão devolve o original (nunca corrompe texto já correto). PURO."""
    txt = str(s)
    if not any(mk in txt for mk in _MOJIBAKE_MARCADORES):
        return txt
    try:
        return txt.encode("latin-1").decode("utf-8")
    except (UnicodeEncodeError, UnicodeDecodeError):
        return txt


def _prevoo_higienizar_texto(s):
    """[PREVOO - 119ª] Higiene NÃO destrutiva de uma célula: corrige mojibake + colapsa espaços + trim. PURO."""
    return re.sub(r"\s+", " ", _prevoo_corrigir_mojibake(s)).strip()


def _gerar_relatorio_html(df, titulo="Relatório do Estudo", data_str=""):
    """[RELATORIO-HTML-PRO - 184ª geração] Relatório HTML AUTOCONTIDO (offline) de nível profissional/BI:
    capa, NAVEGAÇÃO LATERAL (sumário), cartões executivos e seções analíticas ricas — Resumo, Distribuição de
    Distâncias, Síntese por UF, Competitividade dos Polos, Concorrentes, Balsas, Linha Reta × Rota, Mapa e
    Diagnóstico Executivo automático. Gráficos plotly embutidos (scatter_geo funciona sem tiles → offline);
    layout responsivo e amigável para impressão. Defensivo: cada seção só aparece se as colunas existirem;
    erro numa seção não derruba o relatório. Retorna string HTML (ou None em falha)."""
    import html as _he
    try:
        def _num(c):
            return pd.to_numeric(df[c], errors='coerce') if c in df.columns else None
        _n = len(df)
        _dist, _reta, _integ = _num('Distancia'), _num('Linha Reta'), _num('Integridade Geográfica')
        _insc = _num('Inscritos')
        if _insc is None:
            _insc = _num('Quantidade de Inscritos')
        _tot_cand = int(_insc.fillna(0).sum()) if _insc is not None else _n
        _n_polos = df['Municipio Destino'].nunique() if 'Municipio Destino' in df.columns else None
        _st = {"first": True}

        def _emb(fig):
            _h = fig.to_html(full_html=False, include_plotlyjs=(True if _st["first"] else False),
                             config={"displayModeBar": False, "responsive": True})
            _st["first"] = False
            return _h
        _sec = []   # (id, título, html)

        _kpis = [("Candidatos", f"{_tot_cand:,}"), ("Municípios de origem", f"{_n:,}")]
        if _n_polos is not None:
            _kpis.append(("Polos utilizados", f"{_n_polos:,}"))
        if _dist is not None:
            _kpis += [("Deslocamento médio", f"{_dist.mean():.0f} km"), ("Mediana", f"{_dist.median():.0f} km"),
                      ("Maior deslocamento", f"{_dist.max():.0f} km"), ("Deslocamento total", f"{_dist.sum():,.0f} km")]
        if _integ is not None:
            _kpis.append(("Integridade média", f"{_integ.mean():.0f}/100"))
        _kh = "".join(f'<div class="kpi"><div class="kpi-v">{_he.escape(str(v))}</div>'
                      f'<div class="kpi-l">{_he.escape(l)}</div></div>' for l, v in _kpis)
        _sec.append(("resumo", "Resumo Executivo", f'<div class="kpis">{_kh}</div>'))

        if _dist is not None and _dist.notna().any():
            _labs = ["0–50", "50–100", "100–150", "150–200", "200–300", "300–500", "500+"]
            _cat = pd.cut(_dist.dropna(), bins=[0, 50, 100, 150, 200, 300, 500, 10**9], labels=_labs, right=False)
            _cnt = _cat.value_counts().reindex(_labs, fill_value=0)
            _f = go.Figure(go.Bar(x=list(_labs), y=[int(x) for x in _cnt.values], marker_color="#2563eb"))
            _f.update_layout(height=320, margin=dict(l=44, r=16, t=16, b=40), template="plotly_white", yaxis_title="rotas")
            _sec.append(("dist", "Distribuição de Distâncias", _emb(_f)))

        if 'UF Origem' in df.columns and _dist is not None:
            _g = df.assign(_d=_dist).groupby('UF Origem').agg(Rotas=('_d', 'size'), Media=('_d', 'mean')).reset_index().sort_values('Rotas', ascending=False)
            _f = go.Figure(go.Bar(x=_g['UF Origem'], y=_g['Rotas'], marker_color="#0ea5e9"))
            _f.update_layout(height=300, margin=dict(l=44, r=16, t=16, b=40), template="plotly_white", yaxis_title="rotas")
            _rows = "".join(f"<tr><td>{_he.escape(str(r['UF Origem']))}</td><td class='r'>{int(r['Rotas'])}</td><td class='r'>{r['Media']:.0f}</td></tr>" for _, r in _g.head(15).iterrows())
            _sec.append(("uf", "Síntese por UF", _emb(_f) + f"<table><thead><tr><th>UF</th><th class='r'>Rotas</th><th class='r'>Dist. média (km)</th></tr></thead><tbody>{_rows}</tbody></table>"))

        if 'Municipio Destino' in df.columns and _dist is not None:
            _p = df.assign(_d=_dist).groupby('Municipio Destino').agg(Mun=('_d', 'size'), DM=('_d', 'mean')).reset_index().sort_values('Mun', ascending=False)
            _has_c = _insc is not None
            if _has_c:
                _p['Cand'] = _p['Municipio Destino'].map(df.assign(_i=_insc.fillna(0)).groupby('Municipio Destino')['_i'].sum()).fillna(0).astype(int)
            _rows = "".join("<tr><td>" + _he.escape(str(r['Municipio Destino'])) + f"</td><td class='r'>{int(r['Mun'])}</td>" + (f"<td class='r'>{int(r['Cand']):,}</td>" if _has_c else "") + f"<td class='r'>{r['DM']:.0f}</td></tr>" for _, r in _p.head(20).iterrows())
            _cab = "<th>Polo</th><th class='r'>Municípios</th>" + ("<th class='r'>Candidatos</th>" if _has_c else "") + "<th class='r'>Dist. média (km)</th>"
            _sec.append(("polos", "Competitividade dos Polos", f'<p class="lead">Quantos municípios e candidatos cada polo concentra — os do topo são os mais demandados.</p><table><thead><tr>{_cab}</tr></thead><tbody>{_rows}</tbody></table>'))

        if 'Municipio Concorrente' in df.columns:
            _cc = df['Municipio Concorrente'].astype(str).str.strip()
            _cc = _cc[(_cc != '') & (_cc.str.lower() != 'nan')]
            _vc = _cc.value_counts().head(10)
            if len(_vc):
                _dc = _num('Distancia Concorrente')
                _extra = ""
                if _dist is not None and _dc is not None:
                    _difs = (_dc - _dist).dropna()
                    if len(_difs):
                        _extra = f'<p class="lead">Diferença média para o 2º colocado: <b>{_difs.mean():.0f} km</b> · mínima {_difs.min():.0f} km · máxima {_difs.max():.0f} km.</p>'
                _rows = "".join(f"<tr><td>{_he.escape(str(k))}</td><td class='r'>{int(v)}</td></tr>" for k, v in _vc.items())
                _sec.append(("conc", "Concorrentes (2º colocado)", f'{_extra}<table><thead><tr><th>Alternativa de aplicação</th><th class="r">Vezes como 2ª opção</th></tr></thead><tbody>{_rows}</tbody></table>'))

        if 'Balsas' in df.columns:
            _bm = df['Balsas'].astype(str).str.strip().str.lower().isin(['sim', 'yes', 'true', '1'])
            _nb = int(_bm.sum())
            _cb = int(_insc[_bm].fillna(0).sum()) if _insc is not None else _nb
            _sec.append(("balsa", "Balsas", f'<div class="kpis"><div class="kpi"><div class="kpi-v">{_nb:,}</div><div class="kpi-l">Rotas que cruzam balsa</div></div><div class="kpi"><div class="kpi-v">{_cb:,}</div><div class="kpi-l">Candidatos afetados</div></div></div><p class="lead">Rotas dependentes de travessia são sensíveis a horários e condições do rio — priorize alternativas onde possível.</p>'))

        if _dist is not None and _reta is not None:
            _mm = pd.DataFrame({"r": _reta, "v": _dist}).dropna()
            _mm = _mm[(_mm["r"] > 0) & (_mm["v"] > 0)]
            if len(_mm):
                _f = go.Figure(go.Scatter(x=_mm["r"], y=_mm["v"], mode="markers", marker=dict(color="#7c3aed", size=6, opacity=0.55)))
                _mx = float(max(_mm["r"].max(), _mm["v"].max()))
                _f.add_trace(go.Scatter(x=[0, _mx], y=[0, _mx], mode="lines", line=dict(dash="dash", color="#94a3b8")))
                _f.update_layout(height=360, margin=dict(l=52, r=16, t=16, b=40), template="plotly_white", xaxis_title="linha reta (km)", yaxis_title="viária (km)", showlegend=False)
                _sec.append(("sinuo", "Linha Reta × Rota", f'<p class="lead">Sinuosidade média (viária ÷ reta): <b>{(_mm["v"] / _mm["r"]).mean():.2f}×</b>. Pontos acima da diagonal indicam o desvio natural das estradas.</p>' + _emb(_f)))

        if {'Lat Origem', 'Lon Origem'}.issubset(df.columns):
            _dm = df.copy()
            _dm['_la'] = pd.to_numeric(_dm['Lat Origem'], errors='coerce')
            _dm['_lo'] = pd.to_numeric(_dm['Lon Origem'], errors='coerce')
            _dm = _dm[_dm['_la'].notna() & _dm['_lo'].notna()]
            if len(_dm):
                _fm = px.scatter_geo(_dm, lat='_la', lon='_lo',
                                     color=('Distancia' if 'Distancia' in _dm.columns else None),
                                     hover_name=('Municipio Origem' if 'Municipio Origem' in _dm.columns else None),
                                     scope='south america', color_continuous_scale="Turbo")
                _fm.update_layout(height=460, margin=dict(l=0, r=0, t=0, b=0))
                _fm.update_geos(fitbounds="locations", showcountries=True, countrycolor="#94a3b8")
                _sec.append(("mapa", "Mapa das Origens", _emb(_fm)))

        _dg = []
        if _dist is not None:
            _dg.append(f"O estudo cobre <b>{_n:,} municípios</b> de origem" + (f" e <b>{_tot_cand:,} candidatos</b>" if _insc is not None else "") + (f", distribuídos em <b>{_n_polos} polos</b>" if _n_polos else "") + f". O deslocamento médio é de <b>{_dist.mean():.0f} km</b> (mediana {_dist.median():.0f} km) e o pior caso, <b>{_dist.max():.0f} km</b>.")
            if 'Municipio Origem' in df.columns:
                _cr = df.assign(_d=_dist).nlargest(3, '_d')
                _dg.append("<b>Municípios críticos</b> (maior deslocamento): " + "; ".join(f"{_he.escape(str(r['Municipio Origem']))} ({r['_d']:.0f} km)" for _, r in _cr.iterrows()) + " — atenção prioritária a esses candidatos.")
            if 'Municipio Destino' in df.columns:
                _pv = df['Municipio Destino'].value_counts()
                if len(_pv):
                    _dg.append(f"<b>Polo mais utilizado</b>: {_he.escape(str(_pv.index[0]))} ({int(_pv.iloc[0])} municípios) — verifique a capacidade; polos com poucos municípios podem ser consolidados.")
        _sec.append(("diag", "Diagnóstico Executivo", "".join(f"<p>{d}</p>" for d in _dg) or "<p>Sem dados suficientes.</p>"))

        _nav = "".join(f'<a href="#{i}">{_he.escape(t)}</a>' for i, t, _ in _sec)
        _corpo = "".join(f'<section id="{i}"><h2>{_he.escape(t)}</h2>{h}</section>' for i, t, h in _sec)
        _css = (
            ":root{--brand:#0f172a;--accent:#2563eb;--line:#e2e8f0;--muted:#64748b}"
            "*{box-sizing:border-box}body{font-family:-apple-system,Segoe UI,Roboto,Arial,sans-serif;margin:0;"
            "background:#f1f5f9;color:#0f172a}a{color:inherit;text-decoration:none}"
            ".cover{background:linear-gradient(135deg,#0f172a,#1e3a8a);color:#fff;padding:40px 40px 44px}"
            ".cover .tag{font-size:12px;letter-spacing:.14em;text-transform:uppercase;color:#93c5fd}"
            ".cover h1{margin:8px 0 6px;font-size:28px;font-weight:800}.cover p{margin:0;color:#cbd5e1;font-size:13px}"
            ".wrap{display:flex;align-items:flex-start;max-width:1180px;margin:0 auto}"
            "nav{position:sticky;top:0;align-self:flex-start;width:240px;flex:0 0 240px;padding:24px 16px;"
            "max-height:100vh;overflow:auto}nav .lbl{font-size:11px;text-transform:uppercase;letter-spacing:.1em;"
            "color:var(--muted);margin:0 10px 8px}nav a{display:block;padding:9px 12px;border-radius:8px;"
            "font-size:13.5px;color:#334155;margin-bottom:2px}nav a:hover{background:#e2e8f0;color:var(--brand)}"
            "main{flex:1;min-width:0;padding:24px 32px 60px}"
            ".kpis{display:flex;flex-wrap:wrap;gap:14px}.kpi{flex:1;min-width:150px;background:#fff;"
            "border:1px solid var(--line);border-radius:14px;padding:18px}.kpi-v{font-size:26px;font-weight:800;"
            "color:var(--accent)}.kpi-l{font-size:12px;color:var(--muted);margin-top:2px}"
            "section{background:#fff;border:1px solid var(--line);border-radius:14px;padding:20px 22px;"
            "margin-bottom:18px;scroll-margin-top:16px}h2{font-size:16px;margin:0 0 14px;padding-bottom:10px;"
            "border-bottom:2px solid #eef2f7}p.lead{color:#475569;font-size:13.5px;margin:0 0 12px}"
            "table{width:100%;border-collapse:collapse;font-size:13px}th,td{padding:9px 11px;"
            "border-bottom:1px solid #eef2f7;text-align:left}td.r,th.r{text-align:right}"
            "thead th{background:#f1f5f9;color:#475569;font-size:12px}"
            "footer{max-width:1180px;margin:0 auto;padding:8px 32px 44px;color:#94a3b8;font-size:11px}"
            "@media(max-width:820px){.wrap{display:block}nav{position:static;width:auto;flex:none;max-height:none;"
            "display:flex;flex-wrap:wrap;gap:6px}nav .lbl{display:none}nav a{margin:0}}"
            "@media print{nav{display:none}section{break-inside:avoid}.cover{-webkit-print-color-adjust:exact}}"
        )
        return (f'<!DOCTYPE html><html lang="pt-BR"><head><meta charset="utf-8">'
                f'<meta name="viewport" content="width=device-width, initial-scale=1">'
                f'<title>{_he.escape(titulo)}</title><style>{_css}</style></head><body>'
                f'<div class="cover"><div class="tag">Relatório Técnico · Planejamento de Locais de Aplicação</div>'
                f'<h1>{_he.escape(titulo)}</h1><p>{_he.escape(data_str)} · {_n:,} municípios · {_tot_cand:,} candidatos</p></div>'
                f'<div class="wrap"><nav><div class="lbl">Sumário</div>{_nav}</nav><main>{_corpo}</main></div>'
                f'<footer>Relatório autocontido · abre offline em qualquer navegador · gerado pela aplicação.</footer>'
                f'</body></html>')
    except Exception:
        logger.error("[RELATORIO-HTML-PRO] Falha ao gerar relatório", exc_info=True)
        return None


def _gerar_relatorio_comparacao_html(stats, aud, titulo="Relatório da Comparação", data_str=""):
    """[RELATORIO-HTML - 184ª geração] Relatório HTML AUTOCONTIDO (offline) da COMPARAÇÃO entre estudos:
    KPIs de conciliação e vitória + distribuição de vitórias + candidatos por faixa de economia + veredito.
    Para compartilhar o parecer com quem DECIDE. Reusa os agregados de stats['brasil']/aud (chaves conhecidas
    do relatório executivo). Defensivo. Retorna string HTML (ou None)."""
    import html as _he
    try:
        br = (stats or {}).get("brasil", {})
        aud = aud or {}
        _tot = aud.get("total_ref", 0) or 0
        _conc = aud.get("conciliados", 0) or 0
        _pct_conc = round(100.0 * _conc / _tot, 1) if _tot else 0.0
        _p_app = br.get("pct_venceu_app", 0) or 0
        _p_ref = br.get("pct_venceu_ref", 0) or 0
        _p_emp = br.get("pct_empate", 0) or 0
        _econ = br.get("economia_ponderada_km", 0) or 0
        _kpis = [("Conciliação", f"{_pct_conc:.0f}%"), ("Vitórias da aplicação", f"{_p_app:.0f}%"),
                 ("Vitórias da referência", f"{_p_ref:.0f}%"), ("Empate técnico", f"{_p_emp:.0f}%")]
        if _econ:
            _kpis.append(("Economia ponderada", f"{_econ:,.0f} km"))
        _kpi_html = "".join(f'<div class="kpi"><div class="kpi-v">{_he.escape(str(v))}</div>'
                            f'<div class="kpi-l">{_he.escape(l)}</div></div>' for l, v in _kpis)
        _ver = ("A aplicação produziu a melhor distribuição na maioria dos municípios comparáveis."
                if _p_app > _p_ref + 5 else
                ("A base de referência venceu na maioria dos casos."
                 if _p_ref > _p_app + 5 else
                 "As duas soluções são tecnicamente equivalentes no conjunto."))
        _figs, _sf = [], {"first": True}

        def _emb(fig):
            _h = fig.to_html(full_html=False, include_plotlyjs=(True if _sf["first"] else False),
                             config={"displayModeBar": False})
            _sf["first"] = False
            return _h
        _fig_w = go.Figure(go.Bar(x=["Aplicação", "Referência", "Empate técnico"], y=[_p_app, _p_ref, _p_emp],
                                  marker_color=["#2563eb", "#f59e0b", "#94a3b8"]))
        _fig_w.update_layout(title="Distribuição de vitórias (% dos municípios comparáveis)", height=320,
                             margin=dict(l=40, r=20, t=50, b=40), template="plotly_white", yaxis_title="%")
        _figs.append(_emb(_fig_w))
        _fx = br.get("faixas_economia_candidatos", {}) or {}
        if any(_fx.values()):
            _fig_f = go.Figure(go.Bar(x=list(_fx.keys()), y=[_fx[k] for k in _fx], marker_color="#16a34a"))
            _fig_f.update_layout(title="Candidatos por faixa de economia de distância", height=320,
                                 margin=dict(l=40, r=20, t=50, b=40), template="plotly_white")
            _figs.append(_emb(_fig_f))
        _figs_html = "".join(f'<section><div class="fig">{_h}</div></section>' for _h in _figs)
        _css = ("body{font-family:-apple-system,Segoe UI,Roboto,Arial,sans-serif;margin:0;background:#f8fafc;"
                "color:#0f172a}header{background:#0f172a;color:#fff;padding:28px 32px}header h1{margin:0;"
                "font-size:22px}header p{margin:4px 0 0;color:#cbd5e1;font-size:13px}main{max-width:960px;"
                "margin:0 auto;padding:24px 32px}.kpis{display:flex;flex-wrap:wrap;gap:14px}.kpi{flex:1;"
                "min-width:150px;background:#fff;border:1px solid #e2e8f0;border-radius:12px;padding:16px}"
                ".kpi-v{font-size:24px;font-weight:700;color:#2563eb}.kpi-l{font-size:12px;color:#64748b;"
                "margin-top:2px}section{background:#fff;border:1px solid #e2e8f0;border-radius:12px;padding:16px;"
                "margin-top:16px}.verdict{background:#eff6ff;border:1px solid #bfdbfe;border-radius:12px;"
                "padding:16px;margin-top:16px;font-size:15px}.fig{overflow:auto}footer{max-width:960px;"
                "margin:0 auto;padding:16px 32px 40px;color:#94a3b8;font-size:11px}")
        return (f'<!DOCTYPE html><html lang="pt-BR"><head><meta charset="utf-8">'
                f'<meta name="viewport" content="width=device-width, initial-scale=1">'
                f'<title>{_he.escape(titulo)}</title><style>{_css}</style></head><body>'
                f'<header><h1>{_he.escape(titulo)}</h1><p>{_he.escape(data_str)} · '
                f'{_conc} de {_tot} municípios conciliados</p></header>'
                f'<main><div class="verdict">🔎 <strong>Veredito:</strong> {_he.escape(_ver)}</div>'
                f'<div class="kpis" style="margin-top:16px">{_kpi_html}</div>{_figs_html}</main>'
                f'<footer>Relatório autocontido · abre offline em qualquer navegador.</footer></body></html>')
    except Exception:
        logger.error("[RELATORIO-HTML] Falha ao gerar relatório de comparação", exc_info=True)
        return None


def _raio_x_planilha(origens, destinos, max_exemplos=3):
    """[PREVOO - 119ª geração] Raio-X de saúde da planilha ANTES do processamento. Varre Origem/Destino
    em UMA passada (O(N)) e reporta os problemas que mais degradam o resultado. PURO e determinístico.
    Recebe duas sequências de strings; retorna dict {score, nota, total_linhas, achados}. Cada achado:
    {id, severidade('critico'|'aviso'|'info'), titulo, contagem, exemplos, recomendacao, corrigivel}."""
    origens = list(origens)
    destinos = list(destinos)
    n = max(len(origens), len(destinos))

    def _cel(seq, i):
        return str(seq[i]).strip() if (i < len(seq) and seq[i] is not None) else ""

    def _vazio(v):
        return (v == "") or v.lower() == "nan"

    inc, ig, moji, esp, coord_ruim = [], [], [], [], []
    nao_enc, homon_sem_uf = [], []   # [PREVOO-IBGE - 184ª geração] validação SEMÂNTICA de município
    _UFS_PV = {"AC", "AL", "AP", "AM", "BA", "CE", "DF", "ES", "GO", "MA", "MT", "MS", "MG", "PA", "PB",
               "PR", "PE", "PI", "RJ", "RN", "RS", "RO", "RR", "SC", "SP", "SE", "TO"}
    _RE_ENDERECO_PV = re.compile(r"\b(rua|r\.|av\.?|avenida|rod\.?|rodovia|estrada|travessa|alameda|pra[çc]a|"
                                 r"quadra|lote|km|n[º°]|bairro)\b|\d{2,}", re.I)
    pares = {}

    for i in range(n):
        o, d = _cel(origens, i), _cel(destinos, i)
        vo, vd = _vazio(o), _vazio(d)
        if vo or vd:
            inc.append(i + 2)  # +2 = linha real no Excel (cabeçalho + índice 1-based)
        if (not vo) and (not vd):
            _ko, _kd = _prevoo_strip_acentos(o), _prevoo_strip_acentos(d)
            if _ko and _ko == _kd:
                ig.append(f"L{i+2}: {o}")
            pares[(o.lower(), d.lower())] = pares.get((o.lower(), d.lower()), 0) + 1
        for col, v in (("O", o), ("D", d)):
            if _vazio(v):
                continue
            if v != re.sub(r"\s+", " ", v).strip() or "  " in v:
                esp.append(f"L{i+2}/{col}")
            # [PREVOO-FP - 120ª geração] Mojibake PRECISO: só sinaliza quando a correção segura
            # (round-trip latin-1↔utf-8) REALMENTE muda o texto. Assim, acentos maiúsculos legítimos
            # ('SÃO PAULO', 'MARANHÃO') NUNCA são falsos positivos.
            _v_corr = _prevoo_corrigir_mojibake(v)
            if _v_corr != v:
                moji.append(f"L{i+2}/{col}: {v} → {_v_corr}")
            pc = _prevoo_parse_coord(v)
            if pc is not None:
                stt = _prevoo_status_coord(pc[0], pc[1])
                if stt != "ok":
                    coord_ruim.append(f"L{i+2}/{col}: {v} ({'lat/lon trocadas' if stt == 'trocada' else 'fora do Brasil'})")
            # [PREVOO-IBGE - 184ª geração] validação SEMÂNTICA contra a base oficial (fail-fast): só para células
            # que parecem NOME DE MUNICÍPIO — pula coordenadas e qualquer coisa com marcador de endereço ou dígitos
            # (endereço/CEP/código IBGE, onde o município não é a célula inteira e o geocoder resolve). O(1)/célula.
            elif pc is None and not _RE_ENDERECO_PV.search(v):
                _uf_pv, _muni_pv = None, v
                _mu = re.search(r"[\/\-,]?\s*([A-Za-z]{2})\s*$", v)
                if _mu and _mu.group(1).upper() in _UFS_PV:
                    _resto_pv = v[:_mu.start()].strip(" /-,")
                    if _resto_pv:
                        _uf_pv, _muni_pv = _mu.group(1).upper(), _resto_pv
                _cand_pv = IBGE_MUNICIPIOS.get(semantica.normalizar(_muni_pv))
                if _cand_pv is None and _uf_pv:            # a separação da UF pode ter errado: tenta o texto inteiro
                    _cand_inteiro = IBGE_MUNICIPIOS.get(semantica.normalizar(v))
                    if _cand_inteiro is not None:
                        _cand_pv, _uf_pv = _cand_inteiro, None
                if _cand_pv is None:
                    nao_enc.append(f"L{i+2}/{col}: {v}")
                elif len(_cand_pv) > 1 and not _uf_pv:
                    homon_sem_uf.append(f"L{i+2}/{col}: {v} ({','.join(sorted({e.get('uf', '') for e in _cand_pv}))})")

    achados = []

    def _add(id_, sev, titulo, itens, rec, corrigivel=False, contagem=None):
        c = contagem if contagem is not None else len(itens)
        if c <= 0:
            return
        ex = itens[:max_exemplos] if (isinstance(itens, list) and itens and isinstance(itens[0], str)) else []
        achados.append({"id": id_, "severidade": sev, "titulo": titulo, "contagem": c,
                        "exemplos": ex, "recomendacao": rec, "corrigivel": corrigivel})

    _add("linhas_incompletas", "critico", "Linhas com Origem ou Destino em branco",
         [f"linha {x}" for x in inc],
         "Essas linhas NÃO geram rota. Preencha ou remova antes de processar.", contagem=len(inc))
    _dup_extra = sum(c - 1 for c in pares.values() if c > 1)
    _add("duplicatas_exatas", "info", "Rotas repetidas (origem+destino idênticos)", [],
         f"{_dup_extra} linha(s) repetem uma rota já presente. O motor deduplica automaticamente (O(U)) — "
         f"apenas informativo, você não paga API por elas.", contagem=_dup_extra)
    _add("origem_igual_destino", "aviso", "Origem igual ao Destino (distância zero)", ig,
         "Rotas com origem = destino resultam em 0 km. Verifique se é intencional.")
    _add("coordenadas_suspeitas", "critico", "Coordenadas fora do Brasil ou com lat/lon trocadas", coord_ruim,
         "Coordenada inválida gera geocodificação/rota errada. Confira a ordem (lat, lon) e o sinal.")
    _add("encoding_suspeito", "aviso", "Texto com acentuação corrompida (mojibake)", moji,
         "Encoding quebrado (ex.: 'SÃ£o Paulo' → 'São Paulo'). O botão de higienização corrige automaticamente.", corrigivel=True)
    _add("espacos_problematicos", "info", "Espaços extras (início/fim ou duplicados)", esp,
         "Espaços supérfluos podem quebrar o casamento com o cache. A higienização corrige automaticamente.", corrigivel=True)
    _add("municipio_nao_encontrado", "critico", "Município não encontrado na base oficial do IBGE", nao_enc,
         "O nome não casa com nenhum município do IBGE — provável erro de digitação. Corrija antes de processar; "
         "senão a rota pode falhar ou cair em fallback impreciso.")
    _add("homonimo_sem_uf", "aviso", "Município homônimo sem UF (ambíguo)", homon_sem_uf,
         "Esse nome existe em mais de um estado. Sem a UF, o motor pode escolher o município errado — "
         "acrescente a sigla (ex.: 'São Domingos/SC').")

    # Score de saúde: 100 − penalidades ponderadas pela fração afetada. Duplicatas NÃO penalizam
    # (o dedup as resolve — são informativas/positivas).
    _pesos = {"critico": 45.0, "aviso": 20.0, "info": 6.0}
    base = max(1, n)
    penalidade = 0.0
    for a in achados:
        if a["id"] == "duplicatas_exatas":
            continue
        penalidade += _pesos[a["severidade"]] * min(1.0, a["contagem"] / base)
    score = round(max(0.0, min(100.0, 100.0 - penalidade)), 1)
    nota = "Excelente" if score >= 90 else "Boa" if score >= 75 else "Atenção" if score >= 55 else "Crítica"
    return {"score": score, "nota": nota, "total_linhas": n, "achados": achados}


# ==============================================================================
# [GOLDEN - 120ª geração] CADERNETA DE ROTAS DOURADAS (rotas verificadas)
# ------------------------------------------------------------------------------
# Flywheel de dado proprietário: o usuário marca rotas conferidas como VERIFICADAS;
# elas persistem com proveniência, são exportáveis e o Validador passa a avisar
# quando uma rota já foi verificada. Funções PURAS (store injetável) e testáveis.
# ==============================================================================
def _chave_rota_dourada(origem, destino):
    """[GOLDEN - 120ª] Chave canônica DIRECIONAL (origem→destino) de uma rota, normalizada (sem acento,
    minúsculo, espaços colapsados). Direcional porque a distância pode diferir por sentido. PURO."""
    return f"{_prevoo_strip_acentos(origem)}=>{_prevoo_strip_acentos(destino)}"


def _golden_store(store=None):
    """[GOLDEN - 120ª] Resolve o store (injetável p/ teste; senão o cache persistente global)."""
    if store is not None:
        return store
    return cache_rotas_douradas if "cache_rotas_douradas" in globals() else {}


def _registrar_rota_dourada(origem, destino, dados, store=None):
    """[GOLDEN - 120ª] Grava/atualiza uma rota VERIFICADA na caderneta. `dados`: dict com o resultado
    (km, tempo, fonte, score, coords...). Carimba data de verificação e a chave. store injetável.
    Retorna o registro salvo (dict)."""
    _st = _golden_store(store)
    reg = dict(dados or {})
    reg["origem"] = str(origem)
    reg["destino"] = str(destino)
    reg["chave"] = _chave_rota_dourada(origem, destino)
    reg.setdefault("verificada_em", time.strftime("%Y-%m-%d %H:%M:%S"))
    try:
        if hasattr(_st, "set"):
            _st.set(reg["chave"], reg, expire=None)
        else:
            _st[reg["chave"]] = reg
    except Exception:
        try:
            _st[reg["chave"]] = reg
        except Exception:
            pass
    return reg


def _buscar_rota_dourada(origem, destino, store=None):
    """[GOLDEN - 120ª] Busca uma rota verificada pela chave direcional. Retorna o registro (dict) ou None."""
    _st = _golden_store(store)
    ch = _chave_rota_dourada(origem, destino)
    try:
        return _st.get(ch)
    except Exception:
        return None


def _listar_rotas_douradas(store=None):
    """[GOLDEN - 120ª] Retorna a lista de registros verificados (dicts). store injetável."""
    _st = _golden_store(store)
    regs = []
    try:
        for ch in list(_st):
            try:
                v = _st.get(ch) if hasattr(_st, "get") else _st[ch]
                if isinstance(v, dict):
                    regs.append(v)
            except Exception:
                continue
    except Exception:
        return []
    return regs


def _reconciliar_rota_dourada(km_calculado, registro_dourado, limiar_pct=10.0):
    """[GOLDEN-RECON - 122ª geração] Reconcilia o km recém-calculado com o valor VERIFICADO (golden).
    Detecta DRIFT (a via mudou ou a verificação está desatualizada). Usa a métrica de divergência
    centralizada do app (_metricas_divergencia: |a−b|/max(a,b)×100, em [0,100]). PURO. Retorna dict
    {verificada, km_verificado, km_calculado, divergencia_km, divergencia_pct, status, classificacao};
    status ∈ {'sem_registro', 'confirmado', 'divergente'}."""
    def _f(v):
        try:
            return float(v)
        except (TypeError, ValueError):
            return None
    kv = _f((registro_dourado or {}).get("km")) if isinstance(registro_dourado, dict) else None
    kc = _f(km_calculado)
    if kv is None or kv <= 0:
        return {"verificada": False, "km_verificado": None, "km_calculado": kc,
                "divergencia_km": 0.0, "divergencia_pct": 0.0, "status": "sem_registro", "classificacao": ""}
    if kc is None or kc <= 0:
        return {"verificada": True, "km_verificado": round(kv, 1), "km_calculado": None,
                "divergencia_km": 0.0, "divergencia_pct": 0.0, "status": "confirmado", "classificacao": ""}
    _m = _metricas_divergencia(kv, kc)
    pct = _m["pct"] if _m else round(abs(kv - kc) / max(kv, kc) * 100.0, 1)
    status = "divergente" if pct > limiar_pct else "confirmado"
    return {"verificada": True, "km_verificado": round(kv, 1), "km_calculado": round(kc, 1),
            "divergencia_km": round(kc - kv, 1), "divergencia_pct": pct, "status": status,
            "classificacao": (_m["classificacao"] if _m else "")}


def _indice_dor_logistica(dist_viaria, linha_reta, tem_balsa, modo_acesso, dist_max_ref=1500.0):
    """[DOR-LOG - 123ª geração] Índice 0-100 de 'dor logística' de uma rota: quão difícil/custoso é
    atender aquele destino. Combina sinais JÁ medidos — distância absoluta (normalizada por dist_max_ref),
    sinuosidade (viária/reta), dependência de balsa e acesso fluvial/isolado (REGIC). PURO."""
    def _f(v, d=0.0):
        try:
            return float(v)
        except (TypeError, ValueError):
            return d
    dv, lr = _f(dist_viaria), _f(linha_reta)
    _m = str(modo_acesso or "").lower()
    _fluvial = ("fluvial" in _m) or ("isolado" in _m)
    if lr > 0 and dv > 0:
        c_sin = min(100.0, max(0.0, (dv / lr - 1.4) / (3.0 - 1.4) * 100.0))
    else:
        c_sin = 0.0
    c_dist = min(100.0, max(0.0, (dv / dist_max_ref) * 100.0)) if dv > 0 else 0.0
    c_balsa = 100.0 if tem_balsa else 0.0
    c_isol = 100.0 if _fluvial else 0.0
    dor = 0.30 * c_dist + 0.25 * c_sin + 0.25 * c_balsa + 0.20 * c_isol
    return round(max(0.0, min(100.0, dor)), 1)


def _agregar_dor_logistica(registros):
    """[DOR-LOG - 123ª geração] Agrega dicts {municipio, dor, lat, lon} por município → lista ordenada
    por dor média desc: [{municipio, dor_media, n, lat, lon}]. PURO."""
    _por = {}
    for r in registros:
        mun = str(r.get("municipio", "") or "").strip()
        if not mun or mun.lower() == "nan":
            continue
        if mun not in _por:
            _por[mun] = {"dores": [], "lat": r.get("lat"), "lon": r.get("lon")}
        _por[mun]["dores"].append(float(r.get("dor", 0.0)))
    out = [{"municipio": mun, "dor_media": round(sum(d["dores"]) / len(d["dores"]), 1),
            "n": len(d["dores"]), "lat": d["lat"], "lon": d["lon"]}
           for mun, d in _por.items() if d["dores"]]
    out.sort(key=lambda x: x["dor_media"], reverse=True)
    return out


def _cor_dor_logistica(dor):
    """[DOR-LOG - 123ª geração] Gradiente verde→amarelo→vermelho (hex) para um valor de dor 0-100. PURO."""
    d = max(0.0, min(100.0, float(dor) if dor is not None else 0.0))
    if d < 50:
        r, g = int(255 * (d / 50.0)), 200
    else:
        r, g = 255, int(200 * (1 - (d - 50.0) / 50.0))
    return f"#{r:02x}{g:02x}35"


def _narrativa_executiva_lote(stats):
    """[NARRATIVA - 124ª geração] Narrativa executiva em linguagem natural a partir de AGREGADOS do lote
    (dict) — NÃO acessa DataFrame (recebe números prontos → PURO e testável). Estende a leitura do analista
    (118ª) para o lote inteiro. Chaves: total, pct_rodoviario, n_balsa, n_fluvial, dist_media, dist_max,
    score_medio, uf_top, dor_top_mun, dor_top_valor. Retorna str (Markdown)."""
    def _i(k, d=0):
        try:
            return int(stats.get(k, d))
        except (TypeError, ValueError):
            return d

    def _f(k, d=0.0):
        try:
            return float(stats.get(k, d))
        except (TypeError, ValueError):
            return d
    total = _i("total")
    if total <= 0:
        return "Nenhuma rota válida para resumir."
    partes = [f"Foram processadas **{total:,} rota(s)**".replace(",", ".")]
    _pct_rod = _f("pct_rodoviario")
    if _pct_rod > 0:
        partes[-1] += f", das quais **{_pct_rod:.0f}% são totalmente rodoviárias**"
    partes[-1] += "."
    _nb, _nf = _i("n_balsa"), _i("n_fluvial")
    if _nb > 0 or _nf > 0:
        _h = []
        if _nb > 0:
            _h.append(f"**{_nb}** dependem de **balsa/ferry**")
        if _nf > 0:
            _h.append(f"**{_nf}** têm **acesso fluvial/isolado** (IBGE REGIC)")
        partes.append("Do total, " + " e ".join(_h) + " — pontos que exigem atenção logística especial.")
    else:
        partes.append("Nenhuma rota depende de balsa ou tem acesso fluvial/isolado — malha integralmente rodoviária.")
    _dm, _dx, _sc = _f("dist_media"), _f("dist_max"), _f("score_medio")
    _d3 = []
    if _dm > 0:
        _d3.append(f"distância média de **{_dm:.0f} km**" + (f" (máxima {_dx:.0f} km)" if _dx > 0 else ""))
    if _sc > 0:
        _d3.append(f"confiança geográfica média de **{_sc:.0f}/100**")
    if _d3:
        partes.append("A operação tem " + " e ".join(_d3) + ".")
    _uf = str(stats.get("uf_top", "") or "").strip()
    _mun = str(stats.get("dor_top_mun", "") or "").strip()
    _d4 = []
    if _uf:
        _d4.append(f"a UF **{_uf}** concentra a maior dificuldade agregada")
    if _mun:
        _d4.append(f"o município mais difícil é **{_mun}** ({_f('dor_top_valor'):.0f}/100 de dor logística)")
    if _d4:
        partes.append("Em distribuição territorial, " + " e ".join(_d4) + ".")
    return " ".join(partes)


def _haversine_matriz(lats_a, lons_a, lats_b, lons_b):
    """[HUBOPT - 121ª geração] Matriz de distâncias Haversine (km) entre A (m pontos) e B (n pontos).
    Retorna np.ndarray (m, n), vetorizado. PURO. Mesmo critério de linha reta do ranking de proximidade."""
    import numpy as np
    R = 6371.0088
    la = np.radians(np.asarray(lats_a, dtype=float))[:, None]
    lo_a = np.radians(np.asarray(lons_a, dtype=float))[:, None]
    lb = np.radians(np.asarray(lats_b, dtype=float))[None, :]
    lo_b = np.radians(np.asarray(lons_b, dtype=float))[None, :]
    h = np.sin((lb - la) / 2.0) ** 2 + np.cos(la) * np.cos(lb) * np.sin((lo_b - lo_a) / 2.0) ** 2
    return 2.0 * R * np.arcsin(np.sqrt(np.clip(h, 0.0, 1.0)))


def _otimizar_hubs(clientes, candidatos, p=1, pesos=None, objetivo="total", swaps=True):
    """[HUBOPT - 121ª geração] Seleciona p locais (dentre `candidatos`) que minimizam o custo de atender
    os `clientes`. Duas fases: (1) construção GULOSA (adiciona o hub que mais reduz o custo) e (2) melhoria
    por TROCA (interchange / Teitz-Bart): tenta substituir cada hub escolhido por cada candidato de fora e
    aceita a melhor troca que reduzir o custo, até estabilizar — isso corrige as 'armadilhas' do guloso.
    objetivo='total' (soma ponderada da distância ao hub mais próximo) ou 'max' (maior distância).
    clientes/candidatos: sequências de (lat, lon). PURO. Retorna dict com
    {escolhidos:[idx_candidato], custo, custo_total_km, dist_media_km, dist_max_km, atribuicao}."""
    import numpy as np
    C = np.asarray(list(clientes), dtype=float)
    K = np.asarray(list(candidatos), dtype=float)
    m, n = len(C), len(K)
    if m == 0 or n == 0:
        return {"escolhidos": [], "custo": float("inf"), "custo_total_km": 0.0,
                "dist_media_km": 0.0, "dist_max_km": 0.0, "atribuicao": []}
    w = np.ones(m) if pesos is None else np.asarray(pesos, dtype=float)
    D = _haversine_matriz(K[:, 0], K[:, 1], C[:, 0], C[:, 1])  # (n, m): candidato × cliente
    p = max(1, min(int(p), n))

    def _custo(sel):
        dmin = D[sel].min(axis=0)
        return float(dmin.max()) if objetivo == "max" else float((w * dmin).sum())

    # (1) construção gulosa
    escolhidos = []
    melhor = np.full(m, np.inf)
    for _ in range(p):
        novo_all = np.minimum(melhor[None, :], D)
        custos = (novo_all.max(axis=1) if objetivo == "max"
                  else (novo_all * w[None, :]).sum(axis=1)).astype(float).copy()
        if escolhidos:
            custos[escolhidos] = np.inf
        j = int(np.argmin(custos))
        escolhidos.append(j)
        melhor = novo_all[j]

    # (2) melhoria por troca (vertex substitution) — escapa das armadilhas do guloso
    if swaps and 1 <= p < n:
        sel = list(escolhidos)
        custo_atual = _custo(sel)
        for _ in range(50):  # converge rápido para p pequeno
            _fora = [c for c in range(n) if c not in sel]
            _best = None
            for _hi in range(len(sel)):
                for _c in _fora:
                    _cand_sel = sel.copy()
                    _cand_sel[_hi] = _c
                    _cst = _custo(_cand_sel)
                    if _cst < custo_atual - 1e-9 and (_best is None or _cst < _best[0]):
                        _best = (_cst, _cand_sel)
            if _best is None:
                break
            custo_atual, sel = _best[0], _best[1]
        escolhidos = sel

    melhor = D[escolhidos].min(axis=0)
    _atrib_local = np.argmin(D[escolhidos], axis=0)                    # 0..p-1 por cliente
    atribuicao = [escolhidos[a] for a in _atrib_local.tolist()]
    return {
        "escolhidos": escolhidos,
        "custo": (float(np.max(melhor)) if objetivo == "max" else float(np.sum(w * melhor))),
        "custo_total_km": round(float(np.sum(w * melhor)), 1),
        "dist_media_km": round(float(np.average(melhor, weights=w)), 1),
        "dist_max_km": round(float(np.max(melhor)), 1),
        "atribuicao": atribuicao,
    }


def _tsp_ordem(pontos, retornar_origem=False):
    """[TSP - 125ª geração] Ordem de visita (quase) ótima para N paradas (milk-run): vizinho-mais-próximo
    + melhoria 2-opt. pontos: sequência de (lat, lon). Reusa _haversine_matriz. PURO. Retorna dict
    {ordem:[idx], distancia_total_km, distancia_por_perna:[km]}."""
    import numpy as np
    P = np.asarray(list(pontos), dtype=float)
    n = len(P)
    if n == 0:
        return {"ordem": [], "distancia_total_km": 0.0, "distancia_por_perna": []}
    if n == 1:
        return {"ordem": [0], "distancia_total_km": 0.0, "distancia_por_perna": []}
    D = _haversine_matriz(P[:, 0], P[:, 1], P[:, 0], P[:, 1])

    def _total(seq):
        t = sum(D[seq[i]][seq[i + 1]] for i in range(len(seq) - 1))
        if retornar_origem and len(seq) > 1:
            t += D[seq[-1]][seq[0]]
        return t
    # construção: vizinho mais próximo a partir de 0
    visit = [False] * n
    ordem = [0]
    visit[0] = True
    for _ in range(n - 1):
        u = ordem[-1]
        nxt, best = -1, float("inf")
        for v in range(n):
            if not visit[v] and D[u][v] < best:
                best, nxt = D[u][v], v
        ordem.append(nxt)
        visit[nxt] = True
    # melhoria 2-opt (reversão de segmentos)
    it, melhorou = 0, True
    while melhorou and it < 80:
        melhorou = False
        it += 1
        _base = _total(ordem)
        for i in range(1, n - 1):
            for k in range(i + 1, n):
                nova = ordem[:i] + ordem[i:k + 1][::-1] + ordem[k + 1:]
                _nv = _total(nova)
                if _nv < _base - 1e-9:
                    ordem, _base, melhorou = nova, _nv, True
    _pernas = [round(float(D[ordem[i]][ordem[i + 1]]), 1) for i in range(n - 1)]
    if retornar_origem and n > 1:
        _pernas.append(round(float(D[ordem[-1]][ordem[0]]), 1))
    return {"ordem": ordem, "distancia_total_km": round(sum(_pernas), 1), "distancia_por_perna": _pernas}


@st.cache_data(show_spinner=False)
def _contar_rotas_unicas_preview(file_id, n_linhas, _origens, _destinos):
    """[PERF-UI1 - 15ª geração] Conta rotas únicas (pares origem-destino válidos) com
    cache do Streamlit, chaveado APENAS pela identidade do arquivo (file_id = nome+
    tamanho) e nº de linhas. Os argumentos _origens/_destinos têm prefixo '_' para que
    o Streamlit NÃO os inclua no hash da chave de cache (senão hashear 100k itens
    custaria tanto quanto o cálculo). Antes, a prévia recalculava set(zip(...)) sobre
    TODO o DataFrame a CADA rerun (cada tecla no campo de operador) — desperdício real
    em planilhas grandes. Agora só recalcula quando o arquivo muda. Lógica idêntica."""
    pares = set()
    for o, d in zip(_origens, _destinos):
        o_s = str(o).strip() if o is not None else ''
        d_s = str(d).strip() if d is not None else ''
        if o_s and d_s and o_s.lower() != 'nan' and d_s.lower() != 'nan':
            pares.add((o_s, d_s))
    return len(pares)

def _auditar_rotas_suspeitas(df):
    """[AUDIT-SUSPEITAS - 43ª geração] Análise automática pós-lote: sinaliza rotas cuja razão
    distância viária ÷ linha reta é técnica OU estatisticamente anômala (possível erro de
    geocodificação, snap distante ou rota genuinamente sinuosa). Retorna (df_suspeitas, resumo).
    Read-only e sem rede — usa apenas dados JÁ calculados (custo desprezível)."""
    try:
        if df is None or 'Distancia' not in df.columns or 'Linha Reta' not in df.columns:
            return None, {}
        _d = df.copy()
        _dist = pd.to_numeric(_d['Distancia'], errors='coerce')
        _reta = pd.to_numeric(_d['Linha Reta'], errors='coerce')
        _valid = (_dist > 0) & (_reta > 0.5)  # ignora reta ~0 (pontos coincidentes) e falhas
        _d = _d[_valid].copy()
        if _d.empty:
            return None, {"total": 0, "suspeitas": 0}
        _d['_ratio'] = pd.to_numeric(_d['Distancia'], errors='coerce') / pd.to_numeric(_d['Linha Reta'], errors='coerce')
        _d['_pct'] = (_d['_ratio'] - 1.0) * 100.0
        # Limiar técnico: fator de desvio rodoviário típico ~1,2–1,4; ≥1,8 é suspeito.
        _LIMIAR_TEC = 1.8
        # Limiar estatístico: outlier superior de IQR (Tukey).
        _q1, _q3 = _d['_ratio'].quantile(0.25), _d['_ratio'].quantile(0.75)
        _iqr = _q3 - _q1
        _lim_est = _q3 + 1.5 * _iqr if _iqr > 0 else _LIMIAR_TEC
        _limiar = max(_LIMIAR_TEC, _lim_est)
        _susp = _d[_d['_ratio'] >= _limiar].copy().sort_values('_ratio', ascending=False)
        resumo = {"total": int(len(_d)), "suspeitas": int(len(_susp)), "limiar": round(float(_limiar), 2),
                  "ratio_mediano": round(float(_d['_ratio'].median()), 2)}
        return _susp, resumo
    except Exception as e:
        logger.error(f"[AUDIT-SUSPEITAS] Falha na auditoria automática (isolada): {e}")
        return None, {}


def renderizar_scorecard_qualidade(df_resultado):
    """[F-NEW1 - 3ª geração] Painel de Qualidade dos Dados Geográficos.
    
    Calcula e exibe indicadores agregados de qualidade da geocodificação de um lote:
    taxa de sucesso, distribuição de confiança, detecção de anomalias e cobertura
    de fontes. Tudo derivado de colunas já existentes — custo computacional trivial.
    Atende Etapa 7 (Analytics: indicadores de qualidade, precisão e sucesso).
    """
    import streamlit as _st
    total = len(df_resultado)
    if total == 0:
        return

    # --- Métricas de sucesso e falha ---
    lat_o = pd.to_numeric(df_resultado.get('Lat Origem', 0), errors='coerce').fillna(0)
    lat_d = pd.to_numeric(df_resultado.get('Lat Destino', 0), errors='coerce').fillna(0)
    geocodificados = int(((lat_o != 0) & (lat_d != 0)).sum())
    taxa_sucesso = round(100 * geocodificados / total, 1) if total else 0.0

    # --- Distribuição de confiança (Score Final Global) ---
    score_col = pd.to_numeric(df_resultado.get('Score Final Global', 0), errors='coerce').fillna(0)
    excelente = int((score_col >= 90).sum())
    boa = int(((score_col >= 80) & (score_col < 90)).sum())
    aceitavel = int(((score_col >= 70) & (score_col < 80)).sum())
    revisar = int(((score_col > 0) & (score_col < 70)).sum())

    # --- Detecção de anomalias geográficas ---
    dist_via = pd.to_numeric(df_resultado.get('Distancia', 0), errors='coerce').fillna(0)
    linha_reta = pd.to_numeric(df_resultado.get('Linha Reta', 0), errors='coerce').fillna(0)
    # Anomalia: distância viária absurdamente maior que linha reta (possível erro de rota)
    mask_ratio = linha_reta > 0
    ratio = (dist_via[mask_ratio] / linha_reta[mask_ratio]).replace([float('inf')], 0)
    anomalias_ratio = int((ratio > 4.0).sum())
    # Rotas com distância zero mas pontos distintos (suspeita de cache poisoning residual)
    zeros_suspeitos = int(((dist_via == 0) & (lat_o != 0) & (lat_d != 0)).sum())

    _st.markdown("### 🎯 Scorecard de Qualidade dos Dados Geográficos")
    _st.caption("Indicadores automáticos de confiabilidade do lote processado. Quanto mais verde, mais confiável o resultado.")

    c1, c2, c3, c4 = _st.columns(4)
    c1.metric("Taxa de Geocodificação", f"{taxa_sucesso}%",
              help="Percentual de rotas em que origem E destino foram localizados com sucesso na malha geográfica.")
    c2.metric("Alta Confiança (≥80)", f"{excelente + boa}",
              delta=f"{round(100*(excelente+boa)/total,1)}% do total" if total else "0%",
              help="Rotas com score de confiança igual ou superior a 80 — mercadoria chega à porta correta.")
    c3.metric("Requerem Revisão (<70)", f"{revisar}",
              delta=f"-{round(100*revisar/total,1)}%" if total else "0%", delta_color="inverse",
              help="Rotas com baixa confiança que merecem checagem manual do endereço.")
    c4.metric("Anomalias Detectadas", f"{anomalias_ratio + zeros_suspeitos}",
              delta_color="inverse",
              help="Rotas com desvio viário implausível (>4× a linha reta) ou distância zero suspeita.")

    # Barra de distribuição visual de qualidade
    _st.markdown("**Distribuição de Qualidade do Lote:**")
    if total > 0:
        seg = lambda n, cor, lbl: (f"<div style='flex:{max(n,0.001)}; background:{cor}; height:28px; "
                                   f"display:flex; align-items:center; justify-content:center; "
                                   f"color:white; font-size:11px; font-weight:600;' "
                                   f"title='{lbl}: {n}'>{n if n/total > 0.04 else ''}</div>")
        barra = ("<div style='display:flex; width:100%; border-radius:6px; overflow:hidden; margin:8px 0;'>"
                 + seg(excelente, "#2ECC71", "Excelente")
                 + seg(boa, "#3498DB", "Boa")
                 + seg(aceitavel, "#F1C40F", "Aceitável")
                 + seg(revisar, "#E74C3C", "Revisar")
                 + "</div>")
        _st.markdown(barra, unsafe_allow_html=True)
        _st.caption("🟢 Excelente (≥90) · 🔵 Boa (80-89) · 🟡 Aceitável (70-79) · 🔴 Revisar (<70)")

    # Alertas acionáveis de auditoria
    if zeros_suspeitos > 0:
        _st.warning(f"⚠️ {zeros_suspeitos} rota(s) com distância zero entre pontos distintos. "
                    f"O motor anti-cache-poisoning normalmente corrige isso, mas vale auditar na aba 🔍 Auditoria.")
    if anomalias_ratio > 0:
        _st.warning(f"⚠️ {anomalias_ratio} rota(s) com desvio viário acima de 4× a linha reta. "
                    f"Pode indicar travessia de balsa, barreira geográfica real, ou erro de roteamento. Verifique os links.")
    if taxa_sucesso == 100.0 and anomalias_ratio == 0 and zeros_suspeitos == 0:
        _st.success("✅ Lote íntegro: 100% geocodificado, sem anomalias geográficas detectadas.")

def gerar_insights_automaticos(df_kpi):
    """[F-NEW3 - 4ª geração] Descoberta automática de padrões e anomalias.
    
    Varre o DataFrame filtrado e gera frases de insight em linguagem natural,
    destacando o que mais chama atenção: concentração geográfica, outliers de
    distância, faixas de qualidade dominantes e fontes de geocodificação.
    Tudo via agregações pandas vetorizadas — custo trivial, zero chamadas externas.
    Retorna lista de tuplas (tipo, texto) onde tipo ∈ {info, sucesso, alerta}.
    """
    insights = []
    total = len(df_kpi)
    if total == 0:
        return insights
    try:
        # 1. Concentração geográfica (regra de Pareto)
        if 'UF_Sintetica_Origem' in df_kpi.columns:
            top_uf = df_kpi['UF_Sintetica_Origem'].value_counts()
            if len(top_uf) > 0:
                uf_lider = top_uf.index[0]
                pct = round(100 * top_uf.iloc[0] / total, 1)
                if pct >= 40:
                    insights.append(("info", f"📍 **Concentração geográfica:** {pct}% das rotas partem de **{uf_lider}**. "
                                             f"Uma única UF domina a operação — considere otimizar logística regional."))

        # 2. Distância: outliers e média
        if 'Distancia' in df_kpi.columns:
            dist = pd.to_numeric(df_kpi['Distancia'], errors='coerce').fillna(0)
            dist_validas = dist[dist > 0]
            if len(dist_validas) > 0:
                media = dist_validas.mean()
                p95 = dist_validas.quantile(0.95)
                maxd = dist_validas.max()
                if maxd > media * 3 and len(dist_validas) >= 5:
                    insights.append(("alerta", f"📏 **Outlier de distância:** a rota mais longa ({maxd:.0f} km) é "
                                               f"{round(maxd/media,1)}× a média ({media:.0f} km). Vale conferir se não há erro de endereço."))
                insights.append(("info", f"📊 **Perfil de distância:** média de {media:.0f} km; "
                                         f"95% das rotas têm até {p95:.0f} km."))

        # 3. Qualidade dominante
        if 'Status da Rota' in df_kpi.columns:
            status = df_kpi['Status da Rota'].value_counts()
            if len(status) > 0:
                revisar = int(df_kpi['Status da Rota'].isin(['Revisar', 'Erro', 'Erro Crítico de Processamento']).sum())
                pct_revisar = round(100 * revisar / total, 1)
                if pct_revisar >= 20:
                    insights.append(("alerta", f"⚠️ **Atenção à qualidade:** {pct_revisar}% das rotas ({revisar}) precisam de revisão. "
                                               f"Endereços incompletos podem ser a causa — adicione cidade e UF."))
                elif pct_revisar <= 5:
                    insights.append(("sucesso", f"✅ **Alta qualidade:** apenas {pct_revisar}% das rotas requerem revisão. "
                                                f"Excelente padronização dos endereços de entrada."))

        # 4. Fonte de geocodificação predominante
        if 'Fonte Geocoding Origem' in df_kpi.columns:
            fontes = df_kpi['Fonte Geocoding Origem'].value_counts()
            if len(fontes) > 0:
                fonte_lider = fontes.index[0]
                pct_f = round(100 * fontes.iloc[0] / total, 1)
                insights.append(("info", f"🛰️ **Fonte dominante:** {pct_f}% das geocodificações vieram de **{fonte_lider}**. "
                                         f"Diversidade de fontes aumenta a robustez do consenso."))

        # 5. Uso de balsas (insight logístico específico)
        if 'Balsas' in df_kpi.columns:
            balsas = int((df_kpi['Balsas'] == 'Sim').sum())
            if balsas > 0:
                insights.append(("alerta", f"⛴️ **Travessias de balsa:** {balsas} rota(s) exigem balsa. "
                                           f"Isso impacta prazo e custo — sinalize no planejamento."))
    except Exception:
        pass
    return insights

