def inicializar_listas_fuzzy(ibge_mun, ibge_dist):
    lista_fuzzy = []
    for k, v_list in ibge_mun.items(): 
        for v in v_list: 
            lista_fuzzy.append(f"{k} {v['uf']}")
    for k, v_list in ibge_dist.items(): 
        for v in v_list: 
            lista_fuzzy.append(f"{k} {v['uf']}")
    return list(set(lista_fuzzy))

