# VALIDADOR PRÉ-GEOCODING E LÓGICA GEODÉSICA CORPORATIVA (MULTI-CAMADA)
# ==============================================================================

@_lru_cache(maxsize=256)
def parse_tempo_minutos(t_str):
    if not isinstance(t_str, str): 
        return 999999
    try:
        h = re.search(r'(\d+)\s*h', t_str)
        m = re.search(r'(\d+)\s*min', t_str)
        horas = int(h.group(1)) if h else 0
        mins = int(m.group(1)) if m else 0
        
        if not h and not m:
            nums = re.findall(r'\d+', t_str)
            if nums: 
                return int(nums[0])
            return 999999
        return horas * 60 + mins
    except Exception:
        return 999999

def validar_coordenada_brasil(lat, lon):
    try:
        lat_f, lon_f = float(lat), float(lon)
        if (-35.0 <= lat_f <= 6.0) and (-75.0 <= lon_f <= -28.0):
            return True, lat_f, lon_f
        if (-35.0 <= lon_f <= 6.0) and (-75.0 <= lat_f <= -28.0):
            return True, lon_f, lat_f 
        return False, lat_f, lon_f
    except (ValueError, TypeError):
        return False, 0.0, 0.0

def calcular_distancia_linha_reta(lat1, lon1, lat2, lon2, contexto=""):
    global METRICAS_DISTANCIA
    _incrementar_metrica("total_calculos")
    try:
        lat1, lon1, lat2, lon2 = float(lat1), float(lon1), float(lat2), float(lon2)
        dist_final = 0.0
        status_final = ""
        
        if lat1 == 0.0 or lon1 == 0.0 or lat2 == 0.0 or lon2 == 0.0:
             return 0.0, "Falha Operacional (Coordenadas Ausentes)"
             
        if lat1 == lat2 and lon1 == lon2:
             return 0.0, "Calculada Normalmente (Pontos Coincidentes)"
             
        calculado_sucesso = False
        if GEOGRAPHICLIB_DISPONIVEL:
            try:
                # [G23 - 2ª geração] GeographicLib (algoritmo de Karney) = padrão-ouro WGS-84.
                # Precisão de ~15 nanômetros — exatidão geodésica máxima tecnicamente possível.
                dist_metros = Geodesic.WGS84.Inverse(lat1, lon1, lat2, lon2)['s12']
                dist_km = dist_metros / 1000.0
                if dist_km > 0:
                    _incrementar_metrica("sucesso_geographiclib")
                    dist_final, status_final = round(dist_km, 3), "Calculada via GeographicLib WGS-84 (Karney, erro <1mm)"
                    calculado_sucesso = True
            except Exception as e:
                logger.warning(f"GeographicLib falhou: {e}")
                
        if not calculado_sucesso and GEOPY_DISPONIVEL:
            try:
                dist_km = geodesic((lat1, lon1), (lat2, lon2)).km
                if dist_km > 0:
                    _incrementar_metrica("sucesso_geopy")
                    dist_final, status_final = round(dist_km, 3), "Calculada via Geopy Geodesic (elipsoide WGS-84)"
                    calculado_sucesso = True
            except Exception as e:
                logger.warning(f"Geopy falhou: {e}")
                
        if not calculado_sucesso:
            lat1_r, lon1_r, lat2_r, lon2_r = map(math.radians, [lat1, lon1, lat2, lon2])
            dlat = lat2_r - lat1_r
            dlon = lon2_r - lon1_r
            a = math.sin(dlat / 2)**2 + math.cos(lat1_r) * math.cos(lat2_r) * math.sin(dlon / 2)**2
            c = 2 * math.asin(math.sqrt(a))
            # [G23 - 2ª geração] Raio médio autálico IUGG (6371.0088 km) em vez de 6371.0.
            # Reduz o erro sistemático do Haversine esférico em ~8,8m por 1000km.
            dist_haversine = 6371.0088 * c
            
            if dist_haversine >= 0.01:
                _incrementar_metrica("fallback_haversine")
                dist_final, status_final = round(dist_haversine, 3), "Calculada via Fallback Haversine (esfera IUGG, erro ~0.5%)"
            else:
                logger.error(f"FALHA CRÍTICA PREVENIDA: Distância zerada para pontos diferentes. {lat1},{lon1} a {lat2},{lon2} | Ctx: {contexto}")
                _incrementar_metrica("correcoes_automaticas")
                dist_final, status_final = 0.01, "Calculada após reprocessamento (Correção Anti-Zero)"
                
        if dist_final > 5000.0:
            logger.error(f"ANOMALIA TERRITORIAL: Distância de {dist_final}km excede fisicamente os limites do Brasil. Ctx: {contexto}")
            _incrementar_metrica("barreira_territorial")
            return 0.01, "Falha de Bounding Box (Distância Transcontinental Impossível)"
            
        return dist_final, status_final
    except Exception as e:
        logger.error(f"Erro fatal no motor de distância geodésica ({contexto}): {e}")
        _incrementar_metrica("falhas_criticas")
        return 0.0, "Falha Operacional Crítica no Motor Geodésico"

def _distancia_consenso_km(lat1, lon1, lat2, lon2):
    """[PERF-Q2 - 11ª geração] Distância geodésica para comparações INTERNAS do
    consenso Bayesiano (loop O(n²) entre candidatos de API). Usa EXATAMENTE a mesma
    matemática de calcular_distancia_linha_reta (GeographicLib Karney → Geopy →
    Haversine IUGG), mas SEM incrementar os contadores globais de telemetria.

    Dois benefícios líquidos, zero perda:
    1) PERFORMANCE: elimina a contenção do _LOCK_METRICAS no loop O(n²) executado por
       múltiplas threads em paralelo (cada chamada antiga pegava o lock 1-2×).
    2) QUALIDADE/AUDITORIA: METRICAS_DISTANCIA passa a refletir apenas distâncias de
       ROTAS reais, não comparações internas de consenso — métricas de auditoria mais
       fiéis (ex: 'total_calculos' deixa de ser inflado por uso interno).
    O valor numérico retornado é idêntico ao da função pública para os mesmos pontos.
    """
    try:
        lat1, lon1, lat2, lon2 = float(lat1), float(lon1), float(lat2), float(lon2)
        if lat1 == 0.0 or lon1 == 0.0 or lat2 == 0.0 or lon2 == 0.0:
            return 0.0
        if lat1 == lat2 and lon1 == lon2:
            return 0.0
        if GEOGRAPHICLIB_DISPONIVEL:
            try:
                dist_km = Geodesic.WGS84.Inverse(lat1, lon1, lat2, lon2)['s12'] / 1000.0
                if dist_km > 0:
                    return round(dist_km, 3)
            except Exception:
                pass
        if GEOPY_DISPONIVEL:
            try:
                dist_km = geodesic((lat1, lon1), (lat2, lon2)).km
                if dist_km > 0:
                    return round(dist_km, 3)
            except Exception:
                pass
        lat1_r, lon1_r, lat2_r, lon2_r = map(math.radians, [lat1, lon1, lat2, lon2])
        dlat = lat2_r - lat1_r
        dlon = lon2_r - lon1_r
        a = math.sin(dlat / 2)**2 + math.cos(lat1_r) * math.cos(lat2_r) * math.sin(dlon / 2)**2
        c = 2 * math.asin(math.sqrt(a))
        return round(6371.0088 * c, 3)
    except Exception:
        return 0.0

def cascata_postal_tripla(cep_limpo):
    if cep_limpo in cache_cep:
        d = cache_cep[cep_limpo]
        if len(d) == 4: 
            return d[0], d[1], d[2], d[3], 0.0, 0.0
        return d
        
    lat, lon = 0.0, 0.0
    try:
        r = session.get(f"https://brasilapi.com.br/api/cep/v2/{cep_limpo}", timeout=4).json()
        if "city" in r:
            loc = r.get("location", {}).get("coordinates", {})
            if loc and "latitude" in loc and "longitude" in loc:
                try: 
                    lat, lon = float(loc["latitude"]), float(loc["longitude"])
                except (ValueError, TypeError): 
                    pass
            d = (r.get('street', ''), r.get('neighborhood', ''), r.get('city', ''), r.get('state', ''), lat, lon)
            cache_cep.set(cep_limpo, d, expire=2592000)
            return d
    except Exception: 
        pass
        
    try:
        def _nom_cep():
            _throttle_nominatim()
            url = f"https://nominatim.openstreetmap.org/search?format=json&postalcode={cep_limpo}&countrycodes=br&limit=1"
            return session.get(url, headers={"User-Agent": "RotasEnterprise/8.0"}, timeout=4).json()
        r_nom = FILA_NOMINATIM.submit(_nom_cep).result()
        if r_nom: 
            lat, lon = float(r_nom[0]['lat']), float(r_nom[0]['lon'])
    except Exception: 
        pass
        
    try:
        r = session.get(f"https://viacep.com.br/ws/{cep_limpo}/json/", timeout=4).json()
        if "erro" not in r:
            d = (r.get('logradouro', ''), r.get('bairro', ''), r.get('localidade', ''), r.get('uf', ''), lat, lon)
            cache_cep.set(cep_limpo, d, expire=2592000)
            return d
    except Exception: 
        pass
        
    try:
        r = session.get(f"https://opencep.com/v1/{cep_limpo}", timeout=4).json()
        if "error" not in r:
            d = (r.get('logradouro', ''), r.get('bairro', ''), r.get('localidade', ''), r.get('uf', ''), lat, lon)
            cache_cep.set(cep_limpo, d, expire=2592000)
            return d
    except Exception: 
        pass
        
    return "", "", "", "", 0.0, 0.0

def validar_consistencia_administrativa(candidato, uf_inf):
    est_api = unidecode(candidato.get('estado', '')).upper().strip()
    if uf_inf and est_api:
        nome_estado_inf = _normalizar_uf(uf_inf) if uf_inf else ""
        if uf_inf not in est_api and nome_estado_inf not in est_api:
            return False
    return True

def validar_consistencia_municipal(candidato, mun_inf):
    if not mun_inf: 
        return True
    cid_api = unidecode(candidato.get('cidade', '')).upper().strip()
    if not cid_api: 
        return True
    if mun_inf == cid_api or mun_inf in cid_api or cid_api in mun_inf: 
        return True
    if fuzz.token_set_ratio(mun_inf, cid_api, processor=None) >= 95: 
        return True
    return False

def obter_coordenada_centroide_supremo(mun_nome, uf_nome):
    url_arc = f"https://geocode.arcgis.com/arcgis/rest/services/World/GeocodeServer/findAddressCandidates?City={requests.utils.quote(mun_nome)}&Region={requests.utils.quote(uf_nome)}&CountryCode=BRA&f=json&maxLocations=1"
    try:
        r = session.get(url_arc, timeout=5).json()
        if r.get('candidates'):
            cand = r['candidates'][0]
            lat_c, lon_c = float(cand['location']['y']), float(cand['location']['x'])
            if validar_coordenada_brasil(lat_c, lon_c)[0]: 
                return lat_c, lon_c, "ARCGIS_CENTROIDE_SUPREMO"
    except Exception:
        pass
        
    url_nom = f"https://nominatim.openstreetmap.org/search?city={requests.utils.quote(mun_nome)}&state={requests.utils.quote(uf_nome)}&country=Brazil&format=json&limit=1"
    try:
        r = session.get(url_nom, headers={"User-Agent": "RotasCorp/11.0"}, timeout=5).json()
        if r:
            lat_c, lon_c = float(r[0]['lat']), float(r[0]['lon'])
            if validar_coordenada_brasil(lat_c, lon_c)[0]: 
                return lat_c, lon_c, "NOMINATIM_CENTROIDE_SUPREMO"
    except Exception:
        pass
        
    return 0.0, 0.0, None

# ─────────────────────────────────────────────────────────────────────────────
# [BASE-IBGE-CENTROIDE] Resolvedor unificado de centróide municipal + código IBGE
# A API /localidades/municipios do IBGE NÃO traz lat/lon (só o código `id`); por
# isso o centróide é resolvido por cidade+UF via ArcGIS/Nominatim (que devolvem o
# CENTRO da cidade, jamais um POI) e memorizado em RAM. Se um dia a base offline
# passar a ter lat≠0 (ex.: malha IBGE), ela é usada com prioridade. Esta função
# rearma, em produção, o atalho municipal e a blindagem anti-alucinação — que antes
# dependiam de um lat IBGE que nunca existia (ficavam, na prática, desligados).
# ─────────────────────────────────────────────────────────────────────────────
_CENTROIDE_MUN_CACHE = {}

def _info_municipio_ibge(mun_nome, uf_nome):
    """Retorna (item_da_base | None, codigo_ibge | None) do município.
    [IBGE-ROBUSTO - 81ª geração / item #1] CORREÇÃO DA CAUSA RAIZ do 'Cód IBGE: —': antes exigia
    correspondência de UF sempre — se a UF não fosse extraída do endereço (comum em municípios
    remotos), o código vinha vazio mesmo para nomes INEQUÍVOCOS. Agora:
      1) tenta o match exato por UF (desambigua homônimos);
      2) se a UF não casar (ou vier vazia) MAS o nome for ÚNICO na base (1 só município com esse
         nome), devolve esse único item — resolve municípios inequívocos independentemente da UF.
    Homônimos com UF ausente/errada continuam retornando None (não há como desambiguar com segurança)."""
    itens = IBGE_MUNICIPIOS.get(mun_nome)
    if not itens:
        return None, None
    if uf_nome:
        for item in itens:
            if item.get("uf") == uf_nome:
                return item, item.get("codigo_ibge")
    if len(itens) == 1:  # nome inequívoco → não depende da UF
        return itens[0], itens[0].get("codigo_ibge")
    return None, None


def _grau_ambiguidade_homonimos(municipio):
    """[AMBIGUIDADE-HOMONIMOS - 63ª geração / item #3] Grau de ambiguidade de homônimos: em quantas
    UFs DISTINTAS o mesmo nome de município aparece na base IBGE (em memória). Puro e OFFLINE (sem
    rede). A chave da base é normalizada como semantica.normalizar (unidecode+MAIÚSCULAS), então a
    consulta usa a MESMA normalização — coerente com _info_municipio_ibge. Retorna
    {'n_ufs': int, 'ufs': [siglas ordenadas]}. Nome vazio/desconhecido → {'n_ufs': 0, 'ufs': []}."""
    try:
        _mun = semantica.normalizar(municipio) if municipio else ""
    except Exception:
        _mun = ""
    if not _mun or _mun in ("—", "N/A"):
        return {"n_ufs": 0, "ufs": []}
    itens = IBGE_MUNICIPIOS.get(_mun, [])
    ufs = sorted({str(it.get("uf")).upper() for it in itens if it.get("uf")})
    return {"n_ufs": len(ufs), "ufs": ufs}


def _perfil_uf_planilha(ufs_confiaveis):
    """[HOMONIMO - 126ª geração] Constrói o PERFIL DE UF do lote a partir das UFs CONFIÁVEIS (linhas com
    UF explícita ou nome inequívoco). É o sinal de 'contexto da planilha' para desambiguar homônimos sem
    UF. PURO. Retorna {'distribuicao': {uf: frac}, 'dominante': uf|'', 'dominante_frac': float, 'n': int}."""
    _cont = {}
    _tot = 0
    for uf in ufs_confiaveis:
        u = str(uf or "").strip().upper()
        if len(u) == 2 and u.isalpha():
            _cont[u] = _cont.get(u, 0) + 1
            _tot += 1
    if _tot == 0:
        return {"distribuicao": {}, "dominante": "", "dominante_frac": 0.0, "n": 0}
    _dom = max(_cont.items(), key=lambda kv: kv[1])
    return {"distribuicao": {u: round(c / _tot, 4) for u, c in _cont.items()},
            "dominante": _dom[0], "dominante_frac": round(_dom[1] / _tot, 4), "n": _tot}


def _validar_ponto_uf(lat, lon, uf, bboxes=None):
    """[HOMONIMO - 126ª geração] Valida se (lat, lon) cai na bounding box oficial da UF (validação
    espacial). Retorna True/False/None (None quando faltam bbox ou coordenada). PURO. bboxes injetável."""
    if bboxes is None:
        bboxes = BOUNDING_BOXES_UF
    bb = bboxes.get(str(uf or "").strip().upper())
    if not bb:
        return None
    try:
        la, lo = float(lat), float(lon)
    except (TypeError, ValueError):
        return None
    if la == 0 and lo == 0:
        return None
    return (bb["lat_min"] <= la <= bb["lat_max"]) and (bb["lon_min"] <= lo <= bb["lon_max"])


def _desambiguar_municipio_homonimo(nome_norm, uf_explicita="", cod_ibge="", perfil_uf=None,
                                    lat=None, lon=None, base=None, bboxes=None, limiar_contexto=0.6):
    """[HOMONIMO - 126ª geração] Camada de desambiguação de municípios homônimos, 100% OFFLINE (base IBGE
    embutida). Decide o candidato correto por HIERARQUIA DE EVIDÊNCIAS e produz AUDITORIA completa. Ordem:
    (1) código IBGE oficial; (2) UF explícita; (3) nome inequívoco (1 UF); (4) contexto da planilha (UF
    dominante ≥ limiar_contexto) + validação espacial; senão indeterminado (não força — seguro). PURO;
    base/perfil_uf/bboxes injetáveis. Retorna dict de auditoria com 'item' (candidato | None)."""
    if base is None:
        base = IBGE_MUNICIPIOS
    itens = base.get(nome_norm, []) if nome_norm else []
    ufs_cand = sorted({str(it.get("uf")).upper() for it in itens if it.get("uf")})
    n_hom = len(ufs_cand)
    aud = {"homonimo_detectado": n_hom > 1, "n_homonimos": n_hom, "ufs_candidatas": ufs_cand,
           "uf_vencedora": "", "codigo_ibge": "", "metodo": "", "score": 0, "confianca": "",
           "validacao_espacial": None, "risco": "Baixo", "justificativa": "", "item": None}
    if not itens:
        aud.update(metodo="não encontrado", risco="Indefinido",
                   justificativa="Nome não consta na base IBGE offline.")
        return aud

    def _escolher(item, metodo, score, confianca, just):
        aud["item"] = item
        aud["uf_vencedora"] = str(item.get("uf", "")).upper()
        aud["codigo_ibge"] = item.get("codigo_ibge", "")
        aud["metodo"], aud["score"], aud["confianca"] = metodo, score, confianca
        aud["validacao_espacial"] = (_validar_ponto_uf(lat, lon, aud["uf_vencedora"], bboxes)
                                     if (lat is not None and lon is not None) else None)
        _vj = ""
        if aud["validacao_espacial"] is True:
            _vj = " Coordenada confere com a UF."
            aud["risco"] = "Baixo" if confianca == "Alta" else "Médio"
        elif aud["validacao_espacial"] is False:
            _vj = " ⚠️ Coordenada FORA da UF escolhida — possível geocodificação do homônimo errado."
            aud["risco"] = "Alto"
        else:
            aud["risco"] = "Baixo" if confianca == "Alta" else ("Médio" if n_hom > 1 else "Baixo")
        aud["justificativa"] = just + _vj
        return aud

    _cod = str(cod_ibge or "").strip()
    if _cod and _cod not in ("—", "N/A", "0", "None"):
        for it in itens:
            if str(it.get("codigo_ibge")) == _cod:
                return _escolher(it, "código IBGE", 100, "Alta", f"Resolvido pelo código IBGE oficial {_cod}.")
    _ufe = str(uf_explicita or "").strip().upper()
    if _ufe:
        for it in itens:
            if str(it.get("uf")).upper() == _ufe:
                return _escolher(it, "UF explícita", 95 if n_hom > 1 else 90, "Alta",
                                 f"UF informada ({_ufe}) casa com um candidato oficial.")
    if n_hom == 1:
        return _escolher(itens[0], "nome inequívoco", 85, "Alta",
                         "Nome existe em uma única UF na base IBGE — sem ambiguidade.")
    perfil = perfil_uf or {}
    _dom = str(perfil.get("dominante", "") or "").upper()
    _domf = float(perfil.get("dominante_frac", 0.0) or 0.0)
    if _dom and _domf >= limiar_contexto and any(str(it.get("uf")).upper() == _dom for it in itens):
        for it in itens:
            if str(it.get("uf")).upper() == _dom:
                _sc = min(int(round(50 + 40 * _domf)), 88)
                return _escolher(it, "contexto da planilha", _sc, "Média",
                                 f"UF não informada; {int(_domf * 100)}% do lote é {_dom} e “{nome_norm.title()}” "
                                 f"existe em {_dom} — desambiguado por contexto (não oficial).")
    aud.update(metodo="indeterminado", confianca="Baixa", risco="Alto",
               justificativa=(f"Homônimo em {n_hom} UFs ({', '.join(ufs_cand)}) sem UF, sem código e sem "
                              "contexto suficiente — não é seguro desambiguar. Informe a UF ou o código IBGE."))
    return aud


def _enriquecer_desambiguacao_homonimos(df):
    """[HOMONIMO - 126ª geração] Pós-passo (NÃO refatora _montar_dataframe_final): lê o DataFrame já
    montado e ANEXA colunas de auditoria de desambiguação de homônimos, aplicando o motor offline
    (_desambiguar_municipio_homonimo) + o CONTEXTO DA PLANILHA (perfil de UF por endpoint). Aditivo e
    defensivo: em qualquer erro devolve o df intacto. Colunas novas: Homônimo Detectado, UF Desambiguada
    Origem/Destino, Método Desambiguação, Validação Espacial, Risco de Confusão, Confiança Identificação,
    Justificativa Homônimos."""
    try:
        if df is None or len(df) == 0:
            return df
        cols = df.columns
        n = len(df)

        def _perfil_col(nome_col):
            if nome_col not in cols:
                return {}
            _ufs = [u for u in df[nome_col].astype(str).tolist() if len(u.strip()) == 2 and u.strip().isalpha()]
            return _perfil_uf_planilha(_ufs)
        _perf_o, _perf_d = _perfil_col('UF Origem'), _perfil_col('UF Destino')

        def _lst(c, num=False):
            if c not in cols:
                return [None if num else ''] * n
            return (pd.to_numeric(df[c], errors='coerce').tolist() if num else df[c].astype(str).tolist())
        _mo, _md = _lst('Municipio Origem'), _lst('Municipio Destino')
        _ufo, _ufd = _lst('UF Origem'), _lst('UF Destino')
        _codo, _codd = _lst('Cod IBGE Origem'), _lst('Cod IBGE Destino')
        _lao, _loo = _lst('Lat Origem', True), _lst('Lon Origem', True)
        _lad, _lod = _lst('Lat Destino', True), _lst('Lon Destino', True)

        _rank = {"Alto": 3, "Médio": 2, "Baixo": 1, "Indefinido": 0}
        _cr = {"Baixa": 1, "Média": 2, "Alta": 3}
        _cache = {}

        def _norm(x):
            try:
                return semantica.normalizar(x) if x and x.strip().lower() != 'nan' else ""
            except Exception:
                return ""

        def _ufok(u):
            u = str(u).strip().upper()
            return u if (len(u) == 2 and u.isalpha()) else ""

        def _num(v):
            return v if (v is not None and v == v) else None

        def _vtxt(v):
            return "Confere" if v is True else ("Fora" if v is False else "—")

        def _decidir(nome, uf, cod, perfil, lat, lon):
            _k = (nome, uf, str(cod), id(perfil), round(lat, 3) if lat is not None else None,
                  round(lon, 3) if lon is not None else None)
            if _k not in _cache:
                _cache[_k] = _desambiguar_municipio_homonimo(nome, uf, cod, perfil, lat, lon)
            return _cache[_k]

        _amb_idx = _obter_base_ambiguidade()
        c_hom, c_ufo, c_ufd, c_met, c_val, c_risco, c_conf, c_just, c_idx = ([] for _ in range(9))
        for i in range(n):
            _no, _nd = _norm(_mo[i]), _norm(_md[i])
            ao = _decidir(_no, _ufok(_ufo[i]), _codo[i], _perf_o, _num(_lao[i]), _num(_loo[i]))
            ad = _decidir(_nd, _ufok(_ufd[i]), _codd[i], _perf_d, _num(_lad[i]), _num(_lod[i]))
            c_idx.append(max(_amb_idx.get(_no, {}).get("indice", 0), _amb_idx.get(_nd, {}).get("indice", 0)))
            _ho, _hd = ao["homonimo_detectado"], ad["homonimo_detectado"]
            c_hom.append("Ambos" if (_ho and _hd) else ("Origem" if _ho else ("Destino" if _hd else "Não")))
            c_ufo.append(ao["uf_vencedora"] or "—")
            c_ufd.append(ad["uf_vencedora"] or "—")
            c_met.append(f"O: {ao['metodo']} | D: {ad['metodo']}")
            c_val.append(f"O: {_vtxt(ao['validacao_espacial'])} | D: {_vtxt(ad['validacao_espacial'])}")
            _ro = ao["risco"] if _ho else "Baixo"
            _rd = ad["risco"] if _hd else "Baixo"
            c_risco.append(_ro if _rank.get(_ro, 0) >= _rank.get(_rd, 0) else _rd)
            _cs = [c for c in (ao["confianca"], ad["confianca"]) if c in _cr]
            c_conf.append(min(_cs, key=lambda c: _cr[c]) if _cs else "—")
            _js = []
            if _ho:
                _js.append(f"Origem — {ao['justificativa']}")
            if _hd:
                _js.append(f"Destino — {ad['justificativa']}")
            c_just.append("  ||  ".join(_js) if _js else "Sem homônimos.")

        df = df.copy()
        df['Homônimo Detectado'] = c_hom
        df['UF Desambiguada Origem'] = c_ufo
        df['UF Desambiguada Destino'] = c_ufd
        df['Método Desambiguação'] = c_met
        df['Validação Espacial'] = c_val
        df['Risco de Confusão'] = c_risco
        df['Confiança Identificação'] = c_conf
        df['Justificativa Homônimos'] = c_just
        df['Índice de Ambiguidade'] = c_idx
        return df
    except Exception as _e:
        logger.error(f"[HOMONIMO] Falha no enriquecimento de desambiguação: {_e}")
        return df


def _e_prefixo_tokens(a_tokens, b_tokens):
    """[AMBIGUIDADE - 127ª geração] True se a_tokens é prefixo ESTRITO de b_tokens (a mais curto). Captura
    o padrão dominante de ambiguidade toponímica no Brasil: “São Miguel” ⊂ “São Miguel do Araguaia”. PURO."""
    return len(a_tokens) < len(b_tokens) and b_tokens[:len(a_tokens)] == a_tokens


def _indice_ambiguidade(n_homonimos, n_similares_cross, n_similares_total=0):
    """[AMBIGUIDADE - 127ª geração] Índice de Ambiguidade 0-100 (0 = nome exclusivo). Combina homônimos
    EXATOS (mesmo nome em ≥2 UFs, sempre cross-UF) e municípios de nome SEMELHANTE em OUTRA UF (o tipo
    perigoso). Bandas: 0 Exclusivo / ≤20 Baixo / ≤45 Médio / ≤70 Alto / >70 Muito Alto. PURO."""
    idx = 0
    if n_homonimos >= 2:
        idx += 40 + 15 * (n_homonimos - 2)          # 2→40, 3→55, 4→70, ...
    idx += 20 * min(int(n_similares_cross), 3)       # até +60 por semelhantes em outra UF
    if idx == 0 and n_similares_total > 0:
        idx = 15                                      # só semelhante(s) na mesma UF → risco baixo
    return max(0, min(100, idx))


def _risco_ambiguidade(indice):
    """[AMBIGUIDADE - 127ª geração] Rótulo de risco a partir do índice 0-100. PURO."""
    if indice <= 0:
        return "Exclusivo"
    if indice <= 20:
        return "Baixo"
    if indice <= 45:
        return "Médio"
    if indice <= 70:
        return "Alto"
    return "Muito Alto"


def _construir_base_ambiguidade(base_ibge=None, usar_fuzzy=True, limiar_fuzzy=90):
    """[AMBIGUIDADE - 127ª geração] Constrói OFFLINE a Base de Ambiguidade a partir da base IBGE embutida
    (~5,5k municípios). Para cada nome normalizado: grupo de HOMÔNIMOS exatos (mesmo nome em ≥2 UFs) +
    municípios de nome SEMELHANTE (prefixo de token = truncamento/complemento; e near-duplicate por
    rapidfuzz token_set_ratio ≥ limiar, tudo BLOQUEADO por 1º token p/ performance) + Índice de Ambiguidade
    0-100 e risco. PURO/determinístico; base_ibge injetável; sem rede. Retorna {nome_norm: {info}}."""
    if base_ibge is None:
        base_ibge = IBGE_MUNICIPIOS
    nomes = [(nome, tuple(str(nome).split())) for nome in base_ibge.keys() if str(nome).strip()]
    blocos = {}
    for nome, toks in nomes:
        if toks:
            blocos.setdefault(toks[0], []).append((nome, toks))
    _ufs_de = {nome: sorted({str(it.get("uf")).upper() for it in base_ibge.get(nome, []) if it.get("uf")})
               for nome, _ in nomes}
    resultado = {}
    for nome, toks in nomes:
        ufs = _ufs_de.get(nome, [])
        ufs_self = set(ufs)
        n_hom = len(ufs)
        similares = []
        for nome2, toks2 in (blocos.get(toks[0], []) if toks else []):
            if nome2 == nome:
                continue
            tipo, score = None, 0
            if _e_prefixo_tokens(toks, toks2):
                tipo, score = "complemento", 100      # nome2 é a variante mais LONGA (nome ⊂ nome2)
            elif _e_prefixo_tokens(toks2, toks):
                tipo, score = "truncamento", 100       # nome2 é a variante mais CURTA (nome2 ⊂ nome)
            elif usar_fuzzy:
                r = fuzz.token_set_ratio(nome, nome2, processor=None)
                if r >= limiar_fuzzy:
                    tipo, score = "grafia", int(r)
            if tipo:
                ufs2 = _ufs_de.get(nome2, [])
                similares.append({"municipio": nome2, "ufs": ufs2, "tipo": tipo, "score": score})
        n_sim_cross = sum(1 for s in similares if set(s["ufs"]) - ufs_self)
        idx = _indice_ambiguidade(n_hom, n_sim_cross, len(similares))
        resultado[nome] = {"municipio": nome, "itens": base_ibge.get(nome, []), "ufs": ufs,
                           "n_homonimos": n_hom, "similares": similares, "n_similares": len(similares),
                           "n_similares_cross": n_sim_cross, "indice": idx, "risco": _risco_ambiguidade(idx)}
    return resultado


def _estatisticas_ambiguidade(base_amb):
    """[AMBIGUIDADE - 127ª geração] Estatísticas agregadas da Base de Ambiguidade: nº de grupos de
    homônimos, municípios homônimos, grupos com 3+, pares semelhantes, distribuição por UF e por risco, e
    ranking dos mais ambíguos. PURO."""
    grupos_hom, total_hom, grupos_3, pares_sim = 0, 0, 0, 0
    por_uf, por_risco = {}, {}
    for _nome, info in base_amb.items():
        if info["n_homonimos"] >= 2:
            grupos_hom += 1
            total_hom += info["n_homonimos"]
            if info["n_homonimos"] >= 3:
                grupos_3 += 1
            for uf in info["ufs"]:
                por_uf[uf] = por_uf.get(uf, 0) + 1
        pares_sim += info["n_similares"]
        por_risco[info["risco"]] = por_risco.get(info["risco"], 0) + 1
    ranking = sorted(base_amb.values(), key=lambda x: (-x["indice"], -x["n_homonimos"], x["municipio"]))[:50]
    return {"n_grupos_homonimos": grupos_hom, "n_municipios_homonimos": total_hom,
            "n_grupos_3mais": grupos_3, "n_pares_similares": pares_sim // 2,
            "por_uf": dict(sorted(por_uf.items(), key=lambda kv: -kv[1])),
            "por_risco": por_risco,
            "ranking": [(x["municipio"], x["indice"], x["risco"], x["n_homonimos"], x["n_similares"])
                        for x in ranking]}


_BASE_AMBIGUIDADE_CACHE = {}


_DERIV_AMBIGUIDADE_CACHE = {}


def _obter_derivados_ambiguidade():
    """[UI-ESTAVEL - 137ª geração] Singleton dos DERIVADOS da Base de Ambiguidade (estatísticas + os dois
    DataFrames de exportação). CAUSA MEDIDA do travamento/removeChild: o painel da 127ª recalculava isto a
    CADA RERUN — e como st.tabs executa o corpo de TODAS as abas, rodava até quando o usuário apenas
    digitava um endereço no Validador (280 ms de CPU bloqueante por rerun, dos quais 259 ms só nos dois
    XLSX de 521 e 1.690 linhas). Reruns lentos + digitação rápida = deltas sobrepostos = corrida de DOM.
    Agora tudo é calculado UMA VEZ."""
    if not _DERIV_AMBIGUIDADE_CACHE:
        try:
            _amb = _obter_base_ambiguidade()
            _DERIV_AMBIGUIDADE_CACHE["est"] = _estatisticas_ambiguidade(_amb)
            _DERIV_AMBIGUIDADE_CACHE["df_hom"] = _df_homonimos_ambiguidade(_amb)
            _DERIV_AMBIGUIDADE_CACHE["df_sim"] = _df_semelhantes_ambiguidade(_amb)
        except Exception as _e:
            logger.error(f"[AMBIGUIDADE] Falha ao derivar estatísticas/planilhas: {_e}")
    return _DERIV_AMBIGUIDADE_CACHE


def _obter_base_ambiguidade():
    """[AMBIGUIDADE - 127ª geração] Singleton lazy da Base de Ambiguidade (construída 1× sobre a base IBGE
    viva, ~0,3s). Defensivo: em erro devolve {} e a app segue sem o recurso."""
    if not _BASE_AMBIGUIDADE_CACHE:
        try:
            _BASE_AMBIGUIDADE_CACHE.update(_construir_base_ambiguidade(IBGE_MUNICIPIOS))
        except Exception as _e:
            logger.error(f"[AMBIGUIDADE] Falha ao construir a Base de Ambiguidade: {_e}")
    return _BASE_AMBIGUIDADE_CACHE


def _df_homonimos_ambiguidade(base_amb, regioes=None):
    """[AMBIGUIDADE - 127ª geração] DataFrame dos municípios HOMÔNIMOS (1 linha por município do grupo):
    Município, UF, Código IBGE, Região, Qtd Homônimos, Estados Envolvidos, Índice, Risco. PURO."""
    regioes = regioes if regioes is not None else _UF_PARA_REGIAO
    linhas = []
    for nome, info in base_amb.items():
        if info["n_homonimos"] < 2:
            continue
        _estados = ", ".join(info["ufs"])
        for it in info["itens"]:
            _uf = str(it.get("uf", "")).upper()
            linhas.append({"Município": nome.title(), "UF": _uf,
                           "Código IBGE": it.get("codigo_ibge", "") or "",
                           "Região": regioes.get(_uf, "Indefinido"),
                           "Qtd Homônimos": info["n_homonimos"], "Estados Envolvidos": _estados,
                           "Índice de Ambiguidade": info["indice"], "Risco": info["risco"]})
    linhas.sort(key=lambda r: (-r["Qtd Homônimos"], r["Município"], r["UF"]))
    return pd.DataFrame(linhas)


def _df_semelhantes_ambiguidade(base_amb):
    """[AMBIGUIDADE - 127ª geração] DataFrame dos municípios com NOMES SEMELHANTES (1 linha por município
    que tem semelhantes), ordenado do maior potencial de confusão para o menor. PURO."""
    linhas = []
    for nome, info in base_amb.items():
        if not info["similares"]:
            continue
        _sc = [s["score"] for s in info["similares"]]
        _sims = "; ".join(f"{s['municipio'].title()} ({'/'.join(s['ufs'])})" for s in info["similares"][:10])
        linhas.append({"Município": nome.title(), "UF(s)": ", ".join(info["ufs"]) or "—",
                       "Municípios Semelhantes": _sims,
                       "Similaridade Média (%)": round(sum(_sc) / len(_sc), 1) if _sc else 0,
                       "Similaridade Máxima (%)": max(_sc) if _sc else 0,
                       "Qtd Candidatos": len(info["similares"]),
                       "Índice de Ambiguidade": info["indice"], "Risco": info["risco"]})
    linhas.sort(key=lambda r: (-r["Índice de Ambiguidade"], -r["Similaridade Máxima (%)"], r["Município"]))
    return pd.DataFrame(linhas)


def _resolver_identidade_ibge(municipio, endereco_oficial):
    """[IBGE-SINGLESHOT - 59ª geração / item #2] Resolve a identidade municipal oficial para a TELA:
    dict {municipio, uf, cod_ibge} a partir do município já geocodificado + UF extraída do endereço
    oficial — MESMA lógica da planilha (54ª), agora reutilizável no Validador Rápido. Sem rede: só
    consulta a base IBGE em memória. Defensivo: nunca levanta, devolve '—' quando não resolve."""
    _mun = (municipio or "").strip()
    try:
        _uf = extrair_uf_precisa(endereco_oficial or "")
        _uf = "" if _uf == "Indefinido" else _uf
        _item, _cod = _info_municipio_ibge(semantica.normalizar(_mun), _uf) if _mun else (None, None)
        # [IBGE-ROBUSTO - 81ª geração / item #1] se resolveu por nome único, herda a UF OFICIAL do
        # item (mesmo que a extração do endereço tenha falhado) — evita 'UF: —' com Cód IBGE presente.
        _uf_final = _uf or (_item.get("uf") if _item else "")
        return {"municipio": _mun or "—", "uf": _uf_final or "—", "cod_ibge": _cod or "—"}
    except Exception:
        return {"municipio": _mun or "—", "uf": "—", "cod_ibge": "—"}


def _diagnostico_ibge(cod_ibge, municipio, uf):
    """[IBGE-EVERYWHERE - 95ª geração] Quando o Código IBGE NÃO resolve, explica a PROVÁVEL causa em vez
    de deixar o campo apenas vazio (diretriz: jamais um '—' sem justificativa). PURA. Retorna "" quando o
    código está presente (nada a explicar)."""
    _cod = str(cod_ibge or "").strip()
    if _cod and _cod not in ("—", "N/A", "0", "None", ""):
        return ""
    _mun = str(municipio or "").strip()
    _uf = str(uf or "").strip()
    if (not _mun) or _mun in ("—", "N/A", "Não Identificado", "Município Não Mapeado"):
        return ("Código IBGE não resolvido: o **município não foi identificado** na geocodificação "
                "(ponto sub-municipal ou falha de localização). A base IBGE indexa por município.")
    if (not _uf) or _uf in ("—", "N/A"):
        return (f"Código IBGE não resolvido: **UF não identificada** para “{_mun}”. Informe a UF "
                f"(ex.: “{_mun}, SP”) para desambiguar e permitir a resolução oficial.")
    return (f"Código IBGE não resolvido: “{_mun}/{_uf}” **não consta na base IBGE offline** "
            f"(possível grafia divergente). A localização geográfica e a rota não são afetadas.")


def _auditoria_validacao_ibge(texto_usuario, cod_identificado, municipio, uf, fonte):
    """[IBGE-INPUT - 99ª geração] Monta a auditoria 'Validação Oficial pelo Código IBGE' de um ponto:
    compara o código INFORMADO pelo usuário (se digitou um) com o código IDENTIFICADO, e reporta a
    consistência (confirmado / divergência / identificado por geocodificação). PURA. Depende de
    _e_codigo_ibge para detectar se a entrada foi um código."""
    _cod_informado = _e_codigo_ibge(texto_usuario) if "_e_codigo_ibge" in globals() else ""
    _cod_ident = str(cod_identificado or "").strip()
    _cod_ident = "" if _cod_ident in ("—", "N/A", "0", "None", "") else _cod_ident
    _por_codigo = bool(_cod_informado)
    if _por_codigo:
        if _cod_informado == _cod_ident:
            _status, _rev = "✅ Confirmado", "Não"
            _diverg = "Nenhuma — o código informado corresponde ao município identificado."
        elif _cod_ident:
            _status, _rev = "⚠️ Divergência", "Sim"
            _diverg = (f"O código informado ({_cod_informado}) difere do identificado ({_cod_ident}). "
                       f"Correção sugerida: usar {_cod_ident} ({municipio}/{uf}).")
        else:
            _status, _rev = "⚠️ Não confirmado", "Sim"
            _diverg = f"O código informado ({_cod_informado}) não pôde ser confirmado na base oficial."
    else:
        _status, _rev = "ℹ️ Identificado por geocodificação", "Não"
        _diverg = "A entrada não foi um Código IBGE; o código foi obtido pela identificação do município."
    return {
        "entrada_por_codigo": _por_codigo,
        "codigo_informado": _cod_informado or "—", "codigo_identificado": _cod_ident or "—",
        "municipio": municipio or "—", "uf": uf or "—", "fonte": fonte or "—",
        "status": _status, "divergencia": _diverg, "revisao_manual": _rev,
    }


def _centroide_municipio(mun_nome, uf_nome):
    """Centróide oficial do município (lat, lon). Prioriza lat/lon do IBGE offline
    quando existir (>0); senão resolve por cidade+UF (centro da cidade) e memoriza.
    Retorna (0.0, 0.0) apenas se nenhuma fonte responder — preservando o fall-through."""
    chave = (mun_nome, uf_nome)
    if chave in _CENTROIDE_MUN_CACHE:
        return _CENTROIDE_MUN_CACHE[chave]
    item, _cod = _info_municipio_ibge(mun_nome, uf_nome)
    if item and item.get("lat", 0.0) != 0.0 and item.get("lon", 0.0) != 0.0:
        par = (item["lat"], item["lon"])
        _CENTROIDE_MUN_CACHE[chave] = par
        return par
    lat_c, lon_c, _fonte = obter_coordenada_centroide_supremo(mun_nome, uf_nome)
    par = (lat_c, lon_c) if (lat_c != 0.0 and lon_c != 0.0) else (0.0, 0.0)
    _CENTROIDE_MUN_CACHE[chave] = par
    return par

def obedience_base_local(contexto_estruturado):
    if contexto_estruturado["logradouro"] and contexto_estruturado["municipio"] and contexto_estruturado["uf"]:
        chave_cnefe = f"{contexto_estruturado['logradouro']}_{contexto_estruturado['municipio']}_{contexto_estruturado['uf']}"
        if chave_cnefe in cache_base_local:
            return cache_base_local[chave_cnefe]
    return None

# ==============================================================================
# MÓDULOS DE GEOCODIFICAÇÃO COM TELEMETRIA E MOTOR ANTI-COLISÃO
# ==============================================================================
def API_TomTom(query):
    if not TOMTOM_API_KEY: 
        return None
    start_t = time.time()
    try:
        url = f"https://api.tomtom.com/search/2/geocode/{requests.utils.quote(query)}.json?key={TOMTOM_API_KEY}&countrySet=BR&limit=5"
        r = session.get(url, timeout=4).json()
        resultados = []
        if r.get("results"):
            for res in r["results"][:5]:
                pos = res.get("position", {})
                addr = res.get("address", {})
                resultados.append({
                    "lat": float(pos["lat"]), "lon": float(pos["lon"]), "fonte": "TOMTOM", "score_base": 35,
                    "cidade": addr.get("municipality", "").upper(), "estado": addr.get("countrySubdivision", "").upper(),
                    "bairro": addr.get("neighbourhood", addr.get("subdivision", "")).upper(), "logradouro": addr.get("streetName", "").upper(),
                    "numero": str(addr.get("streetNumber", "")).upper(), "cep": addr.get("postalCode", "").replace("-", "")
                })
            registrar_telemetria("TOMTOM", True, time.time() - start_t)
        return resultados if resultados else None
    except Exception: 
        pass
    registrar_telemetria("TOMTOM", False, time.time() - start_t)
    return None

def executar_reverse_geocoding_multimotor(lat, lon):
    rev_key = f"V5_{round(lat,5)}|{round(lon,5)}"
    if rev_key in cache_reverse: 
        return cache_reverse[rev_key]
        
    res = {"logradouro": "", "bairro": "", "cidade": "", "municipio": "", "distrito": "", "estado": "", "cep": ""}
    try:
        def _nom_rev():
            _throttle_nominatim()
            url = f"https://nominatim.openstreetmap.org/reverse?format=json&lat={lat}&lon={lon}&addressdetails=1"
            return session.get(url, headers={"User-Agent": "RotasEnterprise/8.0"}, timeout=4).json()
        r_nom = FILA_NOMINATIM.submit(_nom_rev).result().get("address", {})
        res.update({
            "logradouro": r_nom.get("road", r_nom.get("pedestrian", "")), 
            "bairro": r_nom.get("neighbourhood", r_nom.get("suburb", r_nom.get("city_district", ""))), 
            "cidade": r_nom.get("city", r_nom.get("town", r_nom.get("municipality", ""))), 
            "estado": r_nom.get("state", "").upper(), 
            "cep": r_nom.get("postcode", "")
        })
        cache_reverse.set(rev_key, res, expire=2592000)
        return res
    except Exception: 
        pass
        
    try:
        url_arc = f"https://geocode.arcgis.com/arcgis/rest/services/World/GeocodeServer/reverseGeocode?location={lon},{lat}&f=json"
        r_arc = session.get(url_arc, timeout=4).json()
        if 'address' in r_arc:
            addr = r_arc['address']
            res.update({
                "logradouro": addr.get('Address', ''), 
                "bairro": addr.get('Neighborhood', ''), 
                "cidade": addr.get('City', ''), 
                "estado": addr.get('RegionAbbr', '').upper(), 
                "cep": addr.get('Postal', '')
            })
            cache_reverse.set(rev_key, res, expire=2592000)
    except Exception: 
        pass
        
    return res

def API_ArcGIS(query, ctx=None):
    start_t = time.time()
    try:
        if ctx and (ctx.get("logradouro") or ctx.get("municipio")):
            end = requests.utils.quote(ctx.get("logradouro", ""))
            cid = requests.utils.quote(ctx.get("municipio", ""))
            uf = requests.utils.quote(ctx.get("uf", ""))
            bair = requests.utils.quote(ctx.get("bairro", ""))
            cep = requests.utils.quote(ctx.get("cep", ""))
            url = f"https://geocode.arcgis.com/arcgis/rest/services/World/GeocodeServer/findAddressCandidates?f=json&Address={end}&Neighborhood={bair}&City={cid}&Region={uf}&Postal={cep}&maxLocations=5&sourceCountry=BRA&outFields=*"
        else:
            url = f"https://geocode.arcgis.com/arcgis/rest/services/World/GeocodeServer/findAddressCandidates?f=json&singleLine={requests.utils.quote(query)}&maxLocations=5&sourceCountry=BRA&outFields=*"
            
        r = session.get(url, timeout=4).json()
        resultados = []
        if r.get('candidates'):
            for c in r['candidates'][:5]:
                attr = c.get('attributes', {})
                resultados.append({
                    "lat": float(c['location']['y']), "lon": float(c['location']['x']), "fonte": "ARCGIS", "score_base": 30, 
                    "cidade": attr.get('City', '').upper(), "estado": attr.get('RegionAbbr', '').upper(), 
                    "bairro": attr.get('Neighborhood', '').upper(), "logradouro": attr.get('StName', attr.get('Address', '')).upper(), 
                    "numero": str(attr.get('AddNum', '')).upper(), "cep": attr.get('Postal', '')
                })
            registrar_telemetria("ARCGIS", True, time.time() - start_t)
        return resultados if resultados else None
    except Exception: 
        pass
    registrar_telemetria("ARCGIS", False, time.time() - start_t)
    return None

def API_Nominatim(query, ctx=None):
    start_t = time.time()
    try:
        def _call_nom():
            _throttle_nominatim()
            if ctx and ctx.get("logradouro") and ctx.get("municipio"):
                rua = requests.utils.quote(ctx["logradouro"])
                cid = requests.utils.quote(ctx["municipio"])
                est = requests.utils.quote(ctx.get("uf", ""))
                url = f"https://nominatim.openstreetmap.org/search?format=json&street={rua}&city={cid}&state={est}&limit=5&addressdetails=1&countrycodes=br"
            else:
                url = f"https://nominatim.openstreetmap.org/search?format=json&q={requests.utils.quote(query)}&limit=5&addressdetails=1&countrycodes=br"
            return session.get(url, headers={"User-Agent": "RotasEnterprise/8.0"}, timeout=4).json()
            
        r = FILA_NOMINATIM.submit(_call_nom).result()
        resultados = []
        if r:
            for a in r[:5]:
                addr = a.get("address", {})
                resultados.append({
                    "lat": float(a['lat']), "lon": float(a['lon']), "fonte": "NOMINATIM", "score_base": 25, 
                    "cidade": addr.get('city', addr.get('town', '')).upper(), "estado": addr.get('state', '').upper(), 
                    "bairro": addr.get('neighbourhood', addr.get('suburb', '')).upper(), "logradouro": addr.get('road', '').upper(), 
                    "numero": str(addr.get('house_number', '')).upper(), "cep": addr.get('postcode', '').replace("-", "")
                })
            registrar_telemetria("NOMINATIM", True, time.time() - start_t)
        return resultados if resultados else None
    except Exception: 
        pass
    registrar_telemetria("NOMINATIM", False, time.time() - start_t)
    return None

def API_Photon(query):
    start_t = time.time()
    try:
        url = f"https://photon.komoot.io/api/?q={requests.utils.quote(query)}&limit=5&filter=countrycode:br"
        r = session.get(url, timeout=4).json()
        resultados = []
        if r.get("features"):
            for f in r["features"][:5]:
                lon, lat = f["geometry"]["coordinates"]
                props = f.get("properties", {})
                resultados.append({
                    "lat": lat, "lon": lon, "fonte": "PHOTON", "score_base": 20, 
                    "cidade": props.get("city", "").upper(), "estado": props.get("state", "").upper(), 
                    "bairro": props.get("district", "").upper(), "logradouro": props.get("street", "").upper(), 
                    "numero": str(props.get("housenumber", "")).upper(), "cep": props.get("postcode", "").replace("-", "")
                })
            registrar_telemetria("PHOTON", True, time.time() - start_t)
        return resultados if resultados else None
    except Exception: 
        pass
    registrar_telemetria("PHOTON", False, time.time() - start_t)
    return None

def _pontuar_candidato_estrito(cand, mun_alvo, e_municipio_ibge):
    """[INTEGRIDADE - 128ª geração] Pontuação anti-colisão município↔bairro para o modo estrito. PURO.
    Quando a ENTRADA é um município oficial (e_municipio_ibge=True), o candidato que É esse município
    (cidade == mun_alvo, sem logradouro) recebe bônus alto e vence; um bairro/logradouro homônimo em OUTRA
    cidade NÃO recebe o bônus de especificidade — era a causa de 'barra, ba' cair no bairro da Barra em
    Salvador. Para endereços (e_municipio_ibge=False), mantém o bônus de bairro(+40)/logradouro(+50)."""
    base = cand.get('score_base', 0)
    cidade = str(cand.get('cidade', '') or '').upper().strip()
    bairro = str(cand.get('bairro', '') or '').upper().strip()
    logr = str(cand.get('logradouro', '') or '').upper().strip()
    if e_municipio_ibge and mun_alvo:
        if cidade == mun_alvo and not logr:
            return base + 200
        if cidade and cidade != mun_alvo:
            return base            # colisão: entrada virou entidade sub-municipal em OUTRA cidade
    return base + (40 if bairro else 0) + (50 if logr else 0)


def _candidato_ibge_municipio(mun_alvo, uf_in, base=None):
    """[INTEGRIDADE - 128ª geração] Candidato sintético (âncora oficial) a partir da base IBGE OFFLINE para
    o município da entrada, ou None. Garante que o município correto exista mesmo quando os geocoders de
    nuvem só devolvem um bairro homônimo. PURO; base injetável."""
    if base is None:
        base = IBGE_MUNICIPIOS
    itens = base.get(mun_alvo or "", [])
    it = None
    if uf_in:
        it = next((i for i in itens if str(i.get("uf")).upper() == uf_in), None)
    if it is None and len(itens) == 1:
        it = itens[0]
    if it and it.get("lat") and it.get("lon"):
        return {"lat": it["lat"], "lon": it["lon"], "fonte": "IBGE", "score_base": 30,
                "cidade": mun_alvo, "estado": str(it.get("uf", "")).upper(),
                "bairro": "", "logradouro": "", "numero": "", "cep": ""}
    return None


def _integridade_geografica(dist_viaria_km, dist_reta_km, nivel_origem="", nivel_destino="",
                            mun_origem_pedido="", mun_origem_resolvido="",
                            mun_destino_pedido="", mun_destino_resolvido=""):
    """[INTEGRIDADE - 128ª geração] Índice de Integridade Geográfica (0-100) + diagnósticos. PURO/offline.
    Penaliza: (1) IMPOSSIBILIDADE FÍSICA (viária < reta — a estrada nunca é mais curta que a geodésica);
    (2) COLISÃO DE ENTIDADE (entrada era município, mas resolvida como ponto sub-municipal em OUTRO
    município). Retorna {indice, ok, problemas:[...]}."""
    problemas = []
    idx = 100
    try:
        v, r = float(dist_viaria_km), float(dist_reta_km)
        if v > 0 and r > 0 and v < r * 0.999:
            problemas.append(f"Impossibilidade física: viária {v:.1f} km < linha reta {r:.1f} km "
                             "(a estrada nunca é mais curta que a geodésica) — provável coordenada incorreta.")
            idx -= 60
    except (TypeError, ValueError):
        pass

    def _colisao(lbl, pedido, resolvido, nivel):
        # [INTEGRIDADE - 133ª geração] Regra reforçada: se o usuário pediu um MUNICÍPIO e a app resolveu em
        # OUTRO município, é troca de entidade — independentemente do nível espacial. (Na 128ª eu exigia
        # nivel != município, o que SUPRIMIA o alerta quando o nível vinha vazio.) O nível só enriquece o texto.
        p, rr = str(pedido or "").upper().strip(), str(resolvido or "").upper().strip()
        if p and rr and p != rr:
            _n = str(nivel or "").strip()
            return (f"Colisão de entidade no {lbl}: “{pedido}” (município) foi resolvido em “{resolvido}”"
                    + (f" (nível {_n})" if _n else "")
                    + " — troca indevida do município por outra entidade.")
        return ""
    for _c in (_colisao("origem", mun_origem_pedido, mun_origem_resolvido, nivel_origem),
               _colisao("destino", mun_destino_pedido, mun_destino_resolvido, nivel_destino)):
        if _c:
            problemas.append(_c)
            idx -= 40
    idx = max(0, min(100, idx))
    return {"indice": idx, "ok": len(problemas) == 0, "problemas": problemas}


@st.cache_data(show_spinner=False)
def _montar_planilha_lote_xlsx(df_final):
    """[XLSX-RICO - 184ª geração] Monta o workbook do Lote com MÚLTIPLAS abas estruturadas, em vez de uma aba
    plana: 'Rotas' (dado bruto com cabeçalhos de exame — IDÊNTICA à exportação anterior, p/ compatibilidade),
    'Resumo Executivo' (KPIs), 'Distribuição de Distâncias' (faixas), 'Síntese por UF' e 'Status das Rotas'.
    Cada aba EXTRA só é criada se as colunas existirem; se qualquer extra falhar, a 'Rotas' já foi escrita e o
    arquivo continua válido (defensivo). Retorna bytes."""
    _buf = io.BytesIO()
    with pd.ExcelWriter(_buf, engine='xlsxwriter') as _w:
        _renomear_colunas_exame(df_final).to_excel(_w, index=False, sheet_name="Rotas")
        try:
            _dist = pd.to_numeric(df_final['Distancia'], errors='coerce') if 'Distancia' in df_final.columns else None
            _reta = pd.to_numeric(df_final['Linha Reta'], errors='coerce') if 'Linha Reta' in df_final.columns else None
            _integ = pd.to_numeric(df_final['Integridade Geográfica'], errors='coerce') if 'Integridade Geográfica' in df_final.columns else None
            _res = [("Total de rotas", len(df_final))]
            if _dist is not None:
                _res += [("Distância viária média (km)", round(_dist.mean(), 1)),
                         ("Distância viária total (km)", round(_dist.sum(), 1)),
                         ("Maior deslocamento (km)", round(_dist.max(), 1)),
                         ("Menor deslocamento (km)", round(_dist.min(), 1))]
                if _reta is not None and float(_reta.sum()) > 0:
                    _res.append(("Sinuosidade média (viária/reta)", round(float(_dist.sum()) / float(_reta.sum()), 3)))
            if _integ is not None:
                _res.append(("Integridade geográfica média (0-100)", round(_integ.mean(), 1)))
            if 'Balsas' in df_final.columns:
                _nb = int(df_final['Balsas'].astype(str).str.strip().str.lower().isin(['sim', 'yes', 'true', '1']).sum())
                _res.append(("Rotas que cruzam balsa", _nb))
            pd.DataFrame(_res, columns=["Indicador", "Valor"]).to_excel(_w, index=False, sheet_name="Resumo Executivo")
            if _dist is not None and _dist.notna().any():
                _labs = ["0–50", "50–100", "100–150", "150–200", "200–300", "300–500", "500+"]
                _cat = pd.cut(_dist.dropna(), bins=[0, 50, 100, 150, 200, 300, 500, 10**9], labels=_labs, right=False)
                _cnt = _cat.value_counts().reindex(_labs, fill_value=0)
                _dd = pd.DataFrame({"Faixa (km)": _labs, "Rotas": [int(x) for x in _cnt.values]})
                _dd["% do total"] = (_dd["Rotas"] / max(1, int(_dd["Rotas"].sum())) * 100).round(1)
                _dd.to_excel(_w, index=False, sheet_name="Distribuição de Distâncias")
            if 'UF Origem' in df_final.columns and _dist is not None:
                _g = df_final.assign(_d=_dist).groupby('UF Origem').agg(
                    Rotas=('_d', 'size'), _med=('_d', 'mean'), _max=('_d', 'max'), _tot=('_d', 'sum')
                ).reset_index().sort_values('Rotas', ascending=False)
                for _c in ('_med', '_max', '_tot'):
                    _g[_c] = _g[_c].round(1)
                _g.columns = ['UF', 'Rotas', 'Dist. média (km)', 'Dist. máx (km)', 'Dist. total (km)']
                _g.to_excel(_w, index=False, sheet_name="Síntese por UF")
            if 'Status da Rota' in df_final.columns:
                _s = df_final['Status da Rota'].astype(str).value_counts().reset_index()
                _s.columns = ['Status', 'Rotas']
                _s['% do total'] = (_s['Rotas'] / max(1, int(_s['Rotas'].sum())) * 100).round(1)
                _s.to_excel(_w, index=False, sheet_name="Status das Rotas")
        except Exception:
            logger.error("[XLSX-RICO] Falha nas abas extras do Lote (aba 'Rotas' preservada)", exc_info=True)
    return _buf.getvalue()


def _xlsx_bytes(df, sheet_name="Dados"):
    """[UI-ESTAVEL - 137ª geração] Gera os bytes de um .xlsx UMA ÚNICA VEZ e os memoriza.
    CAUSA RAIZ do removeChild "ao digitar": vários st.download_button recebiam `data=` de um XLSX
    REGERADO a cada rerun. Um XLSX carrega timestamp interno ⇒ os bytes mudam SEMPRE ⇒ o Streamlit
    calcula um novo hash/URL de mídia ⇒ o elemento precisa ser SUBSTITUÍDO no DOM a cada rerun. Como
    st.tabs executa o corpo de TODAS as abas, isso acontecia a cada blur de um text_input — antes de
    qualquer processamento. Com @st.cache_data os bytes ficam IDÊNTICOS entre reruns: zero churn de DOM
    e zero CPU desperdiçada (as bases de ambiguidade tinham 521 + 1.690 linhas por rerun)."""
    _buf = io.BytesIO()
    with pd.ExcelWriter(_buf, engine='xlsxwriter') as _w:
        df.to_excel(_w, index=False, sheet_name=sheet_name)
    return _buf.getvalue()


@st.cache_data(show_spinner=False)
def _xlsx_bytes_2(df1, nome1, df2=None, nome2="Aba2"):
    """[PERF - 139ª geração] Igual a _xlsx_bytes, para planilhas de DUAS abas (a 2ª opcional). Memoiza os
    bytes: sem isto, um XLSX de 2 abas era remontado a cada rerun da aplicação inteira."""
    _buf = io.BytesIO()
    with pd.ExcelWriter(_buf, engine='xlsxwriter') as _w:
        df1.to_excel(_w, index=False, sheet_name=nome1)
        if df2 is not None and len(df2):
            df2.to_excel(_w, index=False, sheet_name=nome2)
    return _buf.getvalue()


def _integridade_de_rota(dist_viaria, dist_reta, texto_origem="", texto_destino="",
                         mun_origem_res="", mun_destino_res="", nivel_origem="", nivel_destino="",
                         base=None, norm=None):
    """[INTEGRIDADE - 133ª geração] Índice de Integridade Geográfica de UMA rota, a partir do que a app já
    tem. Descobre o município PEDIDO no texto do usuário (só quando o texto É um município da base IBGE —
    endereços/POIs não disparam a regra) e compara com o município RESOLVIDO; soma a validação FÍSICA
    (viária ≥ reta). É a forma operacional dos §15/§16/§20 da RFC-001. PURO; base/norm injetáveis."""
    base = IBGE_MUNICIPIOS if base is None else base
    if norm is None:
        def norm(x):
            return semantica.normalizar(x)

    def _pedido(txt):
        try:
            t = norm(txt or "")
        except Exception:
            return ""
        if not t or t.strip().lower() == "nan":
            return ""
        # Remove a UF e a PONTUAÇÃO ("barra, ba" → "BARRA, BA" → "BARRA"): sem isso a vírgula sobrava
        # colada no nome e o município nunca batia na base — a colisão passava despercebida.
        alvo = _RE_UF_SIGLA.sub(" ", t)
        alvo = re.sub(r"[^A-Z0-9 ]", " ", alvo)
        alvo = re.sub(r"\s+", " ", alvo).strip()
        return alvo if base.get(alvo) else ""

    def _res(m):
        try:
            t = norm(m or "")
        except Exception:
            return ""
        return "" if t.strip().lower() in ("", "nan", "nao identificado", "não identificado") else t
    return _integridade_geografica(dist_viaria, dist_reta, nivel_origem, nivel_destino,
                                   _pedido(texto_origem), _res(mun_origem_res),
                                   _pedido(texto_destino), _res(mun_destino_res))


