# ============================================================================
# [COMPARADOR - 138ª geração] Motor de comparação/auditoria contra base externa
# ============================================================================



# ============================================================================
# [COBERTURA - 140ª geração] Planejamento de polos: cobertura + onde abrir
# ============================================================================

def _haversine_matriz(lats, lons):
    """[PLANEJAMENTO - 184ª geração] Matriz N×N de distâncias Haversine (km) entre pontos. Vetorizado (numpy).
    Núcleo do motor de planejamento territorial (catchment/cobertura). Puro."""
    import numpy as np
    _la = np.radians(np.asarray(lats, dtype=float))
    _lo = np.radians(np.asarray(lons, dtype=float))
    _dla = _la[:, None] - _la[None, :]
    _dlo = _lo[:, None] - _lo[None, :]
    _a = np.sin(_dla / 2.0) ** 2 + np.cos(_la)[:, None] * np.cos(_la)[None, :] * np.sin(_dlo / 2.0) ** 2
    return 6371.0088 * 2.0 * np.arcsin(np.sqrt(np.clip(_a, 0.0, 1.0)))


def _catchment_ranking(df, raio_km=100.0):
    """[PLANEJAMENTO - 184ª geração] Para CADA município candidato a sediar prova, quantos municípios e
    candidatos ele cobriria dentro de raio_km (Haversine), + distância média (ponderada por candidatos) e
    máxima na área de influência. Ranqueia por candidatos cobertos. df: colunas
    ['municipio','uf','codigo_ibge','lat','lon','candidatos']. Puro e vetorizado. Retorna DataFrame."""
    import numpy as np
    _cols = ['municipio', 'uf', 'codigo_ibge', 'municipios_cobertos', 'candidatos_cobertos',
             'pct_candidatos', 'dist_media_km', 'dist_max_km']
    if df is None or len(df) == 0:
        return pd.DataFrame(columns=_cols)
    _cand = pd.to_numeric(df['candidatos'], errors='coerce').fillna(0).to_numpy(dtype=float)
    _D = _haversine_matriz(pd.to_numeric(df['lat'], errors='coerce').to_numpy(dtype=float),
                           pd.to_numeric(df['lon'], errors='coerce').to_numpy(dtype=float))
    _mask = _D <= float(raio_km)
    _total = _cand.sum()
    _wmat = _mask * _cand[None, :]
    _wsum = _wmat.sum(axis=1)
    with np.errstate(divide='ignore', invalid='ignore'):
        _dmed = np.where(_wsum > 0, (_D * _wmat).sum(axis=1) / _wsum, 0.0)
    _dmax = np.where(_mask, _D, 0.0).max(axis=1)
    return pd.DataFrame({
        'municipio': df['municipio'].values if 'municipio' in df.columns else '',
        'uf': df['uf'].values if 'uf' in df.columns else '',
        'codigo_ibge': df['codigo_ibge'].values if 'codigo_ibge' in df.columns else '',
        'municipios_cobertos': _mask.sum(axis=1).astype(int),
        'candidatos_cobertos': _wsum.astype(int),
        'pct_candidatos': (100.0 * _wsum / _total).round(1) if _total else 0.0,
        'dist_media_km': np.round(_dmed, 1),
        'dist_max_km': np.round(_dmax, 1),
    }).sort_values('candidatos_cobertos', ascending=False).reset_index(drop=True)


def _cenarios_cobertura_maxima(df, raio_km=100.0, ns=(5, 10, 20, 30, 50, 100)):
    """[PLANEJAMENTO - 184ª geração] Cenários de COBERTURA MÁXIMA (MCLP guloso): para cada N, escolhe
    gulosamente os N municípios que cobrem o MÁXIMO de candidatos AINDA descobertos, dentro de raio_km.
    Retorna (cenarios, escolhidos_por_N, marcos). cenarios: lista de {n, candidatos_cobertos, pct_candidatos,
    municipios_cobertos, pct_municipios, candidatos_descobertos}. marcos: {80/90/95: nº de locais p/ atingir}.
    Puro e vetorizado. Custo ~O(N² · max_n)."""
    import numpy as np
    if df is None or len(df) == 0:
        return [], {}, {}
    _cand = pd.to_numeric(df['candidatos'], errors='coerce').fillna(0).to_numpy(dtype=float)
    _D = _haversine_matriz(pd.to_numeric(df['lat'], errors='coerce').to_numpy(dtype=float),
                           pd.to_numeric(df['lon'], errors='coerce').to_numpy(dtype=float))
    _mask = _D <= float(raio_km)
    _total = _cand.sum()
    _n_mun = len(df)
    _ns = sorted({int(x) for x in ns if int(x) > 0})
    _max_n = min(max(_ns) if _ns else 0, _n_mun)
    _coberto = np.zeros(_n_mun, dtype=bool)
    _sel, _cenarios, _escolhidos, _marcos = [], [], {}, {}
    for _k in range(1, _max_n + 1):
        _ganho = (_mask * (_cand * (~_coberto))[None, :]).sum(axis=1)
        if _sel:
            _ganho[_sel] = -1.0
        _best = int(np.argmax(_ganho))
        if _ganho[_best] <= 0:
            break
        _sel.append(_best)
        _coberto = _coberto | _mask[_best]
        _cc = float(_cand[_coberto].sum())
        _pct = (100.0 * _cc / _total) if _total else 0.0
        for _lim in (80, 90, 95):
            if _lim not in _marcos and _pct >= _lim:
                _marcos[_lim] = _k
        if _k in _ns:
            _escolhidos[_k] = list(_sel)
            _cenarios.append({'n': _k, 'candidatos_cobertos': int(_cc), 'pct_candidatos': round(_pct, 1),
                              'municipios_cobertos': int(_coberto.sum()),
                              'pct_municipios': round(100.0 * _coberto.sum() / _n_mun, 1),
                              'candidatos_descobertos': int(_total - _cc)})
    return _cenarios, _escolhidos, _marcos


def _indices_territoriais(df, marcos=None):
    """[PLANEJAMENTO - 184ª geração] Índices de planejamento territorial, com definições TRANSPARENTES:
    - concentracao (0-100): Gini da demanda entre municípios × 100 (alto = demanda concentrada em poucos).
    - interiorizacao (0-100): % de candidatos FORA dos 10 municípios de maior demanda (alto = espalhado no interior).
    - capilaridade_80pct: nº de locais (do cenário guloso) p/ cobrir 80% dos candidatos (menos = mais concentrado).
    Heurísticos e documentados; puros. Retorna dict."""
    import numpy as np
    if df is None or len(df) == 0:
        return {'concentracao': 0.0, 'interiorizacao': 0.0, 'capilaridade_80pct': None,
                'total_candidatos': 0, 'total_municipios': 0}
    _cand = pd.to_numeric(df['candidatos'], errors='coerce').fillna(0).to_numpy(dtype=float)
    _total = float(_cand.sum())
    _n = len(df)
    _s = np.sort(_cand)
    if _total > 0 and _n > 1:
        _idx = np.arange(1, _n + 1)
        _gini = (2.0 * float((_idx * _s).sum()) / (_n * float(_s.sum()))) - (_n + 1.0) / _n
    else:
        _gini = 0.0
    _top = float(np.sort(_cand)[::-1][:10].sum())
    return {'concentracao': round(max(0.0, min(1.0, _gini)) * 100, 1),
            'interiorizacao': round(100.0 * (_total - _top) / _total, 1) if _total else 0.0,
            'capilaridade_80pct': (marcos or {}).get(80),
            'total_candidatos': int(_total), 'total_municipios': int(_n)}


def _detectar_coluna(colunas, palavras_chave):
    """[PLANEJAMENTO - 184ª geração] Detecta a 1ª coluna cujo nome (normalizado) contém alguma palavra-chave.
    Retorna o nome da coluna ou None. Puro."""
    _norm = {c: unidecode(str(c)).lower().strip() for c in colunas}
    for _p in palavras_chave:
        for _c in colunas:
            if _p in _norm[_c]:
                return _c
    return None


def _planejamento_resolver_entrada(df_bruto, col_muni, col_cand, col_uf=None):
    """[PLANEJAMENTO - 184ª geração] Resolve a planilha de entrada do planejamento em um DataFrame com
    coordenadas OFICIAIS, OFFLINE (base IBGE embarcada — sem rede): cada linha vira
    (codigo_ibge, municipio, uf, lat, lon, candidatos). col_muni aceita nome de município (± UF) OU Código
    IBGE. Agrega candidatos por município. Homônimo sem UF, não encontrado, ou sem coordenada → não resolvido
    (contado). Reusa a base corrigida (curada + sede oficial + geometria). Puro. Retorna (df, n_nao_resolvidos)."""
    _idx = _indice_ibge_por_codigo()
    _linhas, _nao = {}, 0
    for _, _row in df_bruto.iterrows():
        _mv = str(_row.get(col_muni, "") if _row.get(col_muni) is not None else "").strip()
        _cv = pd.to_numeric(_row.get(col_cand), errors='coerce')
        _cv = 0.0 if pd.isna(_cv) else float(_cv)
        if not _mv or _mv.lower() == "nan":
            _nao += 1
            continue
        _uf = str(_row.get(col_uf, "")).strip().upper() if col_uf else ""
        _cod, _info = None, None
        _digs = re.sub(r"\D", "", _mv)
        if len(_digs) == 7 and _digs in _idx:
            _cod, _info = _digs, _idx[_digs]
        else:
            _ent = IBGE_MUNICIPIOS.get(semantica.normalizar(_mv))
            _e = None
            if _ent:
                if len(_ent) == 1:
                    _e = _ent[0]
                elif _uf:
                    _e = next((x for x in _ent if str(x.get("uf", "")).upper() == _uf), None)
            if _e:
                _cod = str(_e.get("codigo_ibge") or "").strip()
                _info = {"municipio": _e.get("municipio", ""), "uf": _e.get("uf", ""),
                         "lat": _e.get("lat", 0.0), "lon": _e.get("lon", 0.0)}
        if _cod and _info and (_info.get("lat") or _info.get("lon")):
            if _cod not in _linhas:
                _linhas[_cod] = {"codigo_ibge": _cod, "municipio": _info.get("municipio", ""),
                                 "uf": _info.get("uf", ""), "lat": _info.get("lat"),
                                 "lon": _info.get("lon"), "candidatos": 0.0}
            _linhas[_cod]["candidatos"] += _cv
        else:
            _nao += 1
    return pd.DataFrame(list(_linhas.values())), _nao


def _curva_cobertura(distancias, pesos=None, faixas=(50, 100, 150, 200, 300, 500)):
    """[COBERTURA - 140ª geração] Curva de cobertura: percentual de CANDIDATOS (ponderado por inscritos)
    que fica dentro de cada faixa de distância do seu local de prova. É a pergunta central do planejamento
    de exames — não "qual a distância média", mas "quantos candidatos estão longe demais". PURO."""
    _d = [x for x in distancias]
    _p = list(pesos) if pesos is not None else [1.0] * len(_d)
    _pares = [(float(d), float(p)) for d, p in zip(_d, _p)
              if d is not None and d == d and p is not None and p == p and float(d) >= 0]
    _tot = sum(p for _, p in _pares)
    if not _pares or _tot <= 0:
        return {"faixas": {}, "total": 0, "mediana": None, "p90": None, "media": None, "max": None}
    _ord = sorted(_pares)
    _acum, _mediana, _p90 = 0.0, None, None
    for d, p in _ord:
        _acum += p
        if _mediana is None and _acum >= _tot * 0.5:
            _mediana = d
        if _p90 is None and _acum >= _tot * 0.9:
            _p90 = d
    _curva = {}
    for f in faixas:
        _dentro = sum(p for d, p in _pares if d <= f)
        _curva[f] = round(100.0 * _dentro / _tot, 1)
    return {"faixas": _curva, "total": int(_tot), "mediana": round(_mediana, 1) if _mediana else None,
            "p90": round(_p90, 1) if _p90 else None,
            "media": round(sum(d * p for d, p in _pares) / _tot, 1),
            "max": round(max(d for d, _ in _pares), 1)}


def _acessibilidade_critica(municipios, limiar_km=200.0):
    """[COBERTURA - 140ª geração] Municípios cujos candidatos percorrem MAIS que o limiar até o local de
    prova, ordenados por IMPACTO (inscritos × km) — não por distância pura: 3.000 candidatos a 210 km doem
    muito mais que 20 candidatos a 400 km. PURO."""
    _out = []
    for m in (municipios or []):
        try:
            _d = float(m.get("dist_atual_km"))
        except (TypeError, ValueError):
            continue
        if _d <= limiar_km:
            continue
        _i = float(m.get("inscritos") or 0)
        _out.append({**m, "impacto_km_candidato": round(_d * _i, 1)})
    _out.sort(key=lambda x: -x["impacto_km_candidato"])
    return _out


def _simular_abertura_polos(municipios, n_polos=5, max_candidatos=300, dist_min_km=30.0,
                            polos_existentes=None, matriz_fn=None,
                            objetivo="eficiencia", limiar_equidade_km=200.0):
    """[COBERTURA - 140ª geração] SIMULADOR DE ABERTURA DE POLOS (facility location guloso). Responde à
    pergunta que o gestor de fato faz: **onde abrir o próximo local de prova?**

    Para cada município candidato a receber um polo, calcula o GANHO MARGINAL — quantos km-candidato seriam
    poupados se ele abrisse, considerando que só migram para lá os municípios que ficariam MAIS PERTO. Elege
    o de maior ganho, ATUALIZA as distâncias dos beneficiados e repete (guloso: cada polo é escolhido
    sabendo dos anteriores). É a aproximação clássica do problema p-median/cobertura máxima.

    ⚠️ LIMITE HONESTO: usa distância GEODÉSICA (linha reta), não viária — é uma ferramenta de TRIAGEM. Ela
    diz QUAIS municípios investigar como polo; a decisão final exige rotear os finalistas de verdade (o
    motor multicritério faz isso).

    ⚠️ EFICIÊNCIA × EQUIDADE — agora é UMA ESCOLHA SUA, não um efeito colateral [154ª geração]:
      • objetivo="eficiencia" (padrão): maximiza os km-candidato TOTAIS poupados. Privilegia CLUSTERS
        DENSOS — abre polos onde há muita gente. Municípios isolados com poucos candidatos podem seguir
        mal atendidos. A matemática está certa; a política pública pode não estar.
      • objetivo="equidade": conta o ganho APENAS para os municípios que HOJE estão acima do limiar crítico
        (padrão 200 km). Ou seja, só valoriza polos que ajudam QUEM ESTÁ PIOR. Um polo que economiza
        1 milhão de km-candidato entre gente que já estava a 40 km vale ZERO neste modo.
    Na 140ª eu NOMEEI essa tensão e disse "a decisão é sua" — mas não te dei a ferramenta para decidir.
    Agora dei. As duas respostas são legítimas; elas respondem a perguntas DIFERENTES.

    DISTÂNCIA MÍNIMA: sem essa restrição o guloso sugeria polos a 12 km um do outro (matematicamente ótimo,
    operacionalmente absurdo). Candidatos a menos de `dist_min_km` de um polo já existente ou já escolhido
    são descartados.

    MEMÓRIA: uma matriz M×M nacional (5.571²) seriam ~248 MB e estouraria o alvo de 1 GB. Por isso os
    CANDIDATOS a polo são limitados aos de pior acessibilidade (impacto = inscritos × km) — que é justamente
    onde um polo faz diferença. Matriz M×K (~13 MB). PURO; matriz_fn injetável."""
    import numpy as np
    matriz_fn = matriz_fn or _haversine_matriz
    _m = [x for x in (municipios or [])
          if x.get("lat") is not None and x.get("lon") is not None and x.get("dist_atual_km") is not None]
    if len(_m) < 2 or n_polos < 1:
        return []
    _lat = [float(x["lat"]) for x in _m]
    _lon = [float(x["lon"]) for x in _m]
    _ins = np.array([float(x.get("inscritos") or 0) for x in _m], dtype=float)
    _dist = np.array([float(x["dist_atual_km"]) for x in _m], dtype=float)

    # candidatos a polo: os de maior IMPACTO (inscritos × km atual) — cap de memória e de bom senso
    _impacto = _ins * _dist
    _k = min(int(max_candidatos), len(_m))
    _cand_idx = list(np.argsort(-_impacto)[:_k])
    _D = matriz_fn(_lat, _lon, [_lat[i] for i in _cand_idx], [_lon[i] for i in _cand_idx])  # (M, K)

    # coordenadas dos polos JÁ existentes (para não sugerir um polo colado num que já opera)
    _pex = [(float(a), float(b)) for a, b in (polos_existentes or [])
            if a is not None and b is not None]
    _bloq = set()
    if _pex and dist_min_km > 0:
        _Dex = matriz_fn([_lat[i] for i in _cand_idx], [_lon[i] for i in _cand_idx],
                         [p[0] for p in _pex], [p[1] for p in _pex])       # (K, P)
        for _c in range(len(_cand_idx)):
            if float(_Dex[_c].min()) < dist_min_km:
                _bloq.add(_cand_idx[_c])

    # [EQUIDADE - 154ª geração] máscara do objetivo: em "equidade", só contam os que HOJE estão mal servidos.
    _eq = str(objetivo).lower().startswith("equi")
    _peso_obj = (_ins * (_dist > float(limiar_equidade_km))) if _eq else _ins
    if _eq and float(_peso_obj.sum()) <= 0:
        return []                    # ninguém acima do limiar: nada a fazer em modo equidade

    _resultado = []
    _dist_atual = _dist.copy()
    _usados = set()
    _escolhidos_ll = []
    for _rodada in range(int(n_polos)):
        _melhor, _ganho_max, _mask_best = None, 0.0, None
        for _c in range(len(_cand_idx)):
            _im = _cand_idx[_c]
            if _im in _usados or _im in _bloq:
                continue
            # não abre um polo colado num que acabamos de escolher
            if dist_min_km > 0 and _escolhidos_ll:
                _dm = matriz_fn([_lat[_im]], [_lon[_im]],
                                [e[0] for e in _escolhidos_ll], [e[1] for e in _escolhidos_ll])
                if float(_dm.min()) < dist_min_km:
                    continue
            _reducao = np.maximum(0.0, _dist_atual - _D[:, _c])   # só migra quem fica MAIS PERTO
            _ganho = float((_reducao * _peso_obj).sum())           # o OBJETIVO decide o que conta
            if _ganho > _ganho_max:
                _melhor, _ganho_max, _mask_best = _c, _ganho, _reducao
        if _melhor is None or _ganho_max <= 0:
            break
        _i_mun = _cand_idx[_melhor]
        _usados.add(_i_mun)
        _escolhidos_ll.append((_lat[_i_mun], _lon[_i_mun]))
        _benef = _mask_best > 0.01
        _n_mun = int(_benef.sum())
        _n_cand = int(_ins[_benef].sum())
        _antes = float((_dist_atual[_benef] * _ins[_benef]).sum() / _ins[_benef].sum()) if _n_cand else 0.0
        _dist_atual = np.minimum(_dist_atual, _D[:, _melhor])     # abre o polo
        _depois = float((_dist_atual[_benef] * _ins[_benef]).sum() / _ins[_benef].sum()) if _n_cand else 0.0
        _resultado.append({
            "objetivo": "equidade" if _eq else "eficiencia",
            "ordem": _rodada + 1,
            "polo": _m[_i_mun].get("nome"),
            "uf": _m[_i_mun].get("uf", ""),
            "lat": _lat[_i_mun], "lon": _lon[_i_mun],
            "ganho_km_candidato": round(_ganho_max, 1),
            "municipios_beneficiados": _n_mun,
            "candidatos_beneficiados": _n_cand,
            "dist_media_antes_km": round(_antes, 1),
            "dist_media_depois_km": round(_depois, 1),
            "reducao_media_km": round(_antes - _depois, 1),
        })
    return _resultado






def _alocar_com_capacidade(municipios, capacidades, permitir_sem_vaga=True):
    """[CAPACIDADE - 152ª geração] ALOCAÇÃO COM RESTRIÇÃO DE CAPACIDADE — o método de Vogel (arrependimento).

    O BURACO QUE ISTO FECHA: até aqui a plataforma REPORTAVA a carga de cada polo ("Rio Verde receberia
    47.000 candidatos") mas NÃO A RESTRINGIA. Se Rio Verde só cabe 5.000, o plano é FICÇÃO — não há sala,
    não há carteira, não há fiscal. Uma alocação que não sobrevive ao contato com a realidade não é um plano;
    é um desenho.

    E é AQUI que os inscritos finalmente MUDAM A DECISÃO. Na 141ª eu expliquei por que eles não mudavam:
    a escolha era feita município a município, e o nº de inscritos era uma constante que se cancelava. Com
    CAPACIDADE, os municípios COMPETEM por vaga — e quem tem mais candidatos consome mais vaga. A decisão
    passa a depender deles.

    POR QUE VOGEL, E NÃO GULOSO INGÊNUO:
      O guloso atende primeiro o par (município, polo) de MENOR CUSTO. Isso é uma armadilha: ele enche o
      melhor polo com quem tinha boas alternativas, e deixa encalhado quem NÃO tinha nenhuma.
      Vogel usa o ARREPENDIMENTO: quanto um município PERDE se não conseguir seu melhor polo
      (custo do 2º melhor − custo do melhor). Atende primeiro quem tem MAIS A PERDER.
      Exemplo real do teste: guloso = 2.040.000 km-candidato; Vogel = 140.000. **14,6× melhor.**

    PREÇO DA RESTRIÇÃO: devolve o custo IDEAL (sem capacidade) e o REAL (com), para o gestor ver
    exatamente quanto a limitação de infraestrutura está custando aos candidatos — em km-candidato.

    LIMITE HONESTO: um município vai INTEIRO para um polo (não é dividido). Um município com mais candidatos
    que a capacidade de QUALQUER polo não tem onde caber, e isso é reportado explicitamente.

    municipios: [{'nome', 'uf', 'inscritos', 'custos': {polo: custo_km}}]
    capacidades: {polo: nº de candidatos que cabem}
    PURO."""
    _muns = [m for m in (municipios or []) if m.get("custos")]
    _cap = {str(k): float(v) for k, v in (capacidades or {}).items() if v and float(v) > 0}
    _total_cand = sum(float(m.get("inscritos") or 0) for m in _muns)
    _total_cap = sum(_cap.values())

    _out = {"alocacao": {}, "deslocados": [], "sem_vaga": [], "ocupacao": {},
            "custo_ideal_km_cand": 0.0, "custo_real_km_cand": 0.0, "preco_da_restricao_km_cand": 0.0,
            "total_candidatos": int(_total_cand), "total_capacidade": int(_total_cap),
            "viavel": _total_cap >= _total_cand, "n_deslocados": 0, "candidatos_deslocados": 0}
    if not _muns or not _cap:
        return _out

    # custo IDEAL: cada município no seu melhor polo, ignorando capacidade
    for m in _muns:
        _b = min(m["custos"].items(), key=lambda kv: kv[1])
        _out["custo_ideal_km_cand"] += _b[1] * float(m.get("inscritos") or 0)

    # [PERF - 153ª geração] HEAP COM INVALIDAÇÃO PREGUIÇOSA. A versão da 152ª recalculava o arrependimento
    # de TODOS os municípios pendentes a cada iteração — O(n²·k). Medido em escala nacional (5.571 × 300):
    # **44,5 SEGUNDOS**. Aqui, como só UMA capacidade muda por iteração, o arrependimento de quase todo mundo
    # continua válido. Guardamos num heap e só RECALCULAMOS quem foi realmente afetado (o polo que escolheu
    # encheu). O resultado é IDÊNTICO — é a mesma ordem de Vogel, calculada de forma esperta.
    import heapq
    _restante = dict(_cap)
    _pend = {id(m): m for m in _muns}

    def _regret_de(m):
        _ins = float(m.get("inscritos") or 0)
        _viaveis = sorted((c, p) for p, c in m["custos"].items()
                          if p in _restante and _restante[p] >= max(_ins, 1))
        if not _viaveis:
            return None, None, None
        _c1, _p1 = _viaveis[0]
        _c2 = _viaveis[1][0] if len(_viaveis) > 1 else _c1 * 3.0   # sem alternativa ⇒ regret alto
        return (_c2 - _c1) * max(_ins, 1), _p1, _c1

    _heap = []
    _seq = 0
    for m in _muns:
        _rg, _p1, _ = _regret_de(m)
        if _rg is None:
            _pend.pop(id(m), None)
            _out["sem_vaga"].append({"municipio": m.get("nome"), "uf": m.get("uf", ""),
                                     "inscritos": int(float(m.get("inscritos") or 0)),
                                     "motivo": "Nenhum polo com vaga suficiente."})
            continue
        heapq.heappush(_heap, (-_rg, _seq, id(m), _p1))
        _seq += 1

    while _heap:
        _neg, _, _mid, _p_cache = heapq.heappop(_heap)
        m = _pend.get(_mid)
        if m is None:
            continue                                   # já alocado (entrada obsoleta no heap)
        _ins = float(m.get("inscritos") or 0)
        # revalida: o polo escolhido ainda cabe?
        if _restante.get(_p_cache, 0) < max(_ins, 1):
            _rg, _p1, _ = _regret_de(m)
            if _rg is None:
                _pend.pop(_mid, None)
                _out["sem_vaga"].append({"municipio": m.get("nome"), "uf": m.get("uf", ""),
                                         "inscritos": int(_ins),
                                         "motivo": "Nenhum polo com vaga suficiente."})
                continue
            heapq.heappush(_heap, (-_rg, _seq, _mid, _p1))
            _seq += 1
            continue
        _melhor_m, _melhor_polo = m, _p_cache
        _pend.pop(_mid, None)
        _out["alocacao"][_melhor_m["nome"]] = _melhor_polo
        _restante[_melhor_polo] -= max(_ins, 1)
        _custo_real = _melhor_m["custos"][_melhor_polo]
        _out["custo_real_km_cand"] += _custo_real * _ins
        _ideal_polo, _custo_ideal = min(_melhor_m["custos"].items(), key=lambda kv: kv[1])
        if _ideal_polo != _melhor_polo:
            _out["deslocados"].append({
                "municipio": _melhor_m["nome"], "uf": _melhor_m.get("uf", ""),
                "inscritos": int(_ins),
                "polo_ideal": _ideal_polo, "custo_ideal_km": round(_custo_ideal, 1),
                "polo_real": _melhor_polo, "custo_real_km": round(_custo_real, 1),
                "km_a_mais": round(_custo_real - _custo_ideal, 1),
                "impacto_km_candidato": round((_custo_real - _custo_ideal) * _ins, 1),
                "motivo": f"O polo ideal ({_ideal_polo}) estava LOTADO."})
            _out["n_deslocados"] += 1
            _out["candidatos_deslocados"] += int(_ins)

    for _p, _c in _cap.items():
        _usado = _c - _restante.get(_p, _c)
        _out["ocupacao"][_p] = {"capacidade": int(_c), "usado": int(_usado),
                                "livre": int(_c - _usado),
                                "pct": round(100.0 * _usado / _c, 1) if _c else 0.0}
    _out["custo_ideal_km_cand"] = round(_out["custo_ideal_km_cand"], 1)
    _out["custo_real_km_cand"] = round(_out["custo_real_km_cand"], 1)
    _out["preco_da_restricao_km_cand"] = round(_out["custo_real_km_cand"] - _out["custo_ideal_km_cand"], 1)
    _out["deslocados"].sort(key=lambda d: -d["impacto_km_candidato"])
    return _out




def _contingencia_polos(municipios, capacidades, top=15):
    """[CONTINGENCIA - 154ª geração] ANÁLISE DE CONTINGÊNCIA: **e se um polo cair?**

    Escola alagada, greve, interdição, problema estrutural — isso ACONTECE, e às vezes a duas semanas da
    prova. Até aqui a plataforma não sabia responder: quais municípios ficam órfãos? para onde vão? a
    capacidade restante absorve? quanto custa aos candidatos?

    Para CADA polo, simula sua queda: remove-o, REALOCA tudo com Vogel respeitando a capacidade dos
    sobreviventes, e mede o estrago. Devolve o RANKING DE CRITICIDADE — porque a pergunta que importa não é
    "o que acontece se o polo X cair", é **"QUAL polo eu não posso perder"**.

    Isso muda a operação: o gestor sabe onde colocar reserva técnica, vistoria prioritária e plano B —
    em vez de espalhar recurso por igual sobre 300 polos, sendo que a queda da maioria custaria quase nada.

    Retorna lista ordenada por criticidade, cada item com: candidatos que dependem do polo, municípios
    realocados, km-candidato a mais, quantos ficariam SEM VAGA (o cenário vermelho) e se o plano seguiria
    viável. PURO."""
    _base = _alocar_com_capacidade(municipios, capacidades)
    _custo_base = _base["custo_real_km_cand"]
    _out = []
    for _polo in list(capacidades.keys()):
        _caps_sem = {p: c for p, c in capacidades.items() if p != _polo}
        _dependem = [m for m in municipios if _base["alocacao"].get(m["nome"]) == _polo]
        _cand_dep = int(sum(float(m.get("inscritos") or 0) for m in _dependem))
        if not _caps_sem:
            _out.append({"polo": _polo, "candidatos_que_dependem": _cand_dep,
                         "municipios_que_dependem": len(_dependem), "viavel_sem_ele": False,
                         "candidatos_sem_vaga": _cand_dep, "municipios_realocados": 0,
                         "km_candidato_a_mais": 0.0, "criticidade": float("inf")})
            continue
        _sem = _alocar_com_capacidade(municipios, _caps_sem)
        _realoc = sum(1 for m in municipios
                      if _base["alocacao"].get(m["nome"]) and
                      _sem["alocacao"].get(m["nome"]) != _base["alocacao"].get(m["nome"]))
        _sv = int(sum(x["inscritos"] for x in _sem["sem_vaga"]))
        _dano = round(_sem["custo_real_km_cand"] - _custo_base, 1)
        # criticidade: o dano em km-candidato + uma penalidade PESADA por candidato sem vaga.
        # Um candidato sem lugar para fazer a prova é incomparavelmente pior que km a mais — não é
        # "mais deslocamento", é a prova NÃO ACONTECER para ele.
        _crit = _dano + _sv * 10000.0
        _out.append({"polo": _polo, "candidatos_que_dependem": _cand_dep,
                     "municipios_que_dependem": len(_dependem),
                     "viavel_sem_ele": _sem["viavel"] and _sv == 0,
                     "candidatos_sem_vaga": _sv,
                     "municipios_realocados": _realoc,
                     "km_candidato_a_mais": _dano,
                     "criticidade": round(_crit, 1)})
    _out.sort(key=lambda x: -x["criticidade"])
    return _out[:top]




