def _portao_de_exibicao(chave='df_processado'):
    """[PORTÃO-EXIBIÇÃO - 181ª geração] O PORTÃO NA FRONTEIRA DE **EXIBIÇÃO**, não só na de produção.

    ── POR QUE ISTO EXISTE (e é a lição mais dura desta série) ──
    Eu coloquei o portão na PRODUÇÃO do DataFrame (176ª). Consertei o crash dele (180ª). E o usuário
    **continuou vendo 958 zeros**. Eu não conseguia distinguir, do meu lado, entre:
      (a) o portão não roda,
      (b) o portão roda e falha,
      (c) o usuário está rodando uma versão antiga.
    **Essa impossibilidade de distinguir é uma falha de PROJETO minha** — o portão era uma caixa-preta.

    ── A CURA: DEFESA EM PROFUNDIDADE ──
    Este portão roda na **FRONTEIRA DE EXIBIÇÃO** — toda vez que o `df_processado` vai ser MOSTRADO ou
    COMPARADO. Ele é **IDEMPOTENTE** (se o df já está limpo, custa ~0 e não faz nada) e **NÃO DEPENDE do
    caminho que produziu o DataFrame**. Não importa se veio do Lote, da Alocação, de uma versão antiga
    ainda em `session_state`, ou de um caminho que eu ainda vou escrever: **se há um zero impossível ali,
    ele é corrigido ANTES de qualquer olho humano vê-lo.**

    É a diferença entre "conserto o produtor" (e sempre sobra um produtor) e "**limpo na porta**".
    PURO em relação ao session_state (grava o df corrigido de volta)."""
    try:
        _df = st.session_state.get(chave)
        if _df is None or not hasattr(_df, "columns") or len(_df) == 0:
            return None
        _viol = _verificar_invariante_zero(_df)
        if not _viol:
            return {"linhas_zero": 0, "recuperadas": 0, "irrecuperaveis": [], "ok": True,
                    "ja_limpo": True}
        logger.warning(f"[PORTÃO-EXIBIÇÃO] {len(_viol)} zero(s) impossível(is) chegaram à EXIBIÇÃO. "
                       "O portão de produção não os pegou — ou este DataFrame veio de outro caminho. "
                       "Corrigindo AGORA, na porta.")
        _limpo, _rel = _portao_final_distancias(_df)
        st.session_state[chave] = _limpo
        st.session_state['portao_exibicao_relatorio'] = _rel
        return _rel
    except Exception as _e:
        logger.error(f"[PORTÃO-EXIBIÇÃO] Falha: {_e}")
        return {"linhas_zero": -1, "recuperadas": 0, "irrecuperaveis": [], "ok": False,
                "crash": f"{type(_e).__name__}: {_e}"}


def _escrever_seguro(df, idx, col, valor):
    """[PORTÃO - 180ª geração] Escreve numa célula RESPEITANDO o dtype da coluna.

    ── POR QUE ISTO EXISTE (e é a causa raiz de 958 zeros) ──
    `df.at[i, col] = valor` parece a coisa mais inocente do mundo. Mas o **pandas 3.x é ESTRITO com
    dtype**: escrever um `int` numa coluna `str` levanta
        `Invalid value '1100023' for dtype 'str'`
    E o código IBGE chega como int em alguns caminhos da base.

    Resultado: o PORTÃO FINAL — a função que eu criei justamente para GARANTIR que o zero não voltasse —
    **crashava na primeira linha**, o try/except engolia a exceção, e ele devolvia o **DataFrame SUJO**.
    **O guardião era exatamente o que deixava o bug passar.**

    Aqui a escrita CONVERTE o valor para o tipo da coluna. Se a coluna resistir, converte a COLUNA para
    object e escreve — nunca desiste, e nunca deixa a exceção derrubar o portão inteiro."""
    try:
        if col not in df.columns:
            return False
        _dt = str(df[col].dtype)
        if valor is None:
            if "float" in _dt or "int" in _dt:
                df.at[idx, col] = float("nan")
            else:
                df[col] = df[col].astype(object)
                df.at[idx, col] = None
            return True
        if _dt in ("object", "str", "string") or "str" in _dt:
            df.at[idx, col] = str(valor)
        elif "float" in _dt:
            df.at[idx, col] = float(valor)
        elif "int" in _dt:
            df[col] = df[col].astype(float)      # a geodésica é fracionária
            df.at[idx, col] = float(valor)
        else:
            df.at[idx, col] = valor
        return True
    except Exception:
        # último recurso: a coluna vira object e aceita qualquer coisa. NUNCA deixamos a escrita
        # derrubar o portão — foi exatamente isso que causou os 958 zeros.
        try:
            df[col] = df[col].astype(object)
            df.at[idx, col] = valor
            return True
        except Exception as _e2:
            logger.error(f"[PORTÃO] Nem com object consegui escrever em '{col}': {_e2}")
            return False


def _portao_final_distancias(df, col_dist="Distancia", col_o="Origem", col_d="Destino"):
    """[PORTÃO - 176ª geração] A GARANTIA ESTRUTURAL: nenhum ZERO IMPOSSÍVEL sai do pipeline.

    ── POR QUE UM "CONSERTO" NÃO ERA SUFICIENTE ──
    Nas gerações 162, 168 e 169 eu consertei os caminhos que geravam zero — e **na 168ª eu declarei
    resolvido um bug que ainda estava lá**, porque consertei o caminho ERRADO. Aprendi a lição: um conserto
    que não foi VERIFICADO no lugar onde o bug ocorre não é conserto, é esperança.
    A resposta certa não é consertar MAIS caminhos. É construir um **PORTÃO que NENHUMA linha atravessa sem
    ser examinada** — independentemente de por qual caminho ela veio, inclusive por caminhos que ainda não
    existem.

    ── A LEI FÍSICA QUE TORNA ISSO POSSÍVEL ──
    **Dois municípios DIFERENTES não podem estar a 0,0 km de distância.** Isso não é convenção nem
    heurística: é geometria. Se `Origem ≠ Destino` e `Distância = 0`, **é bug — sempre, sem exceção**.
    (E o contrário também importa: `Distância = 0` com `Origem == Destino` é PERFEITAMENTE VÁLIDO — o
    candidato faz prova na própria cidade. Confundir os dois casos foi o pecado original: usar zero como
    SENTINELA DE ERRO num campo onde zero é um valor legítimo.)

    ── O QUE O PORTÃO FAZ, EM ORDEM ──
      1. Encontra toda linha com **zero impossível** (origem ≠ destino, distância ≤ 0).
      2. **TENTA RESGATAR** cada uma: resolve as duas pontas pela base oficial do IBGE (offline, O(1)) e
         calcula a **geodésica de Karney** — que é o PISO FÍSICO e sempre existe se as coordenadas existem.
      3. As que resgatou, **CORRIGE** — com a fonte marcada como geodésica (nunca disfarçada de viária).
      4. As que NÃO conseguiu, marca com o **MOTIVO EXPLÍCITO** — nunca mais um zero mudo.
      5. **RELATA** ao usuário: quantas tinham zero, quantas foram recuperadas, quantas restaram e POR QUÊ.

    Devolve (df_corrigido, relatorio). PURO (não muta o df de entrada)."""
    _rel = {"linhas_zero": 0, "recuperadas": 0, "irrecuperaveis": [], "ok": True}
    try:
        if df is None or len(df) == 0 or col_dist not in df.columns:
            return df, _rel
        _d = df.copy()
        _dist = pd.to_numeric(_d[col_dist], errors="coerce")

        _o = _d[col_o].astype(str).str.strip() if col_o in _d.columns else pd.Series([""] * len(_d))
        _dd = _d[col_d].astype(str).str.strip() if col_d in _d.columns else pd.Series([""] * len(_d))
        # ⚠️ ARMADILHA QUE O MEU PRÓPRIO TESTE PEGOU: quando o pipeline falha, ele grava "Erro" em
        # AMBOS os municípios. Comparar "Erro" == "Erro" faria o portão concluir que são a MESMA
        # cidade — e PULAR exatamente as linhas que ele existe para pegar. O sentinela de falha
        # estava disfarçando o bug do próprio detector.
        # CURA: quando o município identificado é um SENTINELA, use o TEXTO CRU da entrada.
        def _limpo(_serie_mun, _serie_txt):
            _m = _serie_mun.astype(str).str.strip()
            _ruim = _m.str.lower().isin(_SENTINELAS_FALHA) | (_m.str.len() == 0)
            return _m.where(~_ruim, _serie_txt.astype(str).str.strip())

        _mun_o = _limpo(_d["Municipio Origem"], _o) if "Municipio Origem" in _d.columns else _o
        _mun_d = _limpo(_d["Municipio Destino"], _dd) if "Municipio Destino" in _d.columns else _dd

        # a mesma cidade? (agora comparando identidades REAIS, nunca sentinelas)
        _mesma = (_mun_o.str.upper() == _mun_d.str.upper()) & (_mun_o.str.len() > 0)
        _zero_impossivel = (_dist.isna() | (_dist <= 0)) & (~_mesma)
        _idx = _d.index[_zero_impossivel].tolist()
        _rel["linhas_zero"] = len(_idx)
        if not _idx:
            return _d, _rel

        logger.warning(f"[PORTÃO] {len(_idx)} linha(s) com ZERO IMPOSSÍVEL (origem ≠ destino, "
                       "distância ≤ 0). Tentando resgate pela base oficial do IBGE...")

        # ═══════════════════════════════════════════════════════════════════════════════════
        # 🔴 O SEGUNDO BUG (Tailândia → Belém): o portão só tentava o TEXTO da coluna.
        #
        # "Belém" é HOMÔNIMO — existem TRÊS (PA, PB, AL). O resgate CORRETAMENTE se recusa a chutar
        # (chutar errado seria pior que falhar). Resultado: a linha ficava irrecuperável.
        #
        # **MAS O CÓDIGO IBGE DO DESTINO ESTAVA NA PRÓPRIA LINHA** (`Cod IBGE Destino` = 1501402), e o
        # portão simplesmente **NÃO OLHAVA PARA ELE**. É o MESMO pecado do bug original: a informação
        # estava ali, ao alcance da mão, e a app não usou.
        #
        # Agora o portão usa TODAS as pistas da linha, na ordem de autoridade:
        #   1. Código IBGE da coluna própria  (INQUESTIONÁVEL — desempata homônimo)
        #   2. Município identificado + UF     (oficial)
        #   3. Texto cru da entrada + UF       (desambigua "Belém" → "Belém, PA")
        #   4. Texto cru sozinho               (só se for nome único no país)
        # ═══════════════════════════════════════════════════════════════════════════════════
        def _resgatar_com_pistas(_i, _c_txt, _c_cod, _c_mun, _c_uf):
            """Tenta TODAS as pistas da linha, do mais forte ao mais fraco."""
            _tentativas = []
            # 1. o CÓDIGO IBGE da coluna própria — a autoridade máxima
            if _c_cod in _d.columns:
                _cd = str(_d.at[_i, _c_cod] or "").strip()
                if _cd and _cd.lower() not in ("nan", "none", ""):
                    _tentativas.append(_cd)
            # 2. município identificado + UF
            _uf = ""
            if _c_uf in _d.columns:
                _uf = str(_d.at[_i, _c_uf] or "").strip().upper()
            if _c_mun in _d.columns:
                _mn = str(_d.at[_i, _c_mun] or "").strip()
                if _mn and _mn.lower() not in _SENTINELAS_FALHA:
                    _tentativas.append(f"{_mn}, {_uf}" if len(_uf) == 2 else _mn)
            # 3. texto cru + UF (desambigua homônimo: "Belém" → "Belém, PA")
            _tx = str(_d.at[_i, _c_txt] or "").strip() if _c_txt in _d.columns else ""
            if _tx:
                if len(_uf) == 2:
                    _tentativas.append(f"{_tx}, {_uf}")
                _tentativas.append(_tx)          # 4. texto sozinho (só se for nome único)
            for _t in _tentativas:
                _r = _resgatar_coordenadas_oficiais(_t)
                if _r:
                    return _r
            return None

        for _i in _idx:
            _txt_o = str(_d.at[_i, col_o]) if col_o in _d.columns else ""
            _txt_d = str(_d.at[_i, col_d]) if col_d in _d.columns else ""
            _rg_o = _resgatar_com_pistas(_i, col_o, "Cod IBGE Origem", "Municipio Origem", "UF Origem")
            _rg_d = _resgatar_com_pistas(_i, col_d, "Cod IBGE Destino", "Municipio Destino", "UF Destino")
            if not (_rg_o and _rg_d):
                _falta = []
                if not _rg_o:
                    _falta.append(f"origem (`{_txt_o}`)")
                if not _rg_d:
                    _falta.append(f"destino (`{_txt_d}`)")
                _rel["irrecuperaveis"].append({
                    "linha": int(_i) + 2,   # +2 = cabeçalho + base 1 (como o Excel mostra)
                    "origem": _txt_o, "destino": _txt_d,
                    "motivo": ("Nem a nuvem nem a BASE OFICIAL do IBGE reconheceram: "
                               + " e ".join(_falta) +
                               ". Provavelmente não é um município brasileiro — confira a grafia."),
                })
                # NUNCA um zero mudo: marca o motivo na própria linha
                _escrever_seguro(_d, _i, "Status da Rota",
                                 "⛔ NÃO RECUPERÁVEL (município não reconhecido)")
                _escrever_seguro(_d, _i, col_dist, None)   # None, não 0 — zero é valor VÁLIDO
                continue

            _lat_o, _lon_o, _m_o, _u_o, _c_o, _met_o = _rg_o
            _lat_d, _lon_d, _m_d, _u_d, _c_d, _met_d = _rg_d
            try:
                _geo, _st = calcular_distancia_linha_reta(
                    _lat_o, _lon_o, _lat_d, _lon_d, contexto=f"PORTÃO FINAL: {_txt_o} → {_txt_d}")
            except Exception as _e_g:
                logger.error(f"[PORTÃO] Falha geodésica na linha {_i}: {_e_g}")
                _geo = 0.0
            if not _geo or _geo <= 0:
                _rel["irrecuperaveis"].append({
                    "linha": int(_i) + 2, "origem": _txt_o, "destino": _txt_d,
                    "motivo": "Municípios reconhecidos, mas a geodésica não pôde ser calculada "
                              "(coordenadas oficiais ausentes na base).",
                })
                _escrever_seguro(_d, _i, col_dist, None)
                continue

            # ✅ RESGATADA — escrita SEGURA POR TIPO.
            #
            # 🔴 O BUG QUE ISTO CORRIGE (e ele DERRUBAVA O PORTÃO INTEIRO):
            # `_d.at[_i, _c] = _v` parece inocente. Mas o pandas 3.x é ESTRITO com dtype: escrever um
            # INT numa coluna `str` levanta `Invalid value '1100023' for dtype 'str'`. E o código do
            # IBGE vem como int em alguns caminhos da base.
            # Resultado: o portão CRASHAVA na PRIMEIRA linha, o try/except engolia, e ele devolvia o
            # **DataFrame SUJO** — com todos os zeros intactos. **O portão que eu criei para GARANTIR
            # que o zero não voltasse era exatamente o que o deixava passar.**
            # E o meu teste da 176ª não pegou porque o DataFrame de teste **não tinha a coluna
            # 'Cod IBGE Origem'** — a escrita que crasha nunca acontecia. **Meu teste não refletia a
            # realidade.** Corrigido nos dois lados: a escrita E o teste.
            _escrever_seguro(_d, _i, col_dist, round(float(_geo), 2))
            for _c, _v in (("Linha Reta", round(float(_geo), 2)),
                           ("Municipio Origem", _m_o), ("Municipio Destino", _m_d),
                           ("Lat Origem", _lat_o), ("Lon Origem", _lon_o),
                           ("Lat Destino", _lat_d), ("Lon Destino", _lon_d),
                           ("Cod IBGE Origem", _c_o), ("Cod IBGE Destino", _c_d),
                           ("Fonte Rota", "Geodésica de Karney (PORTÃO FINAL — rota indisponível)"),
                           ("Status da Rota", "🛟 RECUPERADA no portão final (geodésica oficial)"),
                           ("Modo/Acesso", "📐 Geodésica (rota rodoviária indisponível)")):
                _escrever_seguro(_d, _i, _c, _v)
            _rel["recuperadas"] += 1
            logger.warning(f"[PORTÃO] Linha {_i} RECUPERADA: {_m_o}/{_u_o} → {_m_d}/{_u_d} = "
                           f"{_geo:.2f} km (geodésica). Via {_met_o} / {_met_d}.")

        _rel["ok"] = not _rel["irrecuperaveis"]
        return _d, _rel
    except Exception as _e:
        # 🔴 O PORTÃO NUNCA MAIS FALHA EM SILÊNCIO.
        # Antes: logava e devolvia o df SUJO. O usuário via os zeros e não fazia ideia de que a
        # GARANTIA tinha morrido no caminho. **Um guardião que falha calado é pior que guardião
        # nenhum** — ele cria a ILUSÃO de proteção.
        # Agora o relatório carrega o CRASH, e a UI o mostra em vermelho.
        import traceback as _tb
        _rel["ok"] = False
        _rel["crash"] = f"{type(_e).__name__}: {_e}"
        _rel["stack"] = _tb.format_exc()[-900:]
        logger.error(f"[PORTÃO] 🔴 O PORTÃO FALHOU — os zeros NÃO foram corrigidos: {_e}")
        return df, _rel


def _verificar_invariante_zero(df, col_dist="Distancia", col_o="Origem", col_d="Destino"):
    """[PORTÃO - 176ª geração] O INVARIANTE, verificado. Devolve as linhas que VIOLAM a lei física:
    origem ≠ destino E distância ≤ 0. Se o portão fez o trabalho, esta lista vem VAZIA — e uma lista vazia
    é a única prova aceitável de que o bug não voltou. PURA."""
    try:
        if df is None or len(df) == 0 or col_dist not in df.columns:
            return []
        _dist = pd.to_numeric(df[col_dist], errors="coerce")
        # mesma armadilha do portão: "Erro" == "Erro" NÃO significa "mesma cidade"
        def _id(_c_mun, _c_txt):
            _t = df[_c_txt].astype(str).str.strip()
            if _c_mun not in df.columns:
                return _t.str.upper()
            _m = df[_c_mun].astype(str).str.strip()
            _ruim = _m.str.lower().isin(_SENTINELAS_FALHA) | (_m.str.len() == 0)
            return _m.where(~_ruim, _t).str.upper()

        _mo = _id("Municipio Origem", col_o)
        _md = _id("Municipio Destino", col_d)
        _mesma = (_mo == _md) & (_mo.str.len() > 0)
        # ZERO explícito (não None) com municípios diferentes = violação da lei física
        _viol = (_dist.notna()) & (_dist <= 0) & (~_mesma)
        return df.index[_viol].tolist()
    except Exception as _e:
        logger.error(f"[PORTÃO] Falha ao verificar o invariante: {_e}")
        return []


def _humanizar_identificadores(df):
    """[HUMANIZAR - 173ª geração] O CÓDIGO IBGE SAI DA COLUNA "Origem". O NOME DO MUNICÍPIO ENTRA.

    ── O PROBLEMA ──
    Quando o usuário processa por Código IBGE, a planilha final mostra **"1100023"** na coluna Origem.
    Nos gráficos: "1100023". Nos rankings: "1100023". No relatório executivo: "1100023".
    **Ninguém consegue analisar assim.** Um gestor abre o estudo e vê uma parede de números de 7 dígitos.
    O código é um IDENTIFICADOR DE MÁQUINA; o nome é o identificador de GENTE.

    ── POR QUE ISSO NÃO FOI CORRIGIDO ANTES (e por que agora dá) ──
    A 146ª ADICIONAVA "Origem (Identificada)" mas **NUNCA reescrevia "Origem"** — e com razão: o código
    INTERNO usa 'Origem' como CHAVE (conciliação, mapas de MCDA, joins). Reescrevê-la no meio do pipeline
    quebraria tudo.
    A solução é a mesma arquitetura da 134ª: **traduzir na FRONTEIRA DE APRESENTAÇÃO.** O DataFrame interno
    segue com o que tem; só a EXIBIÇÃO e a EXPORTAÇÃO trocam o código pelo nome. E o código NÃO se perde:
    ele vai para a coluna própria (Cod IBGE Origem), onde ele pertence.

    ── LIMITE HONESTO (acentuação) ──
    A base embarcada NÃO tem acentos (MELGACO, não Melgaço). Por isso a função **PREFERE o nome que o
    PIPELINE identificou** — que vem ACENTUADO das APIs de geocodificação — e só cai na base oficial quando
    o pipeline falhou naquela linha. Na prática: rota OK ⇒ nome acentuado; rota falhou ⇒ nome sem acento,
    mas **correto e presente** (que é infinitamente melhor que "1100023" ou "Erro").
    Se você me passar a lista oficial ACENTUADA do IBGE, eu a embarco e o problema some.

    Idempotente: se 'Origem' já é um nome, não mexe. PURO (não muta o df de entrada)."""
    try:
        if df is None or len(df) == 0:
            return df
        _d = df.copy()
        for _c_txt, _c_mun, _c_cod in (("Origem", "Municipio Origem", "Cod IBGE Origem"),
                                       ("Destino", "Municipio Destino", "Cod IBGE Destino")):
            if _c_txt not in _d.columns:
                continue
            _vals = _d[_c_txt].astype(str)
            _mask = _vals.map(lambda v: bool(_e_codigo_ibge(v)))
            if not _mask.any():
                continue

            # 1) preserva o código na coluna PRÓPRIA (nunca se perde)
            _codigos = _vals.map(lambda v: _e_codigo_ibge(v) or "")
            if _c_cod not in _d.columns:
                _d[_c_cod] = ""
            _atual = _d[_c_cod].astype(str).str.strip()
            _d[_c_cod] = _atual.where(_atual.str.len() > 0, _codigos)

            # 2) o NOME entra no lugar do código — preferindo o que o pipeline já identificou,
            #    e caindo na base oficial se preciso (nunca fica sem nome)
            def _nome(_v):
                _cod = _e_codigo_ibge(_v)
                if not _cod:
                    return None
                _it = _indice_ibge_por_codigo().get(_cod)
                if not _it:
                    return None
                return _titulo_municipio(_it["municipio"])

            _da_base = _vals.map(_nome)
            if _c_mun in _d.columns:
                _do_pipe = _d[_c_mun].astype(str).str.strip()
                _bom = _do_pipe.str.len().gt(0) & ~_do_pipe.str.lower().isin(
                    ["erro", "n/a", "nan", "none", "não identificado", "nao identificado"])
                _nomes = _do_pipe.where(_bom, _da_base)
            else:
                _nomes = _da_base
            _d[_c_txt] = _nomes.where(_mask & _nomes.notna(), _d[_c_txt])
        return _d
    except Exception as _e:
        logger.error(f"[HUMANIZAR] Falha ao humanizar identificadores: {_e}")
        return df


def _enriquecer_rotulos_ibge(df):
    """[IBGE-ROTULO - 146ª geração] Pós-passo ADITIVO: quando a entrada foi um Código IBGE, (a) ANEXA as
    colunas legíveis 'Origem (Identificada)'/'Destino (Identificado)' — "5300108 — Brasília/DF" — e
    (b) RETROALIMENTA 'Municipio Origem'/'UF Origem'/'Cod IBGE Origem' (e o destino) caso estejam vazias.

    NÃO reescreve 'Origem'/'Destino': elas são CHAVES INTERNAS (os mapas dest_to_hub, topk_map, alo_mcda e
    a conciliação do Comparador são indexados por elas). Reescrevê-las quebraria a Alocação inteira — é a
    mesma separação modelo-interno × apresentação da 134ª. Defensivo: em erro devolve o df intacto."""
    try:
        if df is None or len(df) == 0:
            return df
        _idx = _indice_ibge_por_codigo()
        _cols, _n = df.columns, len(df)

        def _lst(c):
            return df[c].astype(str).tolist() if c in _cols else [''] * _n
        _to, _td = _lst('Origem'), _lst('Destino')
        _mo, _md = _lst('Municipio Origem'), _lst('Municipio Destino')
        _uo, _ud = _lst('UF Origem'), _lst('UF Destino')
        _co, _cd = _lst('Cod IBGE Origem'), _lst('Cod IBGE Destino')
        _vazio = ("", "nan", "none", "n/a", "—", "-", "não identificado")

        def _proc(txts, muns, ufs, cods):
            _rot, _m2, _u2, _c2 = [], list(muns), list(ufs), list(cods)
            for i, t in enumerate(txts):
                _rot.append(_rotular_ibge(t, _idx))
                _cod = _e_codigo_ibge(str(t).strip())
                if not _cod:
                    continue
                _it = _idx.get(_cod)
                if not _it:
                    continue
                if str(_m2[i]).strip().lower() in _vazio:
                    _m2[i] = _titulo_municipio(_it["municipio"])
                if str(_u2[i]).strip().lower() in _vazio:
                    _u2[i] = _it["uf"]
                if str(_c2[i]).strip().lower() in _vazio:
                    _c2[i] = _cod
            return _rot, _m2, _u2, _c2
        _ro, _mo2, _uo2, _co2 = _proc(_to, _mo, _uo, _co)
        _rd, _md2, _ud2, _cd2 = _proc(_td, _md, _ud, _cd)

        df = df.copy()
        df['Origem (Identificada)'] = _ro
        df['Destino (Identificado)'] = _rd
        for _c, _v in [('Municipio Origem', _mo2), ('UF Origem', _uo2), ('Cod IBGE Origem', _co2),
                       ('Municipio Destino', _md2), ('UF Destino', _ud2), ('Cod IBGE Destino', _cd2)]:
            if _c in _cols:
                df[_c] = _v
        return df
    except Exception as _e:
        logger.error(f"[IBGE-ROTULO] Falha ao enriquecer rótulos: {_e}")
        return df


def _chave_mun(nome, uf=""):
    """[COMPARADOR - 138ª geração] Chave canônica de município para conciliação: nome normalizado (sem
    acento/pontuação) + UF quando houver. PURO."""
    try:
        t = semantica.normalizar(nome or "")
    except Exception:
        t = str(nome or "").upper()
    t = re.sub(r"[^A-Z0-9 ]", " ", t)
    t = re.sub(r"\s+", " ", t).strip()
    u = str(uf or "").strip().upper()
    u = u if (len(u) == 2 and u.isalpha()) else ""
    return f"{t}|{u}" if u else t




def _validar_planilha_comparativa(df_ref, mapa, base_ibge=None, idx_ibge=None):
    """[CMP-VALID - 149ª geração] PRÉ-VOO DO COMPARADOR: audita a planilha de referência ANTES de processar.
    Barrar lixo na entrada é mais barato que descobrir depois — e MUITO mais barato que produzir um
    relatório executivo confiante em cima de dado podre.

    Retorna {bloqueantes, avisos, info, nota (0-100), pode_processar}. Cada achado traz TIPO, SEVERIDADE,
    quantas linhas, um EXEMPLO real e COMO CORRIGIR. PURO; bases injetáveis.

    NOTA DE DOMÍNIO (que um validador genérico erraria): **origem == destino NÃO é erro aqui.** Em logística
    comercial seria bug; no planejamento de exames é o MELHOR cenário possível — o candidato faz a prova no
    próprio município, deslocamento zero. Marcamos como INFO e contamos, porque é um indicador de qualidade
    da distribuição, não um defeito."""
    base_ibge = IBGE_MUNICIPIOS if base_ibge is None else base_ibge
    idx_ibge = _indice_ibge_por_codigo() if idx_ibge is None else idx_ibge
    _bloq, _avi, _inf = [], [], []

    def _add(lista, tipo, n, exemplo, msg, correcao):
        lista.append({"tipo": tipo, "linhas": int(n), "exemplo": str(exemplo)[:60],
                      "mensagem": msg, "correcao": correcao})

    if df_ref is None or len(df_ref) == 0:
        _add(_bloq, "Planilha vazia", 0, "—", "A planilha não tem nenhuma linha.",
             "Verifique se salvou o arquivo com os dados.")
        return {"bloqueantes": _bloq, "avisos": [], "info": [], "nota": 0, "pode_processar": False}

    _n = len(df_ref)
    _cols = list(df_ref.columns)

    # ---------- 1. COLUNAS ----------
    _obrig = {"origem": "Município de origem do candidato", "destino": "Local de aplicação da prova",
              "distancia": "Distância viária (km)"}
    for _k, _desc in _obrig.items():
        if not mapa.get(_k) or mapa[_k] not in _cols:
            _add(_bloq, "Coluna obrigatória não mapeada", _n, _desc,
                 f"A coluna **{_desc}** não foi selecionada — sem ela não há o que comparar.",
                 "Mapeie a coluna no seletor acima. Se ela não existe na planilha, adicione-a.")
    _dups = [c for c in _cols if _cols.count(c) > 1]
    if _dups:
        _add(_avi, "Colunas duplicadas", len(set(_dups)), ", ".join(sorted(set(_dups))[:3]),
             f"A planilha tem **{len(set(_dups))} nome(s) de coluna repetidos** — o pandas renomeia e você "
             "pode acabar mapeando a errada.",
             "Renomeie as colunas duplicadas na planilha de origem.")
    if _bloq:
        return {"bloqueantes": _bloq, "avisos": _avi, "info": _inf, "nota": 0, "pode_processar": False}

    _c_o, _c_d, _c_dist = mapa["origem"], mapa["destino"], mapa["distancia"]
    _c_ib, _c_uf, _c_in = mapa.get("ibge_origem"), mapa.get("uf_origem"), mapa.get("inscritos")

    # ---------- 2. LINHAS VAZIAS ----------
    _vazias = int(df_ref[_c_o].isna().sum() + (df_ref[_c_o].astype(str).str.strip() == "").sum())
    if _vazias:
        _add(_bloq if _vazias > _n * 0.5 else _avi, "Origem vazia", _vazias, "(célula em branco)",
             f"**{_vazias} linha(s)** sem município de origem — elas ficam FORA de todas as estatísticas.",
             "Preencha ou remova essas linhas antes de subir.")

    # ---------- 3. DISTÂNCIA: tipo e sanidade ----------
    _d = pd.to_numeric(df_ref[_c_dist], errors="coerce")
    _nan = int(_d.isna().sum())
    if _nan:
        _ex = df_ref.loc[_d.isna(), _c_dist].astype(str).iloc[0] if _nan else ""
        _add(_bloq if _nan == _n else _avi, "Distância não numérica", _nan, _ex,
             f"**{_nan} linha(s)** com distância que não é número (ex.: `{_ex}`). Elas não entram na comparação.",
             "Remova o texto (\"km\", vírgula decimal, espaços) e formate a coluna como NÚMERO. "
             "Se a planilha usa vírgula decimal, salve como CSV com ponto ou formate como número no Excel.")
    _neg = int((_d < 0).sum())
    if _neg:
        _add(_avi, "Distância negativa", _neg, f"{_d[_d < 0].iloc[0]:.1f}",
             f"**{_neg} linha(s)** com distância NEGATIVA — impossível.",
             "Verifique se a coluna não é uma diferença em vez de uma distância.")
    _zero = int((_d == 0).sum())
    if _zero:
        _add(_inf, "Distância zero", _zero, "0",
             f"**{_zero} linha(s)** com distância zero — o candidato faz a prova no PRÓPRIO município. "
             "Isso não é erro: é o melhor cenário possível.",
             "Nada a corrigir. É um indicador de boa distribuição.")
    _abs = int((_d > 3000).sum())
    if _abs:
        _add(_avi, "Distância implausível", _abs, f"{_d[_d > 3000].max():.0f} km",
             f"**{_abs} linha(s)** com mais de 3.000 km. O Brasil tem ~4.300 km de norte a sul — é possível, "
             "mas raro. Pode ser município mal identificado.",
             "Confira essas linhas. Se a origem é homônima (ex.: 'São Domingos'), informe a UF.")

    # ---------- 4. ORIGEM == DESTINO (não é erro — é o IDEAL) ----------
    try:
        _ig = int((df_ref[_c_o].astype(str).str.strip().str.upper()
                   == df_ref[_c_d].astype(str).str.strip().str.upper()).sum())
        if _ig:
            _add(_inf, "Origem igual ao destino", _ig, "—",
                 f"**{_ig} município(s)** aplicam a prova em si mesmos — deslocamento ZERO para esses candidatos. "
                 "Em logística comercial isso seria bug; aqui é o **melhor resultado possível**.",
                 "Nada a corrigir.")
    except Exception:
        pass

    # ---------- 5. LINHAS DUPLICADAS (inflam a ponderação!) ----------
    try:
        _dup = int(df_ref.duplicated(subset=[_c_o]).sum())
        if _dup:
            _ex = df_ref.loc[df_ref.duplicated(subset=[_c_o]), _c_o].astype(str).iloc[0]
            _add(_avi, "Município de origem repetido", _dup, _ex,
                 f"**{_dup} linha(s)** repetem um município de origem (ex.: `{_ex}`). A conciliação usa a "
                 "PRIMEIRA — as demais são ignoradas, e os inscritos delas NÃO entram no cômputo.",
                 "Consolide as linhas repetidas (some os inscritos) antes de subir.")
    except Exception:
        pass

    # ---------- 6. CÓDIGO IBGE ----------
    if _c_ib and _c_ib in _cols:
        _ruins, _ex_ruim = 0, ""
        _seis = 0
        for _v in df_ref[_c_ib].astype(str):
            _s = "".join(c for c in _v if c.isdigit())
            if not _s:
                continue
            if len(_s) == 6:
                _seis += 1
                if not _ex_ruim:
                    _ex_ruim = _v
            elif len(_s) != 7 or _s not in idx_ibge:
                _ruins += 1
                if not _ex_ruim:
                    _ex_ruim = _v
        if _seis:
            _add(_avi, "Código IBGE com 6 dígitos", _seis, _ex_ruim,
                 f"**{_seis} código(s)** com 6 dígitos — o Excel **comeu o zero à esquerda**. É a causa nº 1 "
                 "de código IBGE quebrado no Brasil.",
                 "Formate a coluna como **TEXTO** no Excel ANTES de digitar/colar, e recoloque o zero. "
                 "A conciliação vai cair para município+UF nessas linhas (menos confiável).")
        if _ruins:
            _add(_avi, "Código IBGE inexistente", _ruins, _ex_ruim,
                 f"**{_ruins} código(s)** de 7 dígitos que NÃO existem na base oficial do IBGE.",
                 "Provável dígito trocado, ou município extinto/incorporado. Confira. "
                 "A conciliação cai para município+UF nessas linhas.")

    # ---------- 7. MUNICÍPIO INEXISTENTE / HOMÔNIMO SEM UF ----------
    _inex, _hom_sem_uf, _ex_i, _ex_h = 0, 0, "", ""
    _tem_uf = bool(_c_uf and _c_uf in _cols)
    for _i, _v in enumerate(df_ref[_c_o].astype(str)):
        _t = _chave_mun(_v).split("|")[0]
        if not _t:
            continue
        _its = base_ibge.get(_t)
        if not _its:
            _inex += 1
            if not _ex_i:
                _ex_i = _v
            continue
        _ufs = {str(i.get("uf")).upper() for i in _its}
        if len(_ufs) > 1 and not _tem_uf:
            _hom_sem_uf += 1
            if not _ex_h:
                _ex_h = f"{_v} ({len(_ufs)} UFs)"
    if _inex:
        _add(_avi, "Município não encontrado na base IBGE", _inex, _ex_i,
             f"**{_inex} município(s)** não batem com a base oficial (ex.: `{_ex_i}`). A conciliação vai "
             "tentar por similaridade — o que **não é oficial** e aparece marcado na auditoria.",
             "Confira grafia, abreviações (\"S. Miguel\") e nomes truncados (\"São Miguel\" em vez de "
             "\"São Miguel do Araguaia\" — são municípios DIFERENTES, a 2.000 km um do outro).")
    if _hom_sem_uf:
        _add(_bloq if _hom_sem_uf > _n * 0.2 else _avi, "Município homônimo SEM UF", _hom_sem_uf, _ex_h,
             f"**{_hom_sem_uf} município(s) homônimos** sem coluna de UF (ex.: `{_ex_h}`). O Brasil tem "
             "**241 grupos de homônimos** — 'São Domingos' existe em **5 estados**. Sem a UF, a conciliação "
             "pode vincular o município ERRADO e contaminar toda a comparação.",
             "Adicione uma coluna de **UF** (ou de **Código IBGE**) e mapeie-a acima. É a correção que mais "
             "aumenta a confiabilidade deste estudo.")

    # ---------- 8. INSCRITOS ----------
    if _c_in and _c_in in _cols:
        _ins = pd.to_numeric(df_ref[_c_in], errors="coerce")
        _in_nan = int(_ins.isna().sum())
        if _in_nan:
            _add(_avi, "Inscritos não numéricos", _in_nan, "—",
                 f"**{_in_nan} linha(s)** com quantidade de inscritos que não é número — elas pesam ZERO nos "
                 "indicadores ponderados.",
                 "Formate a coluna como NÚMERO inteiro.")
        _in_neg = int((_ins < 0).sum())
        if _in_neg:
            _add(_avi, "Inscritos negativos", _in_neg, "—",
                 f"**{_in_neg} linha(s)** com inscritos negativos — impossível.", "Corrija a coluna.")
    else:
        _add(_inf, "Sem coluna de inscritos", _n, "—",
             "Sem a quantidade de inscritos, cada município pesa **1**. Os indicadores medem impacto sobre "
             "LINHAS, não sobre CANDIDATOS — 1 município com 5.000 inscritos vale o mesmo que um com 10.",
             "Se você tiver o nº de candidatos por município, mapeie a coluna: é a informação que mais muda "
             "a leitura do estudo.")

    # ---------- 9. HIGIENE (espaços, caixa, caracteres estranhos) ----------
    try:
        _txt = df_ref[_c_o].astype(str)
        _esp = int((_txt != _txt.str.strip()).sum())
        if _esp:
            _add(_inf, "Espaços extras", _esp, "—",
                 f"**{_esp} linha(s)** com espaço sobrando no início/fim. Já normalizamos automaticamente.",
                 "Nada a corrigir — apenas informativo.")
        _estranho = int(_txt.str.contains(r"[^\w\sÀ-ÿ'\-\.,/()]", regex=True, na=False).sum())
        if _estranho:
            _ex = _txt[_txt.str.contains(r"[^\w\sÀ-ÿ'\-\.,/()]", regex=True, na=False)].iloc[0]
            _add(_avi, "Caracteres estranhos", _estranho, _ex,
                 f"**{_estranho} linha(s)** com caracteres incomuns (ex.: `{_ex}`) — pode ser **problema de "
                 "encoding** (planilha salva em Latin-1 e lida como UTF-8).",
                 "Reabra a planilha e salve como **.xlsx** (ou CSV UTF-8). Se aparecem 'Ã§' ou 'Ã£', é encoding.")
    except Exception:
        pass

    # ---------- NOTA ----------
    _nota = 100 - 40 * len(_bloq) - 8 * len(_avi)
    _nota = max(0, min(100, _nota))
    return {"bloqueantes": _bloq, "avisos": _avi, "info": _inf, "nota": _nota,
            "pode_processar": len(_bloq) == 0, "linhas": _n}




def _estatisticas_distribuicao(valores, pesos=None):
    """[CMP-STATS - 149ª geração] Estatística descritiva COMPLETA da diferença de distância: média, mediana,
    desvio-padrão, quartis, percentis (P5/P10/P90/P95), amplitude e coeficiente de variação.

    POR QUE IMPORTA (e por que a média sozinha ENGANA): num estudo nacional, uns poucos municípios com ganho
    enorme puxam a média para cima e escondem que a MAIORIA teve ganho pequeno. A MEDIANA e os QUARTIS
    contam a verdade. O COEFICIENTE DE VARIAÇÃO (desvio ÷ média) diz se o ganho é HOMOGÊNEO (CV baixo — a
    aplicação melhora em quase todo lugar) ou CONCENTRADO (CV alto — melhora muito em poucos, quase nada no
    resto). São conclusões OPOSTAS a partir da mesma média. PURO."""
    import numpy as np
    _v = np.array([float(x) for x in (valores or []) if x is not None and x == x], dtype=float)
    if _v.size == 0:
        return {}
    _m = float(_v.mean())
    _dp = float(_v.std(ddof=1)) if _v.size > 1 else 0.0
    _q = np.percentile(_v, [5, 10, 25, 50, 75, 90, 95])
    return {
        "n": int(_v.size), "media": round(_m, 2), "mediana": round(float(_q[3]), 2),
        "desvio_padrao": round(_dp, 2),
        "coef_variacao": round(abs(_dp / _m), 2) if _m else None,
        "minimo": round(float(_v.min()), 2), "maximo": round(float(_v.max()), 2),
        "amplitude": round(float(_v.max() - _v.min()), 2),
        "p5": round(float(_q[0]), 2), "p10": round(float(_q[1]), 2), "q1": round(float(_q[2]), 2),
        "q3": round(float(_q[4]), 2), "p90": round(float(_q[5]), 2), "p95": round(float(_q[6]), 2),
        "iqr": round(float(_q[4] - _q[2]), 2),
    }


def _pareto_economia(linhas, top=20):
    """[CMP-STATS - 149ª geração] ANÁLISE DE PARETO da economia: quantos municípios concentram 80% do ganho?

    É a pergunta mais ACIONÁVEL que existe aqui. Se 20 municípios respondem por 80% da economia total, o
    gestor sabe exatamente onde concentrar a atenção — e sabe que os outros 5.000 são ruído. Se o ganho está
    espalhado, a conclusão é OPOSTA: a melhoria é estrutural, não pontual. PURO.

    Retorna {itens (top N, com % acumulado), n_para_80pct, pct_do_total_no_top, concentrado (bool)}."""
    _pos = [l for l in (linhas or []) if float(l.get("Economia km x Inscritos") or 0) > 0]
    if not _pos:
        return {"itens": [], "n_para_80pct": 0, "total": 0.0, "concentrado": False}
    _pos.sort(key=lambda l: -float(l["Economia km x Inscritos"]))
    _tot = sum(float(l["Economia km x Inscritos"]) for l in _pos)
    _acum, _n80, _itens = 0.0, 0, []
    for _i, _l in enumerate(_pos, start=1):
        _e = float(_l["Economia km x Inscritos"])
        _acum += _e
        if _n80 == 0 and _acum >= 0.8 * _tot:
            _n80 = _i
        if _i <= top:
            _itens.append({"posicao": _i, "municipio": _l.get("Origem"), "uf": _l.get("UF", ""),
                           "inscritos": int(float(_l.get("Inscritos") or 0)),
                           "economia_km_candidato": round(_e, 1),
                           "pct_do_total": round(100.0 * _e / _tot, 2),
                           "pct_acumulado": round(100.0 * _acum / _tot, 1)})
    _pct_muns = 100.0 * _n80 / len(_pos) if _pos else 0.0
    return {"itens": _itens, "n_para_80pct": _n80, "n_municipios_com_ganho": len(_pos),
            "pct_municipios_para_80": round(_pct_muns, 1), "total": round(_tot, 1),
            "concentrado": _pct_muns <= 30.0}






