_AGG_FUNC_MAP = {
    'Contagem Distinta': 'nunique',
    'Contagem':          'count',
    'Soma':              'sum',
    'Média':             'mean',
    'Mínimo':            'min',
    'Máximo':            'max',
    'Mediana':           'median',
    'Desvio Padrão':     'std',
    'Variância':         'var',
    'Percentil 25':      lambda x: x.quantile(0.25),
    'Percentil 50':      lambda x: x.quantile(0.50),
    'Percentil 75':      lambda x: x.quantile(0.75),
}

def get_agg_func(op_name):
    for chave, func in _AGG_FUNC_MAP.items():
        if chave in op_name:
            return func
    return 'count'

